# Step-by-step breakdown:
# 1. We need a Route 53 hosted zone (assuming it may need to be referenced or created)
# 2. We require a CloudWatch Logs log group to store the query logs
# 3. A CloudWatch Logs resource policy is needed to allow Route 53 to publish logs
# 4. A Route 53 query logging configuration to enable logging for the hosted zone

resource "aws_route53_hosted_zone" "primary" {
  name = "primary"
}

resource "aws_cloudwatch_log_group" "route53_query_logs" {
  name              = "aws_route53_example_com"
  retention_in_days = 30
}

resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_name = "route53-query-logging-policy"

  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:aws_route53_example_com:*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = "*"
          },
          ArnLike = {
            "aws:SourceArn" = "arn:aws:route53:::querylogging/*"
          }
        }
      }
    ]
  })
}

resource "aws_route53_query_log" "example" {
  zone_id     = aws_route53_hosted_zone.primary.zone_id
  log_group_arn = aws_cloudwatch_log_group.route53_query_logs.arn
}

