resource "aws_route53_record" "db_weighted_ap_southeast" {
  zone_id = aws_route53_hosted_zone.main.zone_id
  name    = "db-main.main.example.com"
  type    = "CNAME"
  ttl     = 300

  weighted_routing_policy {
    weight = 20
  }

  set_identifier = "replica-ap-southeast"
  records        = [aws_db_instance.replica_ap_southeast.endpoint]
}
