# Terraform configuration for Blue-Green deployment using Route 53 weighted routing with Elastic Beanstalk

# Providers required for AWS resources
provider "aws" {
  region = "us-east-1"  # You can change this to your preferred region
}

# Variables for environment names and domain
variable "domain_name" {
  description = "The domain name for the application (e.g., example.com)"
  type        = string
}

variable "blue_env_name" {
  description = "Name of the blue Elastic Beanstalk environment"
  type        = string
  default     = "blue"
}

variable "green_env_name" {
  description = "Name of the green Elastic Beanstalk environment"
  type        = string
  default     = "green"
}

# Data sources to fetch the CNAMEs of the Elastic Beanstalk environments
data "aws_elastic_beanstalk_environment" "blue" {
  name = var.blue_env_name
}

data "aws_elastic_beanstalk_environment" "green" {
  name = var.green_env_name
}

# Route 53 zone for the domain
data "aws_route53_zone" "primary" {
  name = var.domain_name
}

# Route 53 record for weighted routing: blue environment
resource "aws_route53_record" "blue_record" {
  zone_id = data.aws_route53_zone.primary.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = 60

  weight = 50  # Initial weight for blue environment

  set_identifier = "blue-environment"

  records = [
    data.aws_elastic_beanstalk_environment.blue.cname
  ]
}

# Route 53 record for weighted routing: green environment
resource "aws_route53_record" "green_record" {
  zone_id = data.aws_route53_zone.primary.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = 60

  weight = 50  # Initial weight for green environment

  set_identifier = "green-environment"

  records = [
    data.aws_elastic_beanstalk_environment.green.cname
  ]
}

# Output the DNS name for verification
output "blue_environment_cname" {
  value = data.aws_elastic_beanstalk_environment.blue.cname
}

output "green_environment_cname" {
  value = data.aws_elastic_beanstalk_environment.green.cname
}

output "application_dns_name" {
  value = "app.${var.domain_name}"
}

# Note: To perform a blue-green deployment, adjust the weights.
# For example, shift 100% traffic to green by setting green weight=100 and blue=0.

