# This Terraform configuration sets up two AWS Elastic Beanstalk environments:
# - One in us-west-2 (Oregon) named "us_west"
# - One in eu-central-1 (Frankfurt) named "eu_central"
# It also configures Route 53 with latency-based routing to direct users to the nearest environment.

# Provider configuration for AWS with multiple regions using provider aliases
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

provider "aws" {
  # Default provider (we'll use us-west-2 as default for shared resources like Route 53)
  region = "us-west-2"
}

# Route 53 Hosted Zone - domain registration and DNS are global, created in default provider region
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your actual domain
}

# Elastic Beanstalk Application (created once, environments will reference it)
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-geodistributed-app"
  description = "Application for geo-distributed Elastic Beanstalk environments"
}

# Elastic Beanstalk Environment in us-west-2
resource "aws_elastic_beanstalk_environment" "us_west_env" {
  provider = aws.us_west

  name                = "us-west-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v3.0.0 running Docker" # Updated stack

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  # Optional tags
  tags = {
    Name = "us_west"
  }
}

# Elastic Beanstalk Environment in eu-central-1
resource "aws_elastic_beanstalk_environment" "eu_central_env" {
  provider = aws.eu_central

  name                = "eu-central-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v3.0.0 running Docker" # Same stack

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  # Optional tags
  tags = {
    Name = "eu_central"
  }
}

# Data sources to get CNAMEs from the Elastic Beanstalk environments
data "aws_elastic_beanstalk_environment" "us_west" {
  provider = aws.us_west

  name = aws_elastic_beanstalk_environment.us_west_env.name
}

data "aws_elastic_beanstalk_environment" "eu_central" {
  provider = aws.eu_central

  name = aws_elastic_beanstalk_environment.eu_central_env.name
}

# Route 53 latency records pointing to each region
resource "aws_route53_record" "latency_us_west" {
  zone_id = aws_route53_zone.main.id
  name    = "app.example.com" # Replace with desired subdomain
  type    = "CNAME"
  ttl     = 300

  # Latency record for US West
  latency_routing_policy {
    region = "us-west-2"
  }

  set_identifier = "us-west-2"
  records        = [data.aws_elastic_beanstalk_environment.us_west.cname]
}

resource "aws_route53_record" "latency_eu_central" {
  zone_id = aws_route53_zone.main.id
  name    = "app.example.com" # Same name for both records - they are routed based on latency
  type    = "CNAME"
  ttl     = 300

  # Latency record for EU Central
  latency_routing_policy {
    region = "eu-central-1"
  }

  set_identifier = "eu-central-1"
  records        = [data.aws_elastic_beanstalk_environment.eu_central.cname]
}

# Optional: Health checks (recommended for production)
resource "aws_route53_health_check" "us_west" {
  fqdn              = data.aws_elastic_beanstalk_environment.us_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = 30
  failure_threshold = 3

  tags = {
    Environment = "us_west"
  }
}

resource "aws_route53_health_check" "eu_central" {
  fqdn              = data.aws_elastic_beanstalk_environment.eu_central.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = 30
  failure_threshold = 3

  tags = {
    Environment = "eu_central"
  }
}

# Update the records to include health checks
# (Remove previous records and let these take effect when applied)
# Note: In a real deployment, you'd likely enable health checks

# (The CNAME records above can be updated to include health_check_id references if health checks are used)

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.default, aws.west, aws.europe ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1" # Default region
  alias  = "default"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "us-west-1"
  alias  = "west"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "eu-central-1"
  alias  = "europe"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  provider = aws.default
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_s3_bucket" "us_west_sample_bucket" {
  provider = aws.west
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "us_west_examplebucket_object" {
  provider = aws.west
  key    = "app"
  bucket = aws_s3_bucket.us_west_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "us_west" {
  provider = aws.west
  name        = "my-global-app"
  description = "A global application deployed in US-West."
}

resource "aws_elastic_beanstalk_application_version" "us_west_version" {
  provider = aws.west
  name        = "v1"
  application = aws_elastic_beanstalk_application.us_west.name
  bucket = aws_s3_object.us_west_examplebucket_object.bucket
  key    = aws_s3_object.us_west_examplebucket_object.key
}

# US-West Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider            = aws.west
  name                = "my-global-app-us-west"
  application         = aws_elastic_beanstalk_application.us_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

resource "aws_s3_bucket" "eu_sample_bucket" {
  provider = aws.europe
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "eu_examplebucket_object" {
  provider = aws.europe
  key    = "app"
  bucket = aws_s3_bucket.eu_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk Application (EU-Central Region)
resource "aws_elastic_beanstalk_application" "eu_central" {
  provider = aws.europe
  name        = "my-global-app"
  description = "A global application deployed in EU-Central."
}

resource "aws_elastic_beanstalk_application_version" "europe_version" {
  provider = aws.europe
  name        = "v1"
  application = aws_elastic_beanstalk_application.eu_central.name
  bucket = aws_s3_object.eu_examplebucket_object.bucket
  key    = aws_s3_object.eu_examplebucket_object.key
}

# EU-Central Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.europe
  name                = "my-global-app-eu-central"
  application         = aws_elastic_beanstalk_application.eu_central.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Route53 Hosted Zone for the domain
resource "aws_route53_zone" "main" {
  provider = aws.default
  name     = "myglobalapp.com"
}

# Geolocation Routing Policy Records for Route 53 to direct traffic based on location
resource "aws_route53_record" "us_west" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "west.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "us-west"
  geolocation_routing_policy {
    continent = "NA"
  }
  records = [
    aws_elastic_beanstalk_environment.us_west.name
  ]
}

resource "aws_route53_record" "eu_central" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "central.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "eu-central"
  geolocation_routing_policy {
    continent = "EU"
  }
  records = [
    aws_elastic_beanstalk_environment.eu_central.name
  ]
}

