# This Terraform configuration sets up two AWS Elastic Beanstalk environments:
# - One in us-west-2 (Oregon) named "us_west"
# - One in eu-central-1 (Frankfurt) named "eu_central"
# It also configures Route 53 with latency-based routing to direct users to the nearest environment.

# Provider configuration for AWS with multiple regions using provider aliases
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

provider "aws" {
  # Default provider (we'll use us-west-2 as default for shared resources like Route 53)
  region = "us-west-2"
}

# Route 53 Hosted Zone - domain registration and DNS are global, created in default provider region
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your actual domain
}

# Elastic Beanstalk Application (created once, environments will reference it)
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-geodistributed-app"
  description = "Application for geo-distributed Elastic Beanstalk environments"
}

# Elastic Beanstalk Environment in us-west-2
resource "aws_elastic_beanstalk_environment" "us_west_env" {
  provider = aws.us_west

  name                = "us-west-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v3.0.0 running Docker" # Updated stack

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  # Optional tags
  tags = {
    Name = "us_west"
  }
}

# Elastic Beanstalk Environment in eu-central-1
resource "aws_elastic_beanstalk_environment" "eu_central_env" {
  provider = aws.eu_central

  name                = "eu-central-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v3.0.0 running Docker" # Same stack

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  # Optional tags
  tags = {
    Name = "eu_central"
  }
}

# Data sources to get CNAMEs from the Elastic Beanstalk environments
data "aws_elastic_beanstalk_environment" "us_west" {
  provider = aws.us_west

  name = aws_elastic_beanstalk_environment.us_west_env.name
}

data "aws_elastic_beanstalk_environment" "eu_central" {
  provider = aws.eu_central

  name = aws_elastic_beanstalk_environment.eu_central_env.name
}

# Route 53 latency records pointing to each region
resource "aws_route53_record" "latency_us_west" {
  zone_id = aws_route53_zone.main.id
  name    = "app.example.com" # Replace with desired subdomain
  type    = "CNAME"
  ttl     = 300

  # Latency record for US West
  latency_routing_policy {
    region = "us-west-2"
  }

  set_identifier = "us-west-2"
  records        = [data.aws_elastic_beanstalk_environment.us_west.cname]
}

resource "aws_route53_record" "latency_eu_central" {
  zone_id = aws_route53_zone.main.id
  name    = "app.example.com" # Same name for both records - they are routed based on latency
  type    = "CNAME"
  ttl     = 300

  # Latency record for EU Central
  latency_routing_policy {
    region = "eu-central-1"
  }

  set_identifier = "eu-central-1"
  records        = [data.aws_elastic_beanstalk_environment.eu_central.cname]
}

# Optional: Health checks (recommended for production)
resource "aws_route53_health_check" "us_west" {
  fqdn              = data.aws_elastic_beanstalk_environment.us_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = 30
  failure_threshold = 3

  tags = {
    Environment = "us_west"
  }
}

resource "aws_route53_health_check" "eu_central" {
  fqdn              = data.aws_elastic_beanstalk_environment.eu_central.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = 30
  failure_threshold = 3

  tags = {
    Environment = "eu_central"
  }
}

# Update the records to include health checks
# (Remove previous records and let these take effect when applied)
# Note: In a real deployment, you'd likely enable health checks

# (The CNAME records above can be updated to include health_check_id references if health checks are used)
```

