# Set up an Elastic Beanstalk environment connected to a relational database
# Step-by-step considerations:
# 1. We need an RDS instance (relational database) with the instance name "default"
# 2. We need an Elastic Beanstalk application and environment
# 3. The Beanstalk environment needs to use "eb_ec2_profile" as the instance profile
# 4. We'll use common defaults: e.g., DB engine (PostgreSQL), instance types, etc.
# 5. We'll include appropriate security groups and dependencies

resource "aws_rds_cluster" "default" {
  cluster_identifier = "default"
  engine             = "aurora-postgresql"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = "password123456" # In practice, use AWS Secrets Manager or input variable
  skip_final_snapshot = true
}

resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-eb-application"
  description = "My Elastic Beanstalk Application"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_policy_attachment" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier" # Common policy for EB instances
}

resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "my-eb-environment"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.9 running Python 3.9" # Example stack

  setting {
