# Set up Elastic Beanstalk environments for production and staging with associated RDS instances
# We'll use AWS provider for this configuration

provider "aws" {
  region = "us-east-1" # Default region; can be changed as needed
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-app"
  description = "Elastic Beanstalk application for production and staging environments"
}

# Instance profile for EC2 instances in Elastic Beanstalk
# Assuming the instance profile "eb_ec2_profile" already exists. If it needs to be created:
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# RDS DB Subnet Group (required for RDS instances)
resource "aws_db_subnet_group" "main" {
  name       = "eb-rds-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

# VPC and subnets for the environments
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "eb-vpc"
  }
}

resource "aws_subnet" "private" {
  count = 2

  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "eb-private-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for RDS instances
resource "aws_security_group" "rds_sg" {
  name        = "eb-rds-sg"
  description = "Allow inbound from Elastic Beanstalk instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust based on your Elastic Beanstalk security group or use source_security_group_id
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

