  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}
# RDS Database Configuration
resource "aws_db_instance" "my_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "mydbuser"
  password             = "mypassword"
  parameter_group_name = "default.mysql5.7"
  multi_az             = true
  skip_final_snapshot  = true
  backup_retention_period = 7  # Enable backups with 7-day retention
  apply_immediately       = true
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-app"
  description = "My Application"
}

# Original Elastic Beanstalk Environment (Blue)
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "my-app-blue-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASS"
    value     = aws_db_instance.my_db.password
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# New Elastic Beanstalk Environment (Green), for the new version
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "my-app-green-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_HOST"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_USER"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DATABASE_PASS"
    value     = aws_db_instance.my_db.password
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
    }
}

# Taking a snapshot before deployment
resource "aws_db_snapshot" "my_db_snapshot" {
  db_instance_identifier = aws_db_instance.my_db.identifier
  db_snapshot_identifier = "my-db-snapshot-${formatdate("YYYYMMDDHHmmss", timestamp())}"
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}

# Weighted DNS records for Blue and Green environments
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 120
  }
  set_identifier = "BlueEnvironment"
  records = [
    aws_elastic_beanstalk_environment.blue_env.cname
  ]
}

resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 60
  }
  set_identifier = "GreenEnvironment"
  records = [
    aws_elastic_beanstalk_environment.green_env.cname
  ]
}

response:
```hcl
# This Terraform configuration sets up a blue-green deployment using AWS Elastic Beanstalk
# with an RDS database. It includes:
# - Two Elastic Beanstalk environments (blue and green) for blue-green deployment
# - An RDS instance with specified database name "my_db"
# - Pre-deployment snapshot of the RDS instance
# - Use of EC2 instance profile "ec2_eb_profile1"
# - Appropriate lifecycle and dependency management

resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-app"
  description = "Blue-green deployment application"
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  name         = "app-v1"
  application  = aws_elastic_beanstalk_application.eb_app.name
  description  = "Application version 1"
  bucket       = "my-app-bucket"
  key          = "app-v1.zip"
}

resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "blue-env"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.13 running Python 3.9"
  version_label       = aws_elastic_beanstalk_application_version.app_version.name
  tier                = "WebServer"

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t3.small"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "IamInstanceProfile"
    value     = "ec2_eb_profile1"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBDeletionPolicy"
    value     = "Snapshot"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBEngine"
    value     = "postgres"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBUser"
    value     = "dbadmin"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = "dbpassword"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBName"
    value     = "my_db"
  }
}

resource "aws_elastic_beanstalk_environment" "green" {
  count               = 0 # Initially disabled; toggle during deployment
  name                = "green-env"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.13 running Python 3.9"
  version_label       = aws_elastic_beanstalk_application_version.app_version.name
  tier                = "WebServer"

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t3.small"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "IamInstanceProfile"
    value     = "ec2_eb_profile1"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBDeletionPolicy"
    value     = "Snapshot"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceClass"
    value     = "db.t3.micro"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "Engine"
    value     = "mysql"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBName"
    value     = "my_db"
  }
}

# RDS Database Instance used by Elastic Beanstalk (via environment settings)
resource "aws_db_instance" "eb_database" {
  identifier           = "eb-db-instance"
  db_name              = "my_db"
  instance_class       = "db.t3.micro"
  engine               = "mysql"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine_version       = "8.0"
  username             = "admin"
  password             = "securepassword123"
  publicly_accessible  = false
  skip_final_snapshot  = false
  final_snapshot_identifier = "final-snapshot-${formatdate("YYYYMMDDhhmmss", timestamp())}"

  # Create a snapshot before any modification (simulate pre-deploy snapshot)
  provisioner "local-exec" {
    when    = destroy
    order   = "first"
    command = "echo 'Creating pre-deployment snapshot...'; aws rds create-db-snapshot --db-snapshot-identifier pre-deploy-snapshot-${formatdate("YYYYMMDDhhmmss", timestamp())} --db-instance-identifier ${self.identifier}'"
  }

  # Apply snapshot creation also before update
  lifecycle {
    ignore_changes = []
    precomputed = []
  }
}

# Output environment URLs for blue-green switching
output "blue_environment_url" {
  value = "http://${aws_elastic_beanstalk_environment.blue.cname}"
}

output "green_environment_url" {
  value = "http://${aws_elastic_beanstalk_environment.green.cname}"
  depends_on = [aws_elastic_beanstalk_environment.green]
}

# Note: Blue-green deployment logic (toggling active environment) is managed outside Terraform
# via AWS CLI or EB CLI, but infrastructure is prepared here.
```

