```hcl
# Elastic Beanstalk Web Application with VPC, RDS, and IAM Infrastructure

provider "aws" {
  region = "us-east-1" # Change as needed
}

# VPC for the environment
resource "aws_vpc" "eb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags = {
    Name = "eb-vpc"
  }
}

# Internet Gateway to enable internet access
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.eb_vpc.id
  tags = {
    Name = "eb-igw"
  }
}

# Public subnet for Elastic Beanstalk instances
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "${var.aws_region}a"
  map_public_ip_on_launch = true
  tags = {
    Name = "eb-public-subnet"
  }
}

# Private subnet for RDS database
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${var.aws_region}b"
  tags = {
    Name = "eb-private-subnet"
  }
}

# Route table for public subnet
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.eb_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "eb-public-rt"
  }
}

# Associate public subnet with public route table
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# Route table for private subnet (no direct internet access)
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.eb_vpc.id
  tags = {
    Name = "eb-private-rt"
  }
}

# Associate private subnet with private route table
resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# Security group for Elastic Beanstalk environment
resource "aws_security_group" "eb_sg" {
  name        = "eb-security-group"
  description = "Security group for Elastic Beanstalk instances"
  vpc_id      = aws_vpc.eb_vpc.id

  # Allow HTTP from anywhere
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow HTTPS from anywhere
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH from anywhere (consider restricting in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow outbound traffic to anywhere
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security group for RDS database (only allow access from EB instances)
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Security group for RDS instance"
  vpc_id      = aws_vpc.eb_vpc.id

  # Allow MySQL/Aurora inbound from EB instances
  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_sg.id] # Only EB instances can access
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance (MySQL)
resource "aws_db_instance" "eb_rds" {
  identifier           = "eb-database"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  username             = var.db_username
  password             = var.db_password
  db_name              = "myappdb"
  publicly_accessible  = false
  skip_final_snapshot  = true
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = aws_db_subnet_group.eb_db_subnet_group.name
  # Multi-AZ not enabled for cost savings; consider enabling in production
}

# DB Subnet Group for RDS in private subnet
resource "aws_db_subnet_group" "eb_db_subnet_group" {
  name       = "eb-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet.id]
  tags = {
    Name = "eb-db-subnet-group"
  }
}

# IAM Service Role for Elastic Beanstalk
resource "aws_iam_role" "eb_service_role" {
  name = "aws-elasticbeanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "aws-elasticbeanstalk-service-role"
  }
}

# IAM Policy for EB service role
resource "aws_iam_role_policy_attachment" "eb_service_policy" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkService"
}

# Instance profile role for EC2 instances in EB
resource "aws_iam_role" "eb_instance_role" {
  name = "aws-elasticbeanstalk-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "aws-elasticbeanstalk-ec2-role"
  }
}

# Attach basic policy to allow EB instances to upload logs and metrics
resource "aws_iam_role_policy_attachment" "eb_instance_policy" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Instance profile for EC2
resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "aws-elasticbeanstalk-ec2-role"
  role = aws_iam_role.eb_instance_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "my-web-app"
  description = "My web application on Elastic Beanstalk"
}

# Elastic Beanstalk Application Version (assuming S3 deployment)
# You'd typically source this from a ZIP in S3 built externally
resource "aws_s3_bucket" "eb_bucket" {
  bucket = "eb-app-bucket-${random_string.suffix.result}"
  tags = {
    Name = "eb-app-source-bucket"
  }
}

resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_elastic_beanstalk_application_version" "eb_app_version" {
  name        = "app-v1"
  application = aws_elastic_beanstalk_application.eb_app.name
  description = "Application version 1"

  bucket = aws_s3_bucket.eb_bucket.bucket
  key    = "app.zip" # Update with actual application artifact
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "my-web-app-env"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.7.4 running Node.js 18"

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t3.small"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = aws_subnet.public_subnet.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "AssociatePublicIpAddress"
    value     = "true"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "DeploymentPolicy"
    value     = "Rolling"
  }

  # Pass database connection info via environment variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.eb_rds.endpoint
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.eb_rds.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = var.db_username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASS"
    value     = var.db_password
  }

  # Link to service role
  setting {
    namespace = "aws:elasticbeanstalk:managedactions"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service_role.arn
  }

  # Use instance profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  # Link to security group
  setting {
    namespace = "aws:ec2:securitygroups"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_sg.id
  }

  # Required to avoid dangling versions
  depends_on = [
    aws_elastic_beanstalk_application_version.eb_app_version,
    aws_iam_instance_profile.eb_instance_profile
  ]
}

# Variables
variable "aws_region" {
  description = "AWS Region"
  default     = "us-east-1"
}

variable "db_username" {
  description = "Master username for RDS instance"
  type        = string
  sensitive   = true
}

variable "db_password" {
  description = "Master password for RDS instance"
  type        = string
  sensitive   = true
}

# Output the Elastic Beanstalk URL
output "eb_url" {
  value = "http://${aws_elastic_beanstalk_environment.eb_env.endpoint_url}"
}

# Output RDS Endpoint
output "rds_endpoint" {
  value = aws_db_instance.eb_rds.endpoint
}
```

