extracted_code:
# This Terraform configuration sets up:
# 1. Route 53 hosted zone for the domain
# 2. Route 53 record to route traffic to an Elastic Beanstalk environment
# 3. Elastic Beanstalk environment with reference to EC2 instance profile and RDS database
# 4. RDS database with specified name

# Provider configuration
provider "aws" {
  region = "us-east-1" # Default region; can be customized
}

# Variables to accept domain and other inputs
variable "domain_name" {
  description = "The domain name to host on Route 53 (e.g., example.com)"
  type        = string
}

variable "environment_name" {
  description = "Name of the Elastic Beanstalk environment"
  type        = string
  default     = "myenv"
}

variable "instance_profile" {
  description = "EC2 instance profile name for Elastic Beanstalk"
  type        = string
  default     = "eb_ec2_profile1"
}

variable "db_name" {
  description = "Name of the RDS database"
  type        = string
  default     = "myapp_db"
}

# Route 53: Create a hosted zone for the domain
resource "aws_route53_zone" "main" {
  name = var.domain_name

  # Add tags for better organization
  tags = {
    Environment = "production"
    Project     = "myapp"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "this" {
  name        = "myapp"
  description = "My Terraform-managed Elastic Beanstalk application"
}

# RDS Database Instance used by Elastic Beanstalk
resource "aws_db_instance" "myapp_db" {
  identifier           = var.db_name
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  name                 = var.db_name
  username             = "admin"
  password             = "your_secure_password" # In practice, use AWS Secrets Manager or variables
  publicly_accessible  = false
  skip_final_snapshot  = true

  tags = {
    Name = var.db_name
  }
}

# Elastic Beanstalk Environment pointing to the RDS and using the instance profile
resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = var.environment_name
  application         = aws_elastic_beanstalk_application.this.name
  solution_stack_name = "64bit Amazon Linux 2 v5.4.12 running Python 3.9" # Example stack; adjust based on app

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = var.instance_profile
  }

  # Pass database connection info as environment variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.endpoint
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = var.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = "admin"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASS"
    value     = "your_secure_password"
  }
}

# Route 53 record to point domain to Elastic Beanstalk environment
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.${var.domain_name}"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.myenv.cname]
}

# Optional: APEX record using ALIAS if EB supports alias targeting (requires dualstack endpoint)
resource "aws_route53_record" "apex" {
  zone_id = aws_route53_zone.main.zone_id
  name    = var.domain_name
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = aws_route53_zone.main.zone_id
    evaluate_target_health = true
  }
}

# Output the domain and EB environment URL
output "domain" {
  value = var.domain_name
}

output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.myenv.cname
}

