}

# Create VPC and subnets for eu-west-1
resource "aws_vpc" "eu_west" {
  provider = aws.eu-west-1

  cidr_block = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "eb-vpc-eu-west"
  }
}

resource "aws_subnet" "eu_west_public" {
  provider = aws.eu-west-1
  count    = 2

  vpc_id            = aws_vpc.eu_west.id
  cidr_block        = ["10.1.1.0/24", "10.1.2.0/24"][count.index]
  availability_zone = ["eu-west-1a", "eu-west-1b"][count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "eb-public-eu-west-${count.index}"
