}

resource "aws_subnet" "eu_west_private" {
  provider = aws.eu-west-1
  count    = 2

  vpc_id            = aws_vpc.eu_west.id
  cidr_block        = ["10.1.3.0/24", "10.1.4.0/24"][count.index]
  availability_zone = ["eu-west-1a", "eu-west-1b"][count.index]

  tags = {
    Name = "eb-private-eu-west-${count.index}"
  }
}

# Create Route 53 latency-based records pointing to both regions
