  }

  set_identifier = "us-east-1"
  type           = "A"
  region         = "us-east-1"
}

resource "aws_route53_record" "latency_eu_west" {
  provider = aws.route53

  zone_id = aws_route53_zone.main.zone_id
  name    = "example.com"
