  alias {
    name                   = aws_elastic_beanstalk_environment.eu_west.endpoint_url
    zone_id                = aws_elastic_beanstalk_environment.eu_west.cname
    evaluate_target_health = true
  }

  set_identifier = "eu-west-1"
  type           = "A"
  region         = "eu-west-1"
}

# Main latency-based routing record
resource "aws_route53_record" "app" {
  provider = aws.route53

  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.us_east.endpoint_url
    zone_id                = aws_elastic_beanstalk_environment.us_east.cname
    evaluate_target_health = true
  }

  set_identifier = "us-east-1"
