# We are setting up a blue-green deployment using AWS Route 53 with failover routing.
# Both environments ("blue" and "green") will point to the same RDS database.
# We'll create:
# - Two health checks for blue and green environments (likely EC2 instances or Elastic Beanstalk environments)
# - A common RDS database used by both environments
# - Route 53 DNS records with failover routing (PRIMARY for one, SECONDARY for the other)
# - Assume EC2 instances or Elastic Beanstalk use the instance profile "eb_ec2_profile"
# - Use appropriate naming: "myapp_db", "blue", "green"

# Define variables we might need
locals {
  app_name       = "myapp"
  db_name        = "myapp_db"
  db_username    = "admin"
  db_password    = "securepassword123" # In practice, use AWS Secrets Manager or secure input
  instance_class = "db.t3.micro"
  allocated_storage = 20
  engine         = "mysql"
  engine_version = "8.0"
}

# Create a VPC (assuming we need one; you might use existing)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "${local.app_name}-vpc"
  }
}

# Subnets for DB (in two AZs for high availability)
resource "aws_subnet" "db_subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "${local.app_name}-db-subnet-a"
  }
}

resource "aws_subnet" "db_subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "${local.app_name}-db-subnet-b"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "${local.app_name}-db-subnet-group"
  subnet_ids = [aws_subnet.db_subnet_a.id, aws_subnet.db_subnet_b.id]

  tags = {
    Name = "${local.app_name}-db-subnet-group"
  }
}

# Security group for RDS
resource "aws_security_group" "db" {
  name        = "${local.app_name}-db-sg"
  description = "Allow MySQL from EC2 environments"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    # Assume Blue/Green EC2 instances are in the same VPC
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${local.app_name}-db-sg"
  }
}

# RDS Instance (shared by blue and green)
resource "aws_db_instance" "common" {
  identifier              = local.db_name
  db_name                 = local.db_name
  engine                  = local.engine
  engine_version          = local.engine_version
  instance_class          = local.instance_class
  allocated_storage       = local.allocated_storage
  storage_encrypted       = true
  backup_retention_period = 7
  publicly_accessible     = false
  multi_az                = true
  skip_final_snapshot     = true
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.db.id]
  username                = local.db_username
  password                = local.db_password
  port                    = 3306

  tags = {
    Environment = "shared"
    App         = local.app_name
  }
}

# Instance profile for EC2 instances (assumed Elastic Beanstalk)
# We don't create IAM roles here in full for brevity, but we reference the profile name
# Assuming the instance profile "eb_ec2_profile" exists

# Health check for Blue environment (e.g., Elastic Beanstalk environment)
resource "aws_route53_health_check" "blue" {
  fqdn              = "blue.myapp.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Environment = "blue"
    App         = local.app_name
  }
}

resource "aws_route53_health_check" "green" {
  fqdn              = "green.myapp.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Environment = "green"
    App         = local.app_name
  }
}

# Route 53 Zone (replace with your domain)
resource "aws_route53_zone" "main" {
  name = "myapp.com"
}

# Use failover routing: one PRIMARY, one SECONDARY
# Initially, route to Blue (PRIMARY), fallback to Green (SECONDARY) if Blue fails
resource "aws_route53_record" "app_failover" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.myapp.com"
  type    = "A"

  # Failover routing
  routing_policy {
    failover {
      type = "PRIMARY" # This would be the active "blue"
    }
  }

  # Associate with health check of the same environment
  health_check_id = aws_route53_health_check.blue.id

  # You would point this to ELB or IP of Blue environment
  # For this example, assuming Elastic IP or ALB DNS name
  # These values would normally come from Elastic Beanstalk or Load Balancer outputs
  records = ["192.0.2.1"]  # Example IP for Blue
  ttl     = 60
}

resource "aws_route53_record" "app_failover_secondary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.myapp.com"
  type    = "A"

  routing_policy {
    failover {
      type = "SECONDARY" # Green is standby
    }
  }

  health_check_id = aws_route53_health_check.green.id

  records = ["192.0.2.2"]  # Example IP for Green
  ttl     = 60
}

# Output the RDS endpoint for use in Blue/Green environments
output "rds_endpoint" {
  value = aws_db_instance.common.endpoint
}

# Output the primary DNS name
output "app_dns_name" {
  value = "www.myapp.com"
}

