# AWS Elastic Beanstalk Application Scaffold
# This configuration sets up a basic Elastic Beanstalk application with a sample environment.
# It includes:
# - An Elastic Beanstalk application
# - A sample environment (e.g., for a web application)
# - Configuration for environment tier (WebServer)
# - Tags for resource organization

resource "aws_elastic_beanstalk_application" "example" {
  name        = "example-application"
  description = "An example Elastic Beanstalk application"

  # Enable resource lifecycle to prevent accidental deletion
  lifecycle {
    prevent_destroy = false
  }
}

# Optional: Define an application version bucket (if needed)
resource "aws_s3_bucket" "version_bucket" {
  bucket = "${aws_elastic_beanstalk_application.example.name}-versions"
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle {
    prevent_destroy = false
  }
}

# Optional: Set up application version (requires source bundle in S3)
resource "aws_elastic_beanstalk_application_version" "example" {
  name        = "example-app-version-1"
  application = aws_elastic_beanstalk_application.example.name
  description = "Example application version 1"

  # Source bundle must be uploaded to S3 first
  # This is a placeholder; you'd need to upload a zip file containing your app
  bucket = aws_s3_bucket.version_bucket.bucket
  key    = "app-v1.zip"

  # Force updates even if the version already exists
  force_delete = true
}

# Environment configuration for the Elastic Beanstalk application
resource "aws_elastic_beanstalk_environment" "example" {
  name                = "example-env"
  application         = aws_elastic_beanstalk_application.example.name
  solution_stack_name = "64bit Amazon Linux 2 v5.7.4 running Python 3.9" # Common stack; adjust as needed

  # Tier can be "WebServer" or "Worker"
  tier = "WebServer"

  # Optional: Environment-specific tags
  tags = {
    Environment = "example"
    Project     = "terraform-demo"
  }

  # Example environment variables (customize as needed)
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "NODE_ENV"
    value     = "production"
  }

  # Enable health reporting
  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  # Example: Enable load balancer health checks
  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "StreamLogs"
