# This Terraform configuration sets up a fully managed, auto-scaling web application service
# using AWS App Runner, which supports containerized web apps in various languages (Python, Node.js, Ruby, Go, Java, etc.)
# The service automatically scales from zero and provides a secure HTTPS URL.

# Provider setup
provider "aws" {
  region = "us-east-1"  # App Runner is available in multiple regions
}

# ECR Repository to store the container image
resource "aws_ecr_repository" "webapp_repo" {
  name = "webapp-repository"
  image_tag_mutability = "MUTABLE"

  image_scanning_configuration {
    scan_on_push = true
  }
}

# App Runner Service
resource "aws_apprunner_service" "webapp_service" {
  service_name = "auto-scaling-webapp"
  source_configuration {
    image_repository {
      image_identifier      = "${aws_ecr_repository.webapp_repo.repository_url}:latest"
      image_configuration {
        port = "8080"  # Common port for web apps; adjust based on your app
      }
      image_repository_type = "ECR"
    }
    auto_deployments_enabled = true  # Automatically deploys on new image push
  }

  instance_configuration {
    cpu    = "1024"  # 1 vCPU
    memory = "3072"  # 3 GB memory
  }

  # Auto scaling is built-in: scales from 0 to up to 25 concurrent requests per instance
  health_check_configuration {
    protocol = "HTTP"
    path     = "/health"
    interval = 10
    timeout  = 5
    healthy_threshold   = 2
    unhealthy_threshold = 5
  }
}

# Output the web app URL
output "webapp_url" {
  description = "The URL of the web application"
  value       = "https://${aws_apprunner_service.webapp_service.service_url}"
}

# Optional: IAM role for App Runner to access ECR
resource "aws_iam_role" "apprunner_iam_role" {
  name = "apprunner-service-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "build.apprunner.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "apprunner_ecr_access" {
  role       = aws_iam_role.apprunner_iam_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSAppRunnerServicePolicyForECRAccess"
}

# Associate IAM role with App Runner service
resource "aws_apprunner_service" "webapp_service" {
  depends_on = [aws_iam_role_policy_attachment.apprunner_ecr_access]

  service_name = aws_apprunner_service.webapp_service.service_name
  source_configuration = aws_apprunner_service.webapp_service.source_configuration
  instance_configuration = aws_apprunner_service.webapp_service.instance_configuration
  health_check_configuration = aws_apprunner_service.webapp_service.health_check_configuration

  # Reference the IAM role
  instance_configuration {
    cpu      = aws_apprunner_service.webapp_service.instance_configuration[0].cpu
    memory   = aws_apprunner_service.webapp_service.instance_configuration[0].memory
    instance_role_arn = aws_iam_role.apprunner_iam_role.arn
  }
}

