```hcl
# AWS Elastic Beanstalk Application with Application Version Lifecycle Configuration

resource "aws_elastic_beanstalk_application" "example" {
  name        = "example-application"
  description = "Example Elastic Beanstalk Application with version lifecycle management"
}

resource "aws_elastic_beanstalk_application_version" "example" {
  name        = "example-version-${formatdate("YYYY-MM-DD-HHmm", timestamp())}"
  application = aws_elastic_beanstalk_application.example.name
  description = "Example application version"

  # Source bundle configuration
  # This assumes you have a source bundle in S3
  # For actual use, replace with your S3 bucket and key
  # Or use the "content" argument with local file
  bucket = "my-elastic-beanstalk-apps"
  key    = "app-v1.zip"

  # Optional: For local file deployment
  # content {
  #   source {
  #     filename = "app.zip"
  #   }
  # }

  # Trigger redeployment when source changes
  depends_on = [
    aws_elastic_beanstalk_application.example
  ]
}

# Configure application version lifecycle
resource "aws_elastic_beanstalk_configuration_template" "example" {
  name                = "example-template"
  application         = aws_elastic_beanstalk_application.example.name
  solution_stack_name = "64bit Amazon Linux 2 v5.7.4 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "ENVIRONMENT"
    value     = "production"
  }

  # Application version lifecycle settings
  setting {
    namespace = "aws:elasticbeanstalk:application"
    name      = "Application Healthcheck URL"
    value     = "/health"
  }

  # Version lifecycle configuration
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "VERSION_LIFECYCLE_ENABLE"
    value     = "true"
  }

  # Configure lifecycle for application versions
  setting {
    namespace = "aws:elasticbeanstalk:application:versioncleanup"
    name      = "maxCount"
    value     = "10"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:versioncleanup"
    name      = "deleteSourceFromS3"
    value     = "true"
  }

  # Set to true to enable lifecycle management
  setting {
    namespace = "aws:elasticbeanstalk:application:versioncleanup"
    name      = "serviceRole"
    value     = aws_iam_role.eb_service_role.arn
  }
}

# IAM role for Elastic Beanstalk to manage application versions
resource "aws_iam_role" "eb_service_role" {
  name = "elastic-beanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy for application version cleanup
resource "aws_iam_role_policy" "eb_service_policy" {
  name = "elastic-beanstalk-service-policy"
  role = aws_iam_role.eb_service_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:Get*",
          "s3:DeleteObject",
          "s3:List*"
        ]
        Resource = [
          "arn:aws:s3:::my-elastic-beanstalk-apps",
          "arn:aws:s3:::my-elastic-beanstalk-apps/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:Describe*"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "elasticloadbalancing:Describe*"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:Describe*",
          "cloudwatch:Get*",
          "cloudwatch:List*"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "autoscaling:Describe*",
          "autoscaling:UpdateAutoScalingGroup"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "sns:List*"
        ]
        Resource = "*"
      }
    ]
  })
}

# Optional: Environment configuration for the application
resource "aws_elastic_beanstalk_environment" "example" {
  name                = "example-env"
  application         = aws_elastic_beanstalk_application.example.name
  solution_stack_name = aws_elastic_beanstalk_configuration_template.example.solution_stack_name
  version_label       = aws_elastic_beanstalk_application_version.example.name

  # Use the configuration template
  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }
}
```

