# We need to create an Elastic Beanstalk application and configure the lifecycle policy for application versions.
# Step 1: Create an Elastic Beanstalk application using aws_elastic_beanstalk_application.
# Step 2: Within the application, configure the application_version_lifecycle to delete versions after 5 days.
# The lifecycle configuration includes settings like max_count, delete_source_from_s3, and service roles are not needed here unless specified.

resource "aws_elastic_beanstalk_application" "example" {
  name        = "example-application"
  description = "An Elastic Beanstalk application with lifecycle policy"

  appversion_lifecycle {
    service_role                  = aws_iam_role.beanstalk_service_role.arn
    max_age_in_days               = 5
    delete_source_from_s3         = true
    max_count                     = 100  # Optional: set a limit on number of versions, but not required; defaults to unlimited if not set
    ignore_public_acl             = true # Recommended for newer buckets to avoid ACL issues
  }
}

# We need an IAM service role for Elastic Beanstalk to manage application versions.
# Step 3: Create an IAM role that Elastic Beanstalk can assume to manage lifecycle policies.

resource "aws_iam_role" "beanstalk_service_role" {
  name = "elastic-beanstalk-lifecycle-role"

  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "",
      "Effect": "Allow",
      "Principal": {
        "Service": "elasticbeanstalk.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
POLICY
}

# Step 4: Attach the required managed policy to allow lifecycle management.
# AWS provides a managed policy: AWSElasticBeanstalkService => AmazonElasticBeanstalkService

resource "aws_iam_role_policy_attachment" "beanstalk_service_role_attachment" {
  role       = aws_iam_role.beanstalk_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

