# Create an AWS CodeBuild project with a sample IAM role and GitHub source

# Step 1: Define the IAM role required for CodeBuild to access AWS resources and perform actions
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Step 2: Attach a managed policy to the role to grant permissions for CodeBuild operations
resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryPowerUser"
  role       = aws_iam_role.codebuild_role.name
}

# Optional: Attach CloudWatch Logs and S3 permissions for logs and artifacts
resource "aws_iam_role_policy_attachment" "codebuild_logs" {
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
  role       = aws_iam_role.codebuild_role.name
}

# Step 3: Define the CodeBuild project with GitHub as the source
resource "aws_codebuild_project" "example" {
  name          = "sample-codebuild-project"
  description   = "A sample CodeBuild project using GitHub source"
  build_timeout = 60
  queued_timeout = 480

  # Source configuration using GitHub
  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    # Version can be a branch, tag, or commit
    git_checkout_submodules = false
  }

  # Source version (e.g., branch name)
  source_version = "main"

  # Artifacts - none in this simple case
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    # Environment variables (optional)
    environment_variable {
      name  = "PARAM1"
      value = "VALUE"
    }
  }

  # Service role for CodeBuild
  service_role = aws_iam_role.codebuild_role.arn

  # Enable CloudWatch Logs
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${aws_codebuild_project.example.name}"
      stream_name = "${aws_codebuild_project.example.name}"
      status      = "ENABLED"
    }
    s3_logs {
      status = "DISABLED"
    }
  }

  # Tags
  tags = {
    Name        = "SampleCodeBuild"
    Environment = "Dev"
  }
}

