# Step-by-step breakdown:
# 1. Create an IAM role for CodeBuild to assume with necessary permissions
# 2. Define the AWS CodeBuild project with:
#    - Name and description
#    - Source from GitHub (using a GitHub source location)
#    - Build artifacts configuration (e.g., S3 or no output)
#    - Cache settings (e.g., local or S3 cache)
#    - Environment (image, type, compute type)
#    - Service role referencing the IAM role

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-service-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name         = "sample-codebuild-project"
  description  = "Sample project for CodeBuild with GitHub source"
  service_role = aws_iam_role.codebuild_role.arn

  # GitHub source configuration
  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo "Installing dependencies..."
  build:
    commands:
      - echo "Building the project..."
  post_build:
    commands:
      - echo "Build completed."
artifacts:
  files:
    - "**/*"
EOF
  }

  # Build artifacts (S3 bucket name should be configured if needed)
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Cache settings using local mode
  cache {
    type = "LOCAL"
    modes = [
      "LOCAL_DOCKER_LAYER_CACHE",
      "LOCAL_SOURCE_CACHE",
      "LOCAL_CUSTOM_CACHE"
    ]
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false
  }

  # Project tags
  tags = {
    Environment = "dev"
    Project     = "SampleCodeBuild"
  }
}

