# This Terraform configuration defines an AWS CodeBuild project with a sample IAM role
# and includes secondary source configurations. We'll:
# 1. Create an IAM role with necessary permissions for CodeBuild
# 2. Define a CodeBuild project with primary and secondary source configurations
# 3. Include sample build specifications

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-example-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          "arn:aws:s3:::codebuild-*",
          "arn:aws:s3:::codebuild-*/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "An example CodeBuild project with secondary sources"
  build_timeout = 60
  queued_timeout = 480
  concurrent_build_limit = 1

  # Primary source
  source {
    type      = "GITHUB"
    location  = "https://github.com/example/example-repo.git"
    git_clone_depth = 1
    git_submodules_config {
      fetch_submodules = true
    }
  }

  # Secondary sources
  secondary_source {
    source_identifier = "secondary-repo"
    type               = "BITBUCKET"
    location           = "https://bitbucket.org/example/secondary-repo.git"
    git_clone_depth    = 1
  }

  secondary_source {
    source_identifier = "third-party-repo"
    type               = "CODECOMMIT"
    location           = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/ThirdPartyRepo"
    git_clone_depth    = 1
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  secondary_artifacts {
    artifact_identifier = "secondary-artifact"
    type                = "S3"
    location            = "my-output-bucket"
    path                = "artifacts"
    packaging           = "ZIP"
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    image_pull_credentials_type = "SERVICE_ROLE"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }

    environment_variable {
      name  = "DATABASE_URL"
      value = "production-db.example.com"
      type  = "PLAINTEXT"
    }
  }

  # Specify the service role
  service_role = aws_iam_role.codebuild_role.arn

  # Sample build spec
  source_version = "main"

  # Build spec can either be inline or referenced from source
  build_spec = jsonencode({
    version = "0.2"
    phases = {
      install = {
        commands = [
          "echo Installing dependencies...",
          "npm install"
        ]
      }
      pre_build = {
        commands = [
          "echo Logging in to Amazon ECR...",
          "aws ecr get-login-password --region $AWS_DEFAULT_REGION | docker login --username AWS --password-stdin $AWS_ACCOUNT_ID.dkr.ecr.$AWS_DEFAULT_REGION.amazonaws.com"
        ]
      }
      build = {
        commands = [
          "echo Build started on `date`",
          "echo Compiling the code...",
          "npm run build"
        ]
      }
      post_build = {
        commands = [
          "echo Build completed on `date`"
        ]
      }
    }
    artifacts = {
      files = [
        "dist/**/*"
      ]
    }
  })

  # Tags
  tags = {
    Project = "Example"
    Environment = "Production"
  }
}

