resource "aws_codebuild_project" "sample_build_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with batch configuration"
  build_timeout = 60
  queued_timeout = 480
  concurrent_build_limit = 2

  # Source configuration
  source {
    type      = "GITHUB"
    location  = "https://github.com/example/sample-repo.git"
    git_clone_depth = 1

    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo "Installing dependencies"
  build:
    commands:
      - echo "Building sample application"
  post_build:
    commands:
      - echo "Build completed"
artifacts:
  files:
    - '**/*'
EOF
  }

  # Batch configuration
  batch = {
    service_role = aws_iam_role.codebuild_role.arn
    default_build_batch_config = {
      batch_enabled = true
      combine_artifacts = true
      restrictions = {
        maximum_builds_allowed = 10
      }
    }
    compute_type_override = "BUILD_GENERAL1_LARGE"
    environment_type_override = "LINUX_CONTAINER"
    image_override = "aws/codebuild/standard:5.0"
    build_image_type_override = "CODEBUILD_IMAGE"
  }

  # Environment configuration
  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "SAMPLE_VAR"
      value = "sample-value"
    }
  }

  # Artifacts configuration
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Logs configuration
  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/${aws_codebuild_project.sample_build_project.name}"
      stream_name = "main"
    }
    s3_logs {
      enabled = false
    }
  }

  # IAM role
  service_role = aws_iam_role.codebuild_role.arn

  # Tags
  tags = {
    Environment = "sample"
    Project     = "codebuild-demo"
  }
}

