# We are building an AWS Lex bot with several slots.
# Steps:
# 1. Define the Lex bot using aws_lex_bot.
# 2. Define the intents that the bot will use, which include the slots.
# 3. Define the slot types if using custom ones, though built-in ones can be used too.
# 4. Each intent can have multiple slots, so we'll create an intent with several slots.

# We'll create a sample bot for booking a hotel reservation, including slots like:
# - Check-in date
# - Check-out date
# - Room type
# - Number of guests

# Note: AWS Lex V1 is used here via Terraform aws provider since Lex V2 has different resources.
# Resource: aws_lex_bot, aws_lex_intent, aws_lex_slot_type (if custom)

resource "aws_lex_intent" "book_hotel_intent" {
  name = "BookHotel"

  # Sample slots in the intent
  slot {
    name                 = "CheckInDate"
    slot_type            = "AMAZON.DATE"
    slot_type_name       = "AMAZON.DATE"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day would you like to check in?"
        content_type = "PlainText"
      }
    }
    priority    = 1
    description = "The date the guest checks into the hotel."
  }

  slot {
    name           = "CheckOutDate"
    slot_type      = "AMAZON.DATE"
    slot_type_name = "AMAZON.DATE"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day would you like to check out?"
        content_type = "PlainText"
      }
    }
    priority    = 2
    description = "The date the guest checks out of the hotel."
  }

  slot {
    name           = "RoomType"
    slot_type      = "RoomType"
    slot_type_name = aws_lex_slot_type.room_type.name
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of room do you prefer? For example, king, queen, or twin."
        content_type = "PlainText"
      }
    }
    priority    = 3
    description = "The type of room to book."
  }

  slot {
    name           = "NumberOfGuests"
    slot_type      = "AMAZON.NUMBER"
    slot_type_name = "AMAZON.NUMBER"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many guests will be staying?"
        content_type = "PlainText"
      }
    }
    priority    = 4
    description = "Number of guests staying in the room."
  }

  # Confirmation prompt
  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I'll book a {RoomType} room from {CheckInDate} to {CheckOutDate} for {NumberOfGuests} guests. Should I proceed?"
      content_type = "PlainText"
    }
  }

  # Rejection statement
  rejection_statement {
    message {
      content      = "Okay, I will not book the hotel."
      content_type = "PlainText"
    }
  }

  # Sample utterances
  sample_utterances = [
    "I want to book a hotel",
    "Book a room",
    "Reserve a {RoomType} room from {CheckInDate} to {CheckOutDate}",
  ]

  # Conclusion statement
  conclusion_statement {
    message {
      content      = "Your hotel is booked. Enjoy your stay!"
      content_type = "PlainText"
    }
  }

  # Description
  description = "Intent to book a hotel reservation with multiple slots"
}

# Define a custom slot type for RoomType
resource "aws_lex_slot_type" "room_type" {
  name        = "RoomType"
  description = "Hotel room types"

  enumeration_value {
    value = "king"
  }
  enumeration_value {
    value = "queen"
  }
  enumeration_value {
    value = "twin"
  }
  enumeration_value {
    value = "double"
  }

  create_version = true
}

# Create the Lex bot
resource "aws_lex_bot" "hotel_booking_bot" {
  name                  = "HotelBookingBot"
  description           = "Bot to book hotel reservations"
  abort_statement {
    message {
      content      = "Sorry, I couldn't understand. Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.book_hotel_intent.name
    intent_version = "$LATEST"
  }

  # Clarification prompt for when Lex doesn't understand
  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand. Can you please repeat?"
      content_type = "PlainText"
    }
  }

  # Output voice for audio responses
  voice_id = "Joanna"

  # Session timeout in seconds
  idle_session_ttl_in_seconds = 300

  # Process the bot
  process_behavior = "SAVE"

  # Create a version of the bot
  create_version = false

  # Locale
  locale = "en-US"

  # Enable conversation logs if needed (optional)
  # Not included here for simplicity
}
