extracted_code:
# Create an AWS Lex bot for pizza ordering with a closing summary
# We'll define the bot with required intents, slots, and a closing statement

resource "aws_lex_bot" "pizza_bot" {
  name                = "PizzaOrderingBot"
  description         = "A bot to handle pizza ordering with a summary confirmation"
  abort_statement     = {
    message = [
      {
        content          = "Sorry, I couldn't process your pizza order. Starting over."
        content_type     = "PlainText"
        group_number     = 1
      }
    ]
  }

  clarification_prompt = {
    message = [
      {
        content          = "I didn't understand. Can you please repeat your pizza order?"
        content_type     = "PlainText"
        group_number     = 1
      }
    ]
    max_attempts = 2
  }

  # Closing statement that summarizes the order
  conclusion_statement = {
    message = [
      {
        content          = "Great! I've placed your pizza order. You ordered a ${dialogAction.slotToElicit.pizzaSize} pizza with ${dialogAction.slotToElicit.toppings}. Your order will be ready in 30 minutes. Total: ${dialogAction.slotToElicit.totalPrice}. Thank you!"
        content_type     = "PlainText"
        group_number     = 1
      }
    ]
  }

  intent {
    intent_name    = "OrderPizza"
    intent_version = "$LATEST"
  }

  # We need a fulfillment role for the bot
  role_arn = aws_iam_role.lex_role.arn

  # Set processing to true
  process_behavior = "BUILD"

  # Idle session timeout
  idle_session_ttl_in_seconds = 300

  # Locale
  locale = "en-US"

  # Voice settings (optional)
  voice_id = "Salli"
}

# Create an IAM role for the Lex bot to invoke Lambda for fulfillment
resource "aws_iam_role" "lex_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary policy to the role
resource "aws_iam_role_policy_attachment" "lex_policy" {
  role       = aws_iam_role.lex_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# Define the intent separately (required by AWS Lex)
resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  # Sample utterances
  fulfillment_activity {
    type = "ReturnIntent"
  }

  # Create slots for the pizza ordering
  slot {
    name                 = "pizzaSize"
    description          = "The size of the pizza"
    slot_type            = "AMAZON.Number"
    slot_type_version    = "$LATEST"
    value_elicitation_prompt {
      message {
        content      = "What size pizza would you like? (e.g., 10, 12, 14 inch)"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 1
  }

  slot {
    name                 = "toppings"
    description          = "Pizza toppings"
    slot_type            = "AMAZON.Food"
    slot_type_version    = "$LATEST"
    value_elicitation_prompt {
      message {
        content      = "What toppings would you like on your pizza?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 2
  }

  slot {
    name                 = "deliveryAddress"
    description          = "Delivery address"
    slot_type            = "AMAZON.StreetAddress"
    slot_type_version    = "$LATEST"
    value_elicitation_prompt {
      message {
        content      = "Where should we deliver your pizza?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 3
  }

  slot {
    name                 = "totalPrice"
    description          = "The total price of the order"
    slot_type            = "AMAZON.Number"
    slot_type_version    = "$LATEST"
    value_elicitation_prompt {
      message {
        content      = "The total for your order is ${dialogAction.slotToElicit.totalPrice}. Does that work for you?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
