# Building an AWS Lex Bot for pizza ordering with 5 intents
# Step 1: Define the Lex Bot with clarification and abort statements
# Step 2: Create 5 distinct intents for pizza ordering workflow:
#   - OrderPizza: Main intent to start ordering
#   - AddToppings: Add toppings to pizza
#   - SelectCrust: Choose crust type
#   - SpecifyQuantity: Set number of pizzas
#   - ConfirmOrder: Final confirmation
# Step 3: Use IAM role for Lex bot permissions
# Step 4: Ensure bot is set to latest Lex V2 with idle session timeout

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSLexExecute"
}

resource "aws_lex_bot" "pizza_ordering_bot" {
  name = "PizzaOrderingBot"
  description = "A conversational bot designed to take pizza orders"
  role_arn = aws_iam_role.lex_bot_role.arn

  data_privacy = {
    child_directed = false
  }

  idle_session_ttl_in_seconds = 300
  type = "Bot"
  auto_build_bot_locales = true

  bot_locales = [
    {
      locale_id = "en_US"
      intents = [
        {
          name = "OrderPizza"
          description = "Initiate a new pizza order"
          sample_utterances = [
            "I want to order a pizza",
            "Place a pizza order",
            "Get me a pizza",
            "Order pizza please"
          ]
          intent_confirmation_setting = {
            prompt_specification = {
              message = [
                {
                  content = "Would you like to start a pizza order?"
                  content_type = "PlainText"
                }
              ]
              max_attempts = 2
            }
            declination_response = {
              message = [
                {
                  content = "Okay, maybe next time!"
                  content_type = "PlainText"
                }
              ]
            }
          }
          dialog_code_hook = {
            enabled = false
          }
          fulfillment_code_hook = {
            enabled = true
          }
        },
        {
          name = "AddToppings"
          description = "Add toppings to the current pizza"
          sample_utterances = [
            "Add pepperoni",
            "Put mushrooms on it",
            "Extra cheese please",
            "I want sausage and onions"
          ]
          dialog_code_hook = {
            enabled = false
          }
          fulfillment_code_hook = {
            enabled = true
          }
        },
        {
          name = "SelectCrust"
          description = "Choose crust type for the pizza"
          sample_utterances = [
            "Thin crust",
            "Deep dish",
            "Stuffed crust",
            "Gluten free crust"
          ]
          dialog_code_hook = {
            enabled = false
          }
          fulfillment_code_hook = {
            enabled = true
          }
        },
        {
          name = "SpecifyQuantity"
          description = "Set the number of pizzas to order"
          sample_utterances = [
            "I want two pizzas",
            "Order 3 pizzas",
            "Just one pizza",
            "Need four of them"
          ]
          dialog_code_hook = {
            enabled = false
          }
          fulfillment_code_hook = {
            enabled = true
          }
        },
        {
          name = "ConfirmOrder"
          description = "Confirm the final pizza order"
          sample_utterances = [
            "Yes, place my order",
            "Confirm this order",
            "That looks good, order it",
            "Finalize my pizza order"
          ]
          intent_confirmation_setting = {
            prompt_specification = {
              message = [
                {
                  content = "Ready to confirm your pizza order?"
                  content_type = "PlainText"
                }
              ]
              max_attempts = 2
            }
            declination_response = {
              message = [
                {
                  content = "Order cancelled."
                  content_type = "PlainText"
                }
              ]
            }
          }
          dialog_code_hook = {
            enabled = false
          }
          fulfillment_code_hook = {
            enabled = true
          }
        }
      ]

      slot_types = []
      voice_settings = {
        voice_id = "Joanna"
      }
    }
  ]

  member = []
}

