    intent_name    = aws_lex_intent.ModifyOrder.name
    intent_version = aws_lex_intent.ModifyOrder.version
  }

  intent {
    intent_name    = aws_lex_intent.HelpOrder.name
    intent_version = aws_lex_intent.HelpOrder.version
  }
}

