# Designing an AWS Lex Bot for Children to Place Pizza Orders
# We need to consider:
# 1. A Lex Bot with appropriate intents for ordering pizza
# 2. Child-friendly prompts and responses
# 3. Necessary IAM permissions for Lex
# 4. Integration capabilities
# 5. Session configuration for conversational flow

# Create the Lex Bot for pizza ordering
resource "aws_lex_bot" "pizza_bot_for_children" {
  name                = "PizzaPal"
  description         = "A friendly pizza ordering bot designed for children"
  idle_session_ttl_in_seconds = 300
  locale              = "en-US"
  child_directed      = true  # Important: This bot is for children, so we must comply with COPPA
  voice_id            = "Joanna"  # Friendly, clear voice

  # Intent: OrderPizza - The main intent for placing a pizza order
  intent {
    intent_name    = "OrderPizza"
    intent_version = "$LATEST"
  }

  # Intent: AMAZON.HelpIntent - Built-in help
  intent {
    intent_name    = "AMAZON.HelpIntent"
    intent_version = "$LATEST"
  }

  # Intent: AMAZON.CancelIntent - Built-in cancel
  intent {
    intent_name    = "AMAZON.CancelIntent"
    intent_version = "$LATEST"
  }

  # Intent: AMAZON.StopIntent - Built-in stop
  intent {
    intent_name    = "AMAZON.StopIntent"
    intent_version = "$LATEST"
  }

  # Create version-dependent settings
  clarification_prompt {
    message {
      content          = "I'm your pizza pal! Could you say that again please?"
      content_type     = "PlainText"
      group_number     = 1
    }
    max_attempts = 2
  }

  # Message when the user's request isn't understood
  abort_statement {
    message {
      content      = "I'm sorry, I couldn't help with your pizza order. Let's try again later!"
      content_type = "PlainText"
      group_number = 1
    }
  }

  # Child-directed must be true and we cannot enable cloudwatch logs due to child privacy
  # Lex bot will be designed with simple, friendly language appropriate for children
}

# Create the OrderPizza intent with slots for pizza ordering
resource "aws_lex_intent" "order_pizza_intent" {
  name = "OrderPizza"
  description = "Intent to order a pizza with various toppings and size"

  # Sample utterances that children might use
  sample_utterances = [
    "I want a pizza",
    "I would like to order a pizza",
    "Can I have a pizza please",
    "I'm hungry for pizza",
    "Get me a pizza",
    "Order a pizza",
    "I want to buy a pizza"
  ]

  # Slot: PizzaSize - What size pizza does the child want?
  slot {
    name                  = "PizzaSize"
    slot_type_name        = "AMAZON.Number"
    slot_type             = "AMAZON.PizzaSize"
    value_elicitation_prompt {
      message {
        content      = "What size pizza would you like? We have small, medium, and large!"
        content_type = "PlainText"
        group_number = 1
      }
      max_attempts = 2
    }
    priority = 1
    description = "Size of the pizza"
  }

  # Slot: Toppings - What toppings should go on the pizza?
  slot {
    name                  = "Toppings"
    slot_type_name        = "AMAZON.PizzaToppings"
    value_elicitation_prompt {
      message {
        content      = "What toppings would you like on your pizza? You can say pepperoni, cheese, mushrooms, or whatever you like!"
        content_type = "PlainText"
        group_number = 1
      }
      max_attempts = 3
    }
    priority = 2
    description = "Toppings for the pizza"
  }

  # Slot: CrustType - What kind of crust?
  slot {
    name                  = "CrustType"
    slot_type_name        = "AMAZON.PizzaCrust"
    value_elicitation_prompt {
      message {
        content      = "What kind of crust would you like? We have thin, thick, and stuffed crust!"
        content_type = "PlainText"
        group_number = 1
      }
      max_attempts = 2
    }
    priority = 3
    description = "Type of pizza crust"
  }

  # Confirmation prompt before placing the order
  confirmation_prompt {
    message {
      content      = "So you want a {PizzaSize} pizza with {Toppings} on {CrustType} crust? Should I go ahead and order that for you?"
      content_type = "PlainText"
      group_number = 1
    }
    max_attempts = 2
  }

  # What to say when the order is successfully placed
  conclusion_statement {
    message {
      content      = "Yay! I've ordered your delicious {PizzaSize} {Toppings} pizza on {CrustType} crust! It will be ready soon. Enjoy your pizza!"
      content_type = "PlainText"
      group_number = 1
    }
  }

  # What to say if the user cancels the order
  rejection_statement {
    message {
      content      = "Okay, no pizza this time. You can always order later!"
      content_type = "PlainText"
      group_number = 1
    }
  }
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-pizzapal-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Permissions for the Lex bot role
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

# Update the bot to use the IAM role
resource "aws_lex_bot" "pizza_bot_for_children" {
  # ... (previous configuration)
  role_arn = aws_iam_role.lex_bot_role.arn
}

