# Creating an AWS Lex V2 Bot intended for kids
# Step-by-step considerations:
# 1. Use aws_lexv2models_bot resource to define the bot
# 2. Set appropriate name, description, and data privacy settings
# 3. Specify idle session timeout (children may take longer to respond)
# 4. Enable child-directed setting as required by COPPA
# 5. Set appropriate voice settings if speech is enabled
# 6. Define bot locales (at minimum, en-US)

resource "aws_lexv2models_bot" "kids_bot" {
  name                        = "KidsAssistantBot"
  description                 = "A fun and educational conversational assistant designed for children"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed            = true  # Required for bots directed at children under 13
  }
  idle_session_ttl_in_seconds = 600   # 10 minutes timeout (longer than default for kids)

  # Define the bot locale - English (US) 
  bot_locale {
    locale_id                  = "en_US"
    nlu_confidence_threshold   = 0.4  # Lower threshold to be more forgiving of children's speech variations
    voice_settings {
      voice_id                 = "Joanna" # Friendly, clear voice
    }
  }

  # Additional settings
  timeouts {
    create = "30m"
    update = "30m"
    delete = "30m"
  }
}

# Create IAM role required for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-kids-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lex execution policy
resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBots"
}

