# Step 1: Create a Kinesis data stream to serve as input for the Kinesis Data Analytics application
resource "aws_kinesis_stream" "input_stream" {
  name             = "input-data-stream"
  shard_count      = 1
  retention_period = 24
}

# Step 2: Create an S3 bucket to store the Kinesis Data Analytics application code and dependencies
resource "aws_s3_bucket" "application_code" {
  bucket = "kinesis-analytics-app-code"
}

resource "aws_s3_bucket_acl" "application_code_acl" {
  bucket = aws_s3_bucket.application_code.id
  acl    = "private"
}

# Step 3: Upload an example application code (placeholder) to S3
# Note: Kinesis Data Analytics for Apache Flink requires code to be in S3
resource "aws_s3_object" "application_jar" {
  bucket = aws_s3_bucket.application_code.bucket
  key    = "kinesis-analytics-app.jar"
  source = "path/to/your/application.jar" # Replace with actual path or use a dummy file in practice
  etag   = filemd5("path/to/your/application.jar")
}

# Step 4: Create IAM role for Kinesis Data Analytics application to access AWS resources
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Step 5: Define IAM policy for the role to access Kinesis stream and S3
resource "aws_iam_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.input_stream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "${aws_s3_bucket.application_code.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
