    # Define the input configuration
    streaming_systems_input {
      name_prefix = "SOURCE_SQL_STREAM"

      input_schema {
        record_format_type = "JSON"

        mapping_parameters {
          json_mapping_parameters {
            record_row_path = "$"
          }
        }

        record_column {
          name = "example_column"
          type = "VARCHAR(16)"
        }
      }

      kinesis_stream_input {
        resource_arn = aws_kinesis_stream.input_stream.arn
      }
    }
  }

  # Optional: enable monitoring configuration
  cloudwatch_logging_options {
