# Create an S3 bucket for failed delivery data (required for Firehose when using Elasticsearch as destination)
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-es-backup-bucket-${random_id.suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Generate a random suffix to ensure unique bucket name
resource "random_id" "suffix" {
  byte_length = 4
}

# Create the IAM role that Firehose will assume to deliver data to Elasticsearch and backup to S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose-es-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary permissions to the IAM role
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_es_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:ESHttpGet"
        ]
        Resource = aws_elasticsearch_domain.es_domain.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*:*"
      }
    ]
  })
}

# Create the Elasticsearch domain (required for the Firehose destination)
resource "aws_elasticsearch_domain" "es_domain" {
  domain_name = "firehose-es-domain"

  elasticsearch_version = "7.10"

  cluster_config {
    instance_type = "t3.small.elasticsearch"
    instance_count = 1
    dedicated_master_enabled = false
    zone_awareness_enabled = false
  }

  ebs_options {
    ebs_enabled = true
    volume_type = "gp2"
    volume_size = 10
  }

  domain_endpoint_options {
    enforce_https = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = "es:*"
        Resource = "${aws_elasticsearch_domain.es_domain.arn}/*"
      }
    ]
  })
}

# Create the Kinesis Data Firehose delivery stream
resource "aws_kinesis_firehose_delivery_stream" "es_stream" {
  name        = "es-delivery-stream"
  destination = "elasticsearch"

  # S3 configuration for source data and backup
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_backup.arn

    # Buffer settings
    buffer_size = 5
    buffer_interval = 300
    compression_format = "UNCOMPRESSED"
  }

  # Elasticsearch destination configuration
  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.es_domain.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-data"
    type_name  = "_doc"  # Removed in ES 7.x+, but required for compatibility in Firehose
    index_rotation = "OneDay"

    # Buffer settings before delivering to ES
    buffering_interval = 300
    buffering_size     = 5

    # Retry duration in case of indexing failure
    retry_duration = 300

    # CloudWatch logging for the destination
    cloudwatch_logging_options {
      enabled = true
      log_group_name = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.es_stream.name}"
      log_stream_name = "destination-elasticsearch"
    }
  }

  # Depends on the IAM role being created first
  depends_on = [
    aws_iam_role_policy.firehose_policy
  ]
}

