    domain_arn                  = "arn:aws:es:us-west-2:123456789012:domain/my-opensearch-domain" # Replace with actual domain ARN
    index_name                  = "firehose-logs"
    type_name                   = "_doc"  # Optional; ignored in OpenSearch 7.10+
    index_rotation_period       = "OneDay"
    retry_duration              = 300
    s3_backup_mode              = "FailedDocumentsOnly"

    processing_configuration {
      enabled = false
    }

    vpc_config {
      # Only include if OpenSearch is in a VPC
