    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/firehose/opensearch-stream"
      log_stream_name = "delivery-stream"
    }
  }

  tags = {
    Environment = "dev"
    Purpose     = "testing"
  }
}
