# Create an Amazon Kinesis Data Firehose delivery stream targeting Amazon OpenSearch Serverless
# Steps:
# 1. Define the Firehose delivery stream with 'destination' set to 'opensearchserverless'
# 2. Specify necessary OpenSearch Serverless configuration including collection endpoint and index name
# 3. Include required IAM role for Firehose to access OpenSearch Serverless and other AWS services
# 4. Set up buffer hints, retry, and backup configurations

resource "aws_kinesis_firehose_delivery_stream" "opensearch_serverless_stream" {
  name        = "firehose-to-opensearch-serverless"
  destination = "opensearchserverless"

  # OpenSearch Serverless destination configuration
  opensearchserverless_configuration {
    # The OpenSearch Serverless collection endpoint
    collection_endpoint = aws_opensearchserverless_collection.example.collection_endpoint

    # The name of the index where data will be indexed
    index_name = "firehose-index"

    # IAM role that Firehose will assume to deliver data and manage OpenSearch Serverless
    role_arn = aws_iam_role.firehose_role.arn

    # Specifies the S3 bucket/configuration for intermediate storage before delivery
    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.bucket.arn

      # Optional: buffer settings
      buffer_size  = 5
      buffer_interval = 300
      compression_format = "UNCOMPRESSED"
    }

    # Retry duration in seconds if indexing fails
    retry_duration = 300

    # Document ID configuration (optional)
    # document_id_options {
    #   default_document_id_format = "FIREHOSE_DEFAULT"
    # }

    # VPC configuration if OpenSearch Serverless is in a VPC (optional)
