# Create an Amazon Kinesis Data Firehose delivery stream to deliver data to an Elasticsearch domain within a VPC

# Step 1: Define required providers (AWS)
provider "aws" {
  region = "us-east-1"  # Can be customized based on use case
}

# Step 2: Create an Elasticsearch domain (AWS OpenSearch Service) within a VPC
resource "aws_opensearch_domain" "example" {
  domain_name = "firehose-es-domain"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 1
    zone_awareness_enabled = false
  }

  vpc_options {
    security_group_ids = [aws_security_group.elasticsearch_sg.id]
    subnet_ids         = [aws_subnet.example.id]
  }

  # Enable fine-grained access control and enforce HTTPS
  encrypt_at_rest {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  node_to_node_encryption {
    enabled = true
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }
}

# Step 3: Create a VPC and subnet for the Elasticsearch domain
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support = true

  tags = {
    Name = "firehose-es-vpc"
  }
}

resource "aws_subnet" "example" {
  vpc_id = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "firehose-es-subnet"
  }
}

# Step 4: Security group to allow Firehose to access Elasticsearch in the VPC
resource "aws_security_group" "elasticsearch_sg" {
  name   = "allow-firehose"
  vpc_id = aws_vpc.example.id

  # Allow HTTPS from Kinesis Firehose (typically uses port 443)
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # In practice, restrict to Firehose IPs or use VPC endpoint
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow-firehose-es"
  }
}

# Step 5: IAM role for Firehose to access Elasticsearch and other services
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Step 6: IAM role policy to allow Firehose to deliver data to Elasticsearch and write logs
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_es_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:ESHttpPatch"
        ]
        Resource = aws_opensearch_domain.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesisfirehose/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      }
    ]
  })
}

# Step 7: S3 bucket as a backup location for Firehose
resource "aws_s3_bucket" "bucket" {
  bucket = "firehose-backup-bucket-example"
}

# Step 8: Create the Kinesis Firehose delivery stream to Elasticsearch (OpenSearch)
resource "aws_kinesis_firehose_delivery_stream" "es_stream" {
  name = "firehose-to-es-vpc"
  destination = "elasticsearch"

  # S3 configuration for intermediate storage and backup
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.bucket.arn
    buffer_size = 5
    buffer_interval = 300
    compression_format = "UNCOMPRESSED"
  }

  elasticsearch_configuration {
    domain_arn = aws_opensearch_domain.example.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-stream-index"
    type_name  = "firehose-type" # Not required in newer OpenSearch versions
    index_rotation_period = "OneDay"
    buffering_interval = 300
    buffering_size = 5
    retry_duration = 300
    s3_backup_mode = "FailedDocumentsOnly"

    vpc_config {
      subnet_ids = [aws_subnet.example.id]
      security_group_ids = [aws_security_group.elasticsearch_sg.id]
      role_arn = aws_iam_role.firehose_role.arn
    }
  }

  depends_on = [
    aws_iam_role_policy.firehose_policy,
    aws_opensearch_domain.example
  ]
}

