# Create an Amazon Kinesis Data Firehose delivery stream configured to send data to an Amazon OpenSearch destination within a VPC

# Step 1: Define required AWS provider
provider "aws" {
  region = "us-west-2" # Can be changed as needed
}

# Step 2: Create an IAM role for Kinesis Firehose to assume
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Step 3: Attach required IAM policies to the role for Firehose to access OpenSearch and other services
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpWrite"
        ]
        Resource = aws_opensearch_domain.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:AbortMultipartUpload",
          "s3:ListMultipartUploadParts",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

# Step 4: Create an S3 bucket as a required intermediate destination (Firehose buffers data here before sending to OpenSearch)
resource "aws_s3_bucket" "bucket" {
  bucket = "firehose-opensearch-bucket-example"
}

resource "aws_s3_bucket_acl" "bucket_acl" {
  bucket = aws_s3_bucket.bucket.id
  acl    = "private"
}

# Step 5: Create an OpenSearch domain within a VPC
resource "aws_opensearch_domain" "example" {
  domain_name = "example-domain"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 1
    zone_awareness_enabled = false
  }

  vpc_options {
    security_group_ids = [aws_security_group.opensearch_sg.id]
    subnet_ids         = [aws_subnet.example.id]
  }

  # Enable encryption and authentication
  encrypt_at_rest {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }
}

# Step 6: Define a security group for OpenSearch VPC access
resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-firehose-sg"
  description = "Allow Firehose and clients to reach OpenSearch"

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    # Only allow Firehose and trusted sources (can be limited further)
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Step 7: Define a VPC and subnet for OpenSearch (if not using existing)
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "opensearch-vpc"
  }
}

resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "opensearch-subnet"
  }
}

# Step 8: Create the Kinesis Firehose delivery stream to OpenSearch within VPC
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-to-opensearch-vpc"
  destination = "opensearch"

  # S3 configuration is required as intermediate storage
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.bucket.arn
    buffer_size = 5
    buffer_interval = 300
    compression_format = "UNCOMPRESSED"
  }

  opensearch_configuration {
    role_arn        = aws_iam_role.firehose_role.arn
    domain_arn      = aws_opensearch_domain.example.arn
    index_name      = "firehose-test-index"
    type_name       = "_doc" # Not required in OpenSearch newer versions, but supported for backward compatibility
    index_rotation  = "OneHour"
    retry_duration  = 300 # seconds

    s3_backup_mode = "FailedDocumentsOnly" # Backup failed docs only

    # VPC configuration for OpenSearch destination
    vpc_config {
      subnet_ids         = [aws_subnet.example.id]
      security_group_ids = [aws_security_group.opensearch_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    # Optional: CloudWatch logging for debugging
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/firehose/opensearch-stream"
      log_stream_name = "delivery-stream"
    }
  }

  # Ensure OpenSearch domain and IAM role are ready before creating the stream
  depends_on = [
    aws_opensearch_domain.example,
    aws_iam_role_policy.firehose_policy
  ]
}

