# Create an Amazon Kinesis Data Firehose delivery stream with extended S3 destination
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "extended-s3-delivery-stream"
  destination = "extended_s3"

  # Extended S3 configuration
  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.bucket.arn

    # Optional: specify prefix and error output prefix
    prefix                  = "data/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_output_prefix     = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/"

    # Buffer settings
    buffer_size             = 128
    buffer_interval         = 900
    compression_format      = "GZIP"
    data_format_conversion_configuration {
      enabled = false
    }

    # Processing configuration (optional)
    processing_configuration {
      enabled = true

      processors {
        type = "RecordDeAggregation"
        parameters {
