# Create S3 bucket for Firehose delivery
resource "aws_s3_bucket" "bucket" {
  bucket = "my-firehose-delivery-bucket"
  region = "us-east-1"

  # Enable versioning
  versioning {
    enabled = true
  }

  # Server-side encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Create CloudWatch Log Group and Stream for Firehose
resource "aws_cloudwatch_log_group" "firehose" {
  name = "/aws/firehose/extended-s3-stream"
}

resource "aws_cloudwatch_log_stream" "firehose" {
  name           = "firehose-stream"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# IAM role for Firehose to access S3, CloudWatch Logs, and optionally Lambda
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Firehose role
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents",
          "logs:PutLogEventsBatch"
        ]
        Resource = aws_cloudwatch_log_stream.firehose.arn
      }
    ]
  })
}

