# Create a simple Amazon Kinesis Data Analytics application
# Step 1: Define the Kinesis Data Analytics application
# We'll create a basic application with basic configuration including name, runtime, and starting the app

resource "aws_kinesis_analytics_application" "example" {
  name = "example-kinesis-analytics-app"

  # Specify the runtime environment (SQL-1_0 is commonly used for simple streaming apps)
  runtime_environment = "SQL-1_0"

  # Define the service execution role that the Kinesis Analytics app will assume
  # This role needs appropriate permissions to interact with Kinesis streams and other AWS services
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  # Optional: Define a simple input stream configuration
  # For simplicity, we'll define one input with a Kinesis stream
  # Assume a Kinesis stream already exists or will be created separately

  inputs {
    name_prefix = "input-stream"

    # Example: Kinesis stream input
    # Replace "my-kinesis-stream" with actual stream name
    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.kinesis_access_role.arn
    }

    # Define the input schema
    schema {
      record_format_type = "JSON"

      # Define JSON mapping parameters
      mapping_parameters {
        json {
          record_row_path = "$"
        }
      }

      # Define example record columns
      record_column {
        name = "id"
        sql_type = "INTEGER"
        mapping = "$.id"
      }

      record_column {
        name = "message"
        sql_type = "VARCHAR(100)"
        mapping = "$.message"
      }

      record_column {
        name = "timestamp"
        sql_type = "TIMESTAMP"
        mapping = "$.timestamp"
      }
    }

    # Starting position for streaming data
    input_parallelism {
      count = 1
    }

    # Input processing configuration (optional)
    # input_processing_configuration {
    #   input_lambda_processor {
    #     resource_arn = aws_lambda_function.processor.arn
    #     role_arn     = aws_iam_role.lambda_exec_role.arn
    #   }
    # }
  }

  # Optional: Add output configuration (e.g., write to another Kinesis stream)
  # outputs {
  #   name = "output-stream"
  #   schema {
  #     record_format_type = "JSON"
  #   }
  #   kinesis_stream {
  #     resource_arn = aws_kinesis_stream.output_stream.arn
  #     role_arn     = aws_iam_role.kinesis_access_role.arn
  #   }
  # }

  # Optional application code (for SQL-based processing)
  # application_code = "CREATE OR REPLACE STREAM DESTINATION_SQL_STREAM (id INTEGER, message VARCHAR(100)); INSERT INTO DESTINATION_SQL_STREAM SELECT id, message FROM input-stream WHERE id > 100;"

  lifecycle {
    # Prevent accidental deletion of the analytics application
    prevent_destroy = false
  }
}

# Create the IAM role for Kinesis Analytics service execution
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Create an IAM role for accessing Kinesis streams
resource "aws_iam_role" "kinesis_access_role" {
  name = "kinesis-analytics-kinesis-access"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required policies to the service execution role
resource "aws_iam_role_policy_attachment" "analytics_exec_policy" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

# Attach policy for Kinesis stream access
resource "aws_iam_role_policy_attachment" "kinesis_access_policy" {
  role       = aws_iam_role.kinesis_access_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisReadOnlyAccess"
}

# Example: Create a Kinesis stream for input (optional - if you want to create it here)
resource "aws_kinesis_stream" "input_stream" {
  name        = "input-data-stream"
  shard_count = 1

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }

  retention_period = 24

  tags = {
    Environment = "dev"
  }
}

# Example: Create an output stream (optional)
resource "aws_kinesis_stream" "output_stream" {
  name        = "output-data-stream"
  shard_count = 1

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }

  retention_period = 24

  tags = {
    Environment = "dev"
  }
}

# Note: 
# - This creates a basic Kinesis Data Analytics application with input from a Kinesis stream
# - The application uses SQL runtime and processes JSON-formatted data
# - You can extend this by adding application_code for actual stream processing
# - Consider security, logging, and monitoring in production environments

