resource "aws_kinesisanalyticsv2_application" "sql_application" {
  name               = "simple-sql-analytics-app"
  runtime_environment = "SQL-1_0"
  service_execution_role = aws_iam_role.kinesisanalytics_role.arn

  application_configuration {
    application_code_configuration {
      code_content {
        text_content = <<EOF
-- Example SQL code to process streaming data
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
  "event_time" TIMESTAMP,
  "user_id" VARCHAR(8),
  "action" VARCHAR(16)
);

CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
  INSERT INTO "DESTINATION_SQL在玩家中_STREAM"
  SELECT STREAM "event_time", "user_id", "action"
  FROM "SOURCE_SQL_STREAM_001"
  WHERE "action" = 'CLICK';
EOF
      }

      code_content_type = "PLAINTEXT"
    }

    // Specify input stream configuration if needed
    streaming_source_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        input_schema {
          record_format_type = "JSON"

          mapping_parameters {
            json_mapping_parameters {
              record_row_path = "$"
            }
          }

          record_column {
            name     = "event_time"
            mapping  = "$.event_time"
            sql_type = "TIMESTAMP"
          }
          record_column {
            name     = "user_id"
            mapping  = "$.user_id"
            sql_type = "VARCHAR(8)"
          }
          record_column {
            name     = "action"
            mapping  = "$.action"
            sql_type = "VARCHAR(16)"
          }
        }

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
          role_arn     = aws_iam_role.stream_access_role.arn
        }
      }
    }

    // Optional: Define output stream configuration
    application_output {
      name                = "DESTINATION_SQL_STREAM"
      destination_schema {
        record_format_type = "JSON"
      }
      kinesis_streams_output {
        resource_arn = aws_kinesis_stream.output_stream.arn
        role_arn     = aws_iam_role.stream_access_role.arn
      }
    }
  }
}

