  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

// IAM role for accessing Kinesis streams
resource "aws_iam_role" "stream_access_role" {
  name = "kinesisanalytics_stream_access_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

// Allow Kinesis Analytics to access required services
resource "aws_iam_role_policy_attachment" "analytics_policy" {
  role       = aws_iam_role.kinesisanalytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

resource "aws_iam_role_policy_attachment" "stream_policy" {
  role       = aws_iam_role.stream_access_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisFullAccess"
}

// Input Kinesis stream
resource "aws_kinesis_stream" "input_stream" {
  name             = "input-stream"
  shard_count      = 1
  retention_period = 24
}

// Output Kinesis stream
resource "aws_kinesis_stream" "output_stream" {
  name             = "output-stream"
  shard_count      = 1
  retention_period = 24
}
