# Setting up Route 53 Active-Active failover requires:
# 1. A hosted zone reference (assumed to exist and referred to as "main")
# 2. Two health checks for primary and secondary endpoints using FQDNs
# 3. DNS records with failover routing policy (using multivalue or failover routing)
# Since Active-Active typically implies both are active unless one fails, we use multivalue answer routing with health checks
# However, if true failover is intended (despite "Active-Active" in name), we'd use failover routing. Clarification: Active-Active usually means both respond.
# But AWS Route 53 "failover" records are typically Active-Passive. For true Active-Active, AWS uses weighted or multivalue routing.
# Given the request says "Active-Active failover", we interpret this as multivalue answer routing with health checks to remove unhealthy endpoints.

# We assume two FQDNs for endpoints: primary_endpoint and secondary_endpoint
# We create two health checks for them
# Then create a multivalue answer record that returns both, with health checks tied to each

# Inputs expected (would normally come from variables):
# - hosted_zone_id or domain name for "main"
# - primary_fqdn and secondary_fqdn

# We'll use domain name to find hosted zone (via data source)

resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = var.primary_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  fully_qualified_domain_name = var.primary_fqdn
  request_interval  = 30
  failure_threshold = 3
}

resource "aws_route53_health_check" "secondary_health_check" {
  fqdn              = var.secondary_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  fully_qualified_domain_name = var.secondary_fqdn
  request_interval  = 30
  failure_threshold = 3
}

data "aws_route53_zone" "main" {
  name = var.main_domain_name
}

resource "aws_route53_record" "active_active_record" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "api.${var.main_domain_name}" # example: api.example.com
  type    = "A"
  ttl     = 60

  # Multivalue answer routing allows returning multiple values, but only healthy ones
  routing_policy {
    multivalue_answer_routing {
      # AWS treats this record as multivalue when this block is present
    }
  }

  # Entry for primary
  records = [
    var.primary_ip,  # A records typically resolve to IPs, so we need IPs. Alternatively, use alias or CNAME with different type
    var.secondary_ip
  ]

  # Instead, if we want to respond with the IPs of the FQDNs, we could do A records
  # But Route 53 multivalue needs health checks on the record answers
  # So we associate health checks with each record

  # However, Route 53 multivalue answer routing supports multiple records with health checks per record
  # We can create two resource records, each with a health check
}

# But note: Route 53 multivalue records return multiple values only if they have health checks AND are configured per record.
# Actually, multivalue answer routing requires each record (value) to reference a unique health check.

resource "aws_route53_record" "primary_answer" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "api.${var.main_domain_name}"
  type    = "A"
  ttl     = 60
  records = [var.primary_ip]
  health_check_id = aws_route53_health_check.primary_health_check.id

  routing_policy {
    multivalue_answer_routing {
      # This enables multivalue behavior per answer
    }
  }
}

resource "aws_route53_record" "secondary_answer" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "api.${var.main_domain_name}"
  type    = "A"
  ttl     = 60
  records = [var.secondary_ip]
  health_check_id = aws_route53_health_check.secondary_health_check.id

  routing_policy {
    multivalue_answer_routing {
      # This enables multivalue behavior per answer
    }
  }
}

# However, AWS requires that all records with the same name and type under multivalue must have health checks.
# The above approach creates two records, but it's not standard. Instead, Route 53 uses a single record with multiple values.

# Correct approach: single record resource with multiple answers and multiple health checks, one per answer.

# Actually, Terraform does not allow different health_check_id per value in a single record. So we use one health check per record?

# Clarification: AWS Route 53 multivalue answer routing supports two record values, each pointing to its own health check.
# But in Terraform, the `aws_route53_record` resource allows only one `health_check_id` for the whole record.

# That's a limitation. So to achieve multivalue with per-answer health checks, we must use different routing.

# Alternative: failover routing with multivalue not possible. So real multivalue with independent health checks per endpoint is not directly supported in one record.

# Actually, AWS now supports this: you can have one record with multiple values, each value can have a health check if you use multivalue_answer_routing.

# But in Terraform, you can only specify one health_check_id for the entire record.

# This is a known limitation.

# Workaround: Use weighted routing or failover with active-active via latency or geolocation not applicable.

# After research: AWS supports multivalue answer routing where each answer (resource record) has a health check, but Terraform `aws_route53_record` does not allow per-record health checks in a multi-value record.

# So we cannot achieve per-answer health checks in a single record via current Terraform.

# Instead, the intended solution may be to use failover routing with two records: PRIMARY and SECONDARY — but that's active-passive.

# Given the confusion, perhaps the user meant active-active via weighted routing with health checks.

# But weighted routing doesn't remove unhealthy answers unless using health checks — it does, but health check applies to the whole set.

# So both records will fail if either health check fails? No — each record can have its own health check if using multivalue answer records.

# After AWS docs: For multivalue answer routing, you create one record per value, and each has a health check, and AWS returns up to 8 healthy values.

# So multiple `aws_route53_record` resources with the same name, type, and multivalue_answer_routing block.

# This is supported in AWS, and Terraform's Route 53 provider supports this via multiple records.

# Therefore, final design:

# - One health check for primary FQDN
# - One for secondary FQDN
# - Two `aws_route53_record` resources with same name and type, each with one IP, each with multivalue_answer_routing, each with its own health check.

# So we do:

variable "primary_fqdn" {
  description = "FQDN for primary endpoint"
  type        = string
}

variable "secondary_fqdn" {
  description = "FQDN for secondary endpoint"
  type        = string
}

variable "primary_ip" {
  description = "IP address for primary endpoint"
  type        = string
}

variable "secondary_ip" {
  description = "IP address for secondary endpoint"
  type        = string
}

variable "main_domain_name" {
  description = "Domain name of the main hosted zone"
  type        = string
}

# Health checks
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = var.primary_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  fully_qualified_domain_name = var.primary_fqdn
  request_interval  = 30
  failure_threshold = 3
  measure_latency   = true
  tags = {
    Name = "primary_health_check"
  }
}

resource "aws_route53_health_check" "secondary_health_check" {
  fqdn              = var.secondary_fqdn
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  fully_qualified_domain_name = var.secondary_fqdn
  request_interval  = 30
  failure_threshold = 3
  measure_latency   = true
  tags = {
    Name = "secondary_health_check"
  }
}

# Hosted zone
data "aws_route53_zone" "main" {
  name = var.main_domain_name
}

# Multivalue answer records
resource "aws_route53_record" "primary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "api.${var.main_domain_name}"
  type    = "A"
  ttl     = 60
  records = [var.primary_ip]
  health_check_id = aws_route53_health_check.primary_health_check.id

  routing_policy {
    multivalue_answer_routing {
      // This enables multivalue answer routing for this record
    }
  }
}

resource "aws_route53_record" "secondary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "api.${var.main_domain_name}"
  type    = "A"
  ttl     = 60
  records = [var.secondary_ip]
  health_check_id = aws_route53_health_check.secondary_health_check.id

  routing_policy {
    multivalue_answer_routing {
      // This enables multivalue answer routing for this record
    }
  }
}

