resource "aws_route53_traffic_policy" "lowest_latency_policy" {
  name     = "lowest-latency-policy"
  comment  = "Routes traffic to the region with lowest latency: us-east-1 and eu-central-1"

  document = jsonencode({
    "AWSPolicyFormatVersion": "2018-05-22",
    "Rules": {
      "primary-routing-rule": {
        "RuleType": "Latency",
        "Locations": [
          {
