        "Type": "elastic-load-balancer",
        "Region": "eu-central-1",
        "Value": "my-elb-654321.eu-central-1.elb.amazonaws.com"
      }
    },
    "StartEndpoint": "",
    "StartRule": "primary-routing-rule"
  })
}

# Optional: Attach traffic policy to a hosted zone via traffic policy instance
resource "aws_route53_traffic_policy_instance" "instance" {
