variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the EKS cluster"
  type        = list(string)
}

variable "vpc_id" {
  description = "VPC ID for the EKS cluster"
  type        = string
}

# Create IAM role for EKS cluster
resource "aws_iam_role" "eks_role" {
  name = "${var.cluster_name}-eks-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
        Condition = {}
      },
    ]
  })
}

# Attach Amazon EKS managed policies to the IAM role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_role.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks_role.name
}

# Create EKS cluster with dependency on IAM role and policies
resource "aws_eks_cluster" "eks_cluster" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_role.arn

  vpc_config {
    subnet_ids = var.subnet_ids
    vpc_id     = var.vpc_id
  }

  # Ensure IAM role and policies are created/updated before cluster
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # Update kubectl config after cluster creation
  provisioner "local-exec" {
    command = <<EOT
      aws eks update-kubeconfig \n        --name ${var.cluster_name} \n        --region ${var.aws_region} \n        --kubeconfig ~/.kube/config
    EOT
    interpreter = ["/bin/bash", "-c"]
  }

  # Clean up kubectl config on destroy
  provisioner "local-exec" {
    when    = destroy
    command = <<EOT
      # Remove EKS context from kubeconfig
      if kubectl config get-contexts ${var.cluster_name} >/dev/null 2>&1; then
        kubectl config delete-context ${var.cluster_name}
        kubectl config delete-cluster ${var.cluster_name}
      fi
    EOT
    interpreter = ["/bin/bash", "-c"]
  }
}

# Optional - define provider if not already set
provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region for the EKS cluster"
  type        = string
  default     = "us-west-2"
}

