response:
```hcl
# Step 1: Define the required IAM role for EKS cluster with assume-role policy allowing EKS service to assume the role
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks"

  # Assume role policy allows EKS service to assume this role
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# Step 2: Attach the required AWS managed policies to the IAM role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo_eks.name
}

resource "aws_iam_role_policy_attachment" "eks_vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.demo_eks.name
}

# Step 3: Define the EKS cluster resource with name 'demo_eks' and proper VPC configuration
# We assume that VPC and subnets are pre-existing or passed via variables; here we demonstrate using placeholder references.
# In practice, you might reference aws_vpc and aws_subnet resources or pass them as variables.
resource "aws_eks_cluster" "demo_eks" {
  name     = "demo_eks"
  role_arn = aws_iam_role.demo_eks.arn

  vpc_config {
    # Example: specify subnets and security groups; in real use, reference actual subnet IDs
    # Replace with actual data sources or variable references as needed
    subnet_ids = [
      # Example: "subnet-12345678", "subnet-87654321"
    ]
    # Optional: enable endpoint private access, specify security groups, etc.
  }

  # Ensure the cluster does not recreate due to role issues by depending on policy attachments
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_vpc_resource_controller
  ]

  # Kubernetes version (required field)
  version = "1.29" # Specify desired Kubernetes version
}

# Output the EKS cluster endpoint and ARN for reference
output "eks_cluster_endpoint" {
  value = aws_eks_cluster.demo_eks.endpoint
}

output "eks_cluster_arn" {
  value = aws_eks_cluster.demo_eks.arn
}

output "iam_role_arn" {
  value = aws_iam_role.demo_eks.arn
}
```

