# Create an S3 bucket with the specified configuration
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"

  # Prevent accidental deletion by enabling lifecycle rules and setting the bucket to not allow deletion
  # The bucket will be protected from accidental deletion by applying a lifecycle rule and using ignore_administrative_actions
  # However, to prevent deletion, we use prevent_destroy lifecycle policy
  lifecycle {
    prevent_destroy = true
  }

  # Set the ACL to private
  acl    = "private"

  # Enable default server-side encryption with AES256
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Apply public access block to block all public access
  # This is done via aws_s3_bucket_public_access_block resource
}

# Attach public access block to the bucket to block all public access
resource "aws_s3_bucket_public_access_block" "test_bucket" {
  bucket = aws_s3_bucket.test_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Ensure region is set via provider; assuming AWS provider is configured separately

