# Create an S3 bucket with the specified configuration
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"

  # Prevent accidental deletion by enabling lifecycle rules and setting the bucket to not allow deletion
  # The bucket will be protected from accidental deletion by applying a lifecycle rule and using ignore_administrative_actions
  # However, to prevent deletion, we use prevent_destroy lifecycle policy
  lifecycle {
    prevent_destroy = true
  }

  # Set the ACL to private
  acl    = "private"

