resource "aws_s3_bucket" "wellcomecollection_platform_infra" {
  bucket = "wellcomecollection-platform-infra"
  acl    = "private"

  # Prevent accidental deletion of the bucket
  force_destroy = false
}

# Enable bucket versioning
resource "aws_s3_bucket_versioning" "wellcomecollection_platform_infra_versioning" {
  bucket = aws_s3_bucket.wellcomecollection_platform_infra.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Configure lifecycle rules for the bucket
resource "aws_s3_bucket_lifecycle_configuration" "wellcomecollection_platform_infra_lifecycle" {
  bucket = aws_s3_bucket.wellcomecollection_platform_infra.id

  # Rule to expire objects under 'tmp/' prefix after 30 days
  rule {
    id     = "expire-tmp-objects"
    status = "Enabled"
    prefix = "tmp/"

    expiration {
      days = 30
    }

    # Transition noncurrent versions to STANDARD_IA after 30 days
    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    # Expire noncurrent versions after 90 days
    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

# Optionally enable server-side encryption by default
