resource "aws_s3_bucket" "example_bucket" {
  bucket = "example-bucket"
  object_lock_enabled_for_bucket = true

  object_lock_configuration {
    object_lock_enabled = "Enabled"

    rule {
      default_retention {
        mode = "COMPLIANCE"
        days = 30
      }
    }
  }

  # Enable versioning as it is required for Object Lock
  versioning {
    enabled = true
  }
}

