        sse_algorithm = "AES256"
      }
    }
  }
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data_ownership" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

# S3 Bucket for website data
resource "aws_s3_bucket" "web_data" {
  bucket = "${var.project_name}-web-${var.bucket_suffix}"

  acl    = "private"
}

resource "aws_s3_bucket_public_access_block" "web_data_access_block" {
  bucket = aws_s3_bucket.web_data.id

  ignore_public_acls       = true
  block_public_acls        = true
  block_public_policy      = true
  restrict_public_buckets  = true
}

# Upload file to web data bucket
resource "aws_s3_object" "uploaded_file" {
  bucket = aws_s3_bucket.web_data.id
  key    = "order_data2.csv"
  source = "order_data2.csv"
  etag   = filemd5("order_data2.csv")
}

# Bucket policy to allow s3:PutObject for all principals
resource "aws_s3_bucket_policy" "web_data_put_policy" {
  bucket = aws_s3_bucket.web_data.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = "*"
        Action = "s3:PutObject"
        Resource = "${aws_s3_bucket.web_data.arn}/*"
      }
    ]
  })
}
