  special = false
  upper   = false
}

locals {
  bucket_name = "my-unique-bucket-name-${random_string.bucket_suffix.result}"
}

# Step 3: Create the S3 bucket with the dynamically generated unique name
resource "aws_s3_bucket" "example" {
  bucket = local.bucket_name

  # Apply a canned ACL (e.g., "private" as default)
  acl = "private"

  # Enable versioning for better data protection
  versioning {
    enabled = true
  }

  # Enable server-side encryption by default
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Add tags for better management
  tags = {
    Name        = "MyUniqueS3Bucket"
    Environment = "dev"
    CreatedBy   = "Terraform"
  }
}

# Step 4: Define a bucket policy that allows s3:GetObject for any principal,
# but only if the request includes a specific AWS:Referer header (e.g., from a known domain)
resource "aws_s3_bucket_policy" "example" {
  bucket = aws_s3_bucket.example.id

  # Policy document granting GetObject with Referer condition
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = "*"
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.example.arn}/*"
        Condition = {
          StringLike = {
            "aws:Referer" = [
              "https://www.example.com/*", # Replace with your allowed referer domain(s)
            ]
          }
        }
      }
    ]
  })
}

