# Step-by-step approach:
# 1. Create a KMS key with a specified description and deletion window (pending deletion period in days)
# 2. Create an S3 bucket with a specified name
# 3. Enable server-side encryption on the S3 bucket using the KMS key created in step 1
# 4. Specify the AWS KMS encryption algorithm (aws:kms) in the bucket's server-side encryption configuration

resource "aws_kms_key" "s3_kms_key" {
  description             = var.kms_description
  deletion_window_in_days = var.deletion_window_in_days
  enable_key_rotation     = true # Best practice to enable key rotation
}

