# Provider configuration for AWS
provider "aws" {
  region = "us-west-2" # Default region; can be overridden as needed
}

# Generate unique bucket names using random pet for uniqueness
resource "random_pet" "log_bucket_name" {
  prefix = "logs-bucket"
}

resource "random_pet" "data_bucket_name" {
  prefix = "data-bucket"
}

# Create the private S3 bucket (data bucket) that will serve as the source for logging
resource "aws_s3_bucket_v2" "private_data_bucket" {
  bucket = random_pet.data_bucket_name.id

  # Explicit private ACL
  acl    = "private"

  # Enable versioning for data protection
  versioning {
    enabled = true
  }

  # Block public access completely
  block_public_acls   = true
  block_public_policy = true
  ignore_public_acls  = true
  restrict_public_buckets = true
}

# Create the S3 bucket to receive server access logs
resource "aws_s3_bucket_v2" "log_delivery_bucket" {
  bucket = random_pet.log_bucket_name.id

  # ACL that permits log delivery (log-delivery-write)
  acl    = "log-delivery-write"

  # Block public access but allow log delivery
  block_public_acls   = true
  block_public_policy = true
  ignore_public_acls  = true
  restrict_public_buckets = true

  # Enable versioning on log bucket
  version muc_enabled = true
}

# Set bucket policy on the log bucket to allow AWS to write logs (required for log-delivery-write)
resource "aws_s3_bucket_policy" "log_bucket_policy" {
  bucket = aws_s3_bucket_v2.log_delivery_bucket.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid    = "AWSLogDeliveryWrite",
        Effect = "Allow",
        Principal = {
          Service = "logging.s3.amazonaws.com"
        },
        Action   = "s3:PutObject",
        Resource = "arn:aws:s3:::${aws_s3_bucket_v2.log_delivery_bucket.id}/logs/*",
        Condition = {
          StringEquals = {
            "s3:x-amz-acl": "bucket-owner-full-control"
          }
        }
      }
    ]
  })

  # Depends on the log bucket being created
  depends_on = [aws_s3_bucket_v2.log_delivery_bucket]
}

# Enable server access logging on the private data bucket, targeting the log bucket
resource "aws_s3_bucket_logging" "data_bucket_logging" {
  bucket = aws_s3_bucket_v2.private_data_bucket.id

  target_bucket = aws_s3_bucket_v2.log_delivery_bucket.id
  target_prefix = "logs/" # Specified target prefix for logs
}

# Optional: Add lifecycle rule to log bucket to transition logs after 30 days
resource "aws_s3_bucket_lifecycle_configuration" "log_lifecycle" {
  bucket = aws_s3_bucket_v2.log_delivery_bucket.id

  rule {
    id = "expire-old-logs"

    expiration {
      days = 365
    }

    filter {}

    status = "Enabled"
  }
}

# Outputs to display bucket names
output "private_data_bucket_name" {
  value = aws_s3_bucket_v2.private_data_bucket.bucket
  description = "Private S3 bucket for data"
}

output "log_delivery_bucket_name" {
  value = aws_s3_bucket_v2.log_delivery_bucket.bucket
  description = "S3 bucket for storing access logs"
}

