# This Terraform configuration creates an S3 bucket with a specified name
# and applies ownership controls to ensure the bucket owner has full control
# over objects, setting object ownership to BucketOwnerPreferred.

# Define required providers
provider "aws" {
  region = "us-east-1" # Default region; can be changed as needed
}

# Resource: AWS S3 Bucket
# Creates an S3 bucket with a given bucket name.
# The bucket will be used to store objects and have ownership controls applied.
resource "aws_s3_bucket" "example_bucket" {
  bucket = "my-example-unique-bucket-name-12345" # Specify a unique bucket name

  # Optionally add other configurations like tags, lifecycle, etc.
  tags = {
    Name        = "ExampleBucket"
    Environment = "Dev"
  }
}

# Resource: AWS S3 Bucket Ownership Controls
# Applies ownership controls to the created S3 bucket.
# Sets object ownership to BucketOwnerPreferred so that the bucket owner has full control
# over objects, even if they were uploaded by another account.
resource "aws_s3_bucket_ownership_controls" "example_ownership" {
  bucket = aws_s3_bucket.example_bucket.id # Reference the bucket by its ID

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Output the bucket name for reference
output "bucket_name" {
  value = aws_s3_bucket.example_bucket.bucket
}

# Output the bucket ARN
output "bucket_arn" {
  value = aws_s3_bucket.example_bucket.arn
}

