# Create a bespoke VPC with 10.0.0.0/16 CIDR block
resource "aws_vpc" "bespoke_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "bespoke-vpc"
  }
}

# Create subnet in us-east-1a
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.bespoke_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "subnet-us-east-1a"
  }
}

# Create subnet in us-east-1b
resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.bespoke_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "subnet-us-east-1b"
  }
}

# Create an internet gateway to enable internet access
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.bespoke_vpc.id

  tags = {
    Name = "bespoke-igw"
  }
}

# Create route table for public access
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.bespoke_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate both subnets with the public route table
resource "aws_route_table_association" "subnet_a_assoc" {
  subnet_id      = aws_subnet.subnet_a.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "subnet_b_assoc" {
  subnet_id      = aws_subnet.subnet_b.id
  route_table_id = aws_route_table.public_rt.id
}

# Get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Create a key pair for SSH access (assuming you have a public key)
# resource "aws_key_pair" "deployer" {
#   key_name   = "deployer-key"
#   public_key = file("~/.ssh/id_rsa.pub")
# }

# Security group to allow SSH and ICMP (optional but useful)
resource "aws_security_group" "allow_ssh_icmp" {
  name        = "allow_ssh_icmp"
  description = "Allow SSH and ICMP"
  vpc_id      = aws_vpc.bespoke_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow-ssh-icmp"
  }
}

# Launch EC2 instance in us-east-1a
resource "aws_instance" "instance_a" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.allow_ssh_icmp.name]

  root_block_device {
    volume_size = 50
    volume_type = "gp2"
  }

  tags = {
    Name = "ec2-instance-us-east-1a"
  }
}

