```hcl
# Main Terraform configuration for VPC with public/private subnets and EC2 Fleet using Launch Templates

# Required providers block
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider block with AWS region
provider "aws" {
  region = "us-west-2"  # Can be changed as needed
}

##########################################################
# VPC Setup
##########################################################

resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

##########################################################
# Internet Gateway for public subnets
##########################################################

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "main-igw"
  }
}

##########################################################
# Public Subnet
##########################################################

resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "${var.aws_region}a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

##########################################################
# Private Subnet
##########################################################

resource "aws_subnet" "private_subnet" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "${var.aws_region}a"
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet"
  }
}

##########################################################
# Route Table for Public Subnet
##########################################################

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

##########################################################
# Fetch latest Amazon Linux 2 AMI
##########################################################

data "aws_ami" "amazon_linux2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*"]
  }
}

##########################################################
# Key pair for EC2 instances (assuming key already exists)
# You may import or create via aws_key_pair resource if needed
##########################################################

# Optional: Uncomment below if you want to manage key via Terraform (not recommended in production)
# resource "tls_private_key" "ec2_key" {
#   algorithm = "RSA"
#   rsa_bits  = 2048
# }

# resource "aws_key_pair" "deployer" {
#   key_name   = "ec2-deployer-key"
#   public_key = tls_private_key.ec2_key.public_key_openssh
# }

# Using existing key (recommended to reference existing key)
variable "key_name" {
  description = "Name of the existing EC2 key pair"
  type        = string
  default     = "my-key-pair"
}

##########################################################
# Security Group for EC2 instances
##########################################################

resource "aws_security_group" "ec2_sg" {
  name        = "ec2-fleet-sg"
  description = "Security group for EC2 fleet instances"
  vpc_id      = aws_vpc.main_vpc.id

  # Allow SSH from anywhere - restrict in production
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-fleet-sg"
  }
}

##########################################################
# Launch Template for uniform EC2 configuration
##########################################################

resource "aws_launch_template" "ec2_fleet_template" {
  name_prefix   = "ec2-fleet-template-"
  description   = "Launch template for On-Demand and Spot EC2 fleet"
  image_id      = data.aws_ami.amazon_linux2.id
  instance_type = "t3.micro"
  key_name      = var.key_name
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  iam_instance_profile {
    name = aws_iam_instance_profile.ec2_instance_profile.name
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              echo "Hello from EC2 instance using Launch Template"
              EOF
  )

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "ec2-fleet-instance"
      Type = "fleet-instance"
    }
  }
}

##########################################################
# IAM Role and Instance Profile for EC2
##########################################################

resource "aws_iam_role" "ec2_role" {
  name = "ec2-fleet-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "ec2_instance_profile" {
  name = "ec2-fleet-instance-profile"
  role = aws_iam_role.ec2_role.name
}

##########################################################
# EC2 Fleet: 5 On-Demand + 4 Spot Instances
##########################################################

resource "aws_ec2_fleet" "example" {
  launch_template_config {
    launch_template_specification {
      name    = aws_launch_template.ec2_fleet_template.name
      version = aws_launch_template.ec2_fleet_template.latest_version
    }
  }

  target_capacity_specification {
    total_target_capacity = 9  # 5 On-Demand + 4 Spot
    on_demand_target_capacity = 5
    spot_target_capacity        = 4
    default_target_capacity_type = "spot"  # fallback if not specified per pool
  }

  fleet_type = "maintain"  # maintains target capacity

  # Optional: Define allocation strategy
  # spot_options {
  #   allocation_strategy = "lowest-price"
  #   instance_interruption_behavior = "terminate"
  # }

  tags = {
    Name = "ec2-fleet"
  }
}

##########################################################
# Output variables
##########################################################

output "vpc_id" {
  description = "ID of the created VPC"
  value       = aws_vpc.main_vpc.id
}

output "public_subnet_id" {
  description = "ID of the public subnet"
  value       = aws_subnet.public_subnet.id
}

output "private_subnet_id" {
  description = "ID of the private subnet"
  value       = aws_subnet.private_subnet.id
}

output "ec2_fleet_id" {
  description = "ID of the EC2 Fleet"
  value       = aws_ec2_fleet.example.id
}

# AWS Region variable
variable "aws_region" {
  description = "AWS region to deploy resources"
  type        = string
  default     = "us-west-2"
}
```

