extracted_code:
# Create a VPC with public and private subnets, and launch 3 EC2 instances in a cluster placement group

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Public subnet in availability zone a
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# Private subnet in availability zone b
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway to enable public subnet internet access
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Public route table
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-rt"
  }
}

# Associate public subnet with public route table
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_route_table.id
}

# Placement group with cluster strategy
resource "aws_placement_group" "cluster_pg" {
  name     = "cluster-placement-group"
  strategy = "cluster"
}

# EC2 Key Pair (assuming you have a public key)
# Note: You may want to use an existing key or generate it via other means
# For this example, we assume a key named "my-key" exists

# AMI data source (using latest Amazon Linux 2 in us-west-2)
data "aws_ami" "amazon_linux2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }
}

# User data script to run on instance launch
variable "user_data" {
  default = <<-EOF
            #!/bin/bash
            echo "Hello World" > /tmp/hello.txt
            EOF
}

# Launch 3 EC2 instances in the placement group across subnets
resource "aws_instance" "instance" {
  count                        = 3
  instance_type                = "t3.micro"
  ami                            = data.aws_ami.amazon_linux2.id
  placement_group                = aws_placement_group.cluster_pg.name
  subnet_id                      = count.index % 2 == 0 ? aws_subnet.public_subnet.id : aws_subnet.private_subnet.id
  vpc_security_group_ids         = [aws_security_group.instance_sg.id]
  associate_public_ip_address    = count.index % 2 == 0 ? true : false
  user_data                      = var.user_data
  source_dest_check              = false
  disable_api_termination        = false
  instance_initiated_shutdown_behavior = "stop"

  tags = {
    Name = "instance-${count.index}"
  }
}

# Security group to allow SSH and ICMP
resource "aws_security_group" "instance_sg" {
  name        = "instance-security-group"
  description = "Allow SSH and ICMP"
  vpc_id      = aws_vpc.main.id

  # SSH from anywhere (consider restricting in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # ICMP for ping
  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Outbound internet access
  egress {
    from_port        = 0
    to_port          = 0
    protocol         = "-1"
    cidr_blocks      = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  tags = {
    Name = "instance-sg"
