resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name        = "redshift-subnet-grp"
  description = "Subnet group for Redshift cluster"
  subnet_ids  = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
}

# Create the Redshift cluster with two nodes
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "terraform-redshift-cluster"
  database_name             = "mydb"
  master_username           = "admin"
  master_password           = "Password1234!" # Should be handled via secrets in production
  node_type                 = "dc2.large" # Common node type; adjust as needed
  cluster_type              = "multi-node"
  number_of_nodes           = 2
  publicly_accessible       = true
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  skip_final_snapshot       = true # For testing; set to false and define final_snapshot_identifier in production

  # Prevent accidentally deleting the cluster
  lifecycle {
    prevent_destroy = false # Set to true in production
  }
}

# Security group to allow Redshift access
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  # Allow Redshift default port (5439) from any IP (restrict in production)
  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# Step 3: Set up endpoint authorization for AWS account ID
resource "aws_redshift_endpoint_authorization" "auth" {
  account         = "012345678910"
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
  # Optionally allow maintenance: var.allow_maintenance or false
  force_destroy   = false # Set to true to delete authorization even if cluster has active connections
}
```

