  cluster_subnet_group_name   = aws_redshift_subnet_group.example_subnet_group.name

  skip_final_snapshot = true
}

extracted_code:
# We need to provision a two-node Amazon Redshift cluster in us-east-1
# and set up cross-region replication to us-east-2.

# Step 1: Define providers for both source (us-east-1) and target (us-east-2) regions
# Step 2: Create a Redshift cluster in us-east-1 with node type and count
# Step 3: Create a snapshot copy grant (required for cross-region snapshot copy)
# Step 4: Enable snapshot copying (replication) from us-east-1 to us-east-2

provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"
}

provider "aws" {
  alias  = "us_east_2"
  region = "us-east-2"
}

# Generate a random password for the master user
resource "random_string" "master_password" {
  length  = 16
  special = true
  upper   = true
  lower   = true
  numeric = true
}

# Create a VPC and subnet group for Redshift in us-east-1
resource "aws_vpc" "redshift_vpc" {
  provider = aws.us_east_1

  cidr_block = "10.1.0.0/16"

  tags = {
    Name = "redshift-vpc-us-east-1"
  }
}

resource "aws_subnet" "redshift_subnet_a" {
  provider        = aws.us_east_1
  vpc_id          = aws_vpc.redshift_vpc.id
  cidr_block      = "10.1.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-a"
  }
}

resource "aws_subnet" "redshift_subnet_b" {
  provider        = aws.us_east_1
  vpc_id          = aws_vpc.redshift_vpc.id
  cidr_block      = "10.1.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-b"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  provider = aws.us_east_1

  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# IAM role for snapshot copy to us-east-2
resource "aws_iam_role" "snapshot_copy_role" {
  provider = aws.us_east_1

  name = "redshift-snapshot-copy-role-us-east-1"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "snapshot_copy_policy" {
  provider = aws.us_east_1

  name = "redshift-snapshot-copy-policy"
  role = aws_iam_role.snapshot_copy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::aws-redshift-snapshots-${data.aws_region.current_us_east_2.name}/*",
          "arn:aws:s3:::aws-redshift-snapshots-${data.aws_region.current_us_east_2.name}"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

# Get region names as data
data "aws_region" "current_us_east_1" {
  provider = aws.us_east_1
}

data "aws_region" "current_us_east_2" {
  provider = aws.us_east_2
}

# Create the Redshift cluster in us-east-1
resource "aws_redshift_cluster" "primary" {
  provider = aws.us_east_1

  cluster_identifier        = "primary-redshift-cluster"
  database_name             = "analytics"
  master_username           = "adminuser"
  master_password           = random_string.master_password.result
  node_type                 = "dc2.large"
  cluster_type              = "multi-node"
  number_of_nodes           = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  publicly_accessible       = false
  automated_snapshot_retention_period = 7

  # Enable encryption
  encrypted = true

  # Enable version upgrade
  allow_version_upgrade = true

  # Apply maintenance window
  preferred_maintenance_window = "sun:03:00-sun:04:00"

  # Apply port
  port = 5439

  # Enable snapshot copy to us-east-2
  enable_snapshot_copy = true
  snapshot_copy {
    destination_region = "us-east-2"
    retention_period   = 7
    grant_name         = aws_redshift_snapshot_copy_grant.snapshot_copy_grant.snapshot_copy_grant_name
  }

  # Depends on subnet group and IAM role
  depends_on = [
    aws_redshift_subnet_group.redshift_subnet_group,
    aws_iam_role.snapshot_copy_role
  ]
}

# Create snapshot copy grant in us-east-1 to allow copying snapshots to us-east-2
resource "aws_redshift_snapshot_copy_grant" "snapshot_copy_grant" {
  provider = aws.us_east_1

  snapshot_copy_grant_name = "snapshot-copy-grant-to-use2"
  kms_key_id               = aws_kms_key.snapshot_copy_kms.key_id
}

# KMS key for encrypting copied snapshots
resource "aws_kms_key" "snapshot_copy_kms" {
  provider = aws.us_east_1

  description             = "KMS key for Redshift snapshot copy to us-east-2"
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action = "kms:*"
        Resource = "*"
      },
      {
        Sid = "Allow Redshift service to use the KMS key"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid = "Allow access for root user"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action = "kms:*"
        Resource = "*"
      }
    ]
  })
}

# Data sources for account ID
data "aws_caller_identity" "current" {}

# Output the cluster endpoint and other details
output "primary_cluster_endpoint" {
  value = aws_redshift_cluster.primary.endpoint
}

output "primary_cluster_host" {
  value = aws_redshift_cluster.primary.cluster_public_key
}

output "master_password" {
  value     = random_string.master_password.result
  sensitive = true
}

