# Set up an Amazon Redshift cluster with two nodes and configure endpoint access

# Define required providers
provider "aws" {
  region = "us-west-2" # You can change this to your preferred region
}

# Create a subnet group for Redshift cluster
resource "aws_redshift_subnet_group" "example" {
  name       = "example-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with actual subnet IDs in your VPC
  tags = {
    Name = "Example Redshift Subnet Group"
  }
}

# Create a Redshift cluster with two nodes (ra3.xlplus node type as example)
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-redshift-cluster"
  database_name             = "exampledb"
  master_username           = "adminuser"
  master_password           = "SecurePassword123!" # Use AWS Secrets Manager in production
  node_type                 = "ra3.xlplus"
  cluster_type              = "multi-node"
  number_of_nodes           = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  publicly_accessible       = false # Set to true if public access is needed (not recommended for production)
  allow_version_upgrade     = true
  automated_snapshot_retention_period = 7

  vpc_security_group_ids = [
    aws_security_group.redshift_sg.id
  ]

  # Enhanced VPC routing
  enhanced_vpc_routing = true

  tags = {
    Name = "Example Redshift Cluster"
  }
}

# Create a security group to control access to the Redshift cluster
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  # Allow Redshift default port (5439) from specific CIDR or security groups
  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to your internal VPC CIDR or specific IP ranges
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift Security Group"
  }
}

# Optional: Output cluster details
output "redshift_cluster_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "redshift_cluster_host" {
  value = aws_redshift_cluster.example.cluster_public_key
}

