response:
To set up an Amazon SageMaker endpoint, we need to follow these steps:

1. **Model Configuration**: First, define a SageMaker model. This includes the container image (e.g., from Amazon ECR) and the model artifact (e.g., trained model stored in S3).
2. **Endpoint Configuration**: Create an endpoint configuration that specifies the model, instance type, and number of instances for inference.
3. **Endpoint**: Finally, create the endpoint using the endpoint configuration.

We assume:
- You already have a trained model artifact in an S3 bucket.
- You have a Docker image for inference (e.g., a pre-built SageMaker image or a custom one in ECR).
- We’ll use a `ml.m5.large` instance for hosting.

We’ll include:
- `aws_sagemaker_model`
- `aws_sagemaker_endpoint_configuration`
- `aws_sagemaker_endpoint`

```hcl
resource "aws_sagemaker_model" "sagemaker_model" {
  name               = "example-sagemaker-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    image = "012345678901.dkr.ecr.us-west-2.amazonaws.com/my-inference-image:latest"
    model_data_url = "s3://my-model-bucket/path/to/model.tar.gz"
  }
}

resource "aws_sagemaker_endpoint_configuration" "endpoint_config" {
  name = "example-endpoint-config"

  production_variants {
    variant_name           = "variant-1"
    model_name             = aws_sagemaker_model.sagemaker_model.name
    instance_type          = "ml.m5.large"
    initial_instance_count = 1
  }
}

resource "aws_sagemaker_endpoint" "endpoint" {
  name = "example-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.endpoint_config.name

  tags = {
    Name = "example-sagemaker-endpoint"
  }
}

# IAM role required for SageMaker to access resources (model, logs, etc.)
resource "aws_iam_role" "sagemaker_role" {
  name = "role-sagemaker-endpoint"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# Optional: attach S3 read access if using custom model data
resource "aws_iam_role_policy" "s3_access" {
  name = "s3-access-policy"
  role = aws_iam_role.sagemaker_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          "arn:aws:s3:::my-model-bucket",
          "arn:aws:s3:::my-model-bucket/*"
        ]
      }
    ]
  })
}
