provider "aws" {
  region = "us-east-1"
}

# VPC resource
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

# Public subnet
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# Private subnet
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Public route table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate public subnet with public route table
resource "aws_route_table_association" "public_rta" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# Latest Amazon Linux 2 AMI data source
data "aws_ssm_parameter" "amz2_latest" {
  name = "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2"
}

# IAM role for EC2 instances
resource "aws_iam_role" "ec2_role" {
  name = "ec2-fleet-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Instance profile for EC2 fleet
resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-fleet-instance-profile"
  role = aws_iam_role.ec2_role.name
}

# Launch template for EC2 instances
resource "aws_launch_template" "fleet_template" {
  name          = "ec2-fleet-launch-template"
  image_id      = data.aws_ssm_parameter.amz2_latest.value
  instance_type = "t3.micro"
  key_name      = "your-key-pair"  # Replace with your key pair name

  iam_instance_profile {
    name = aws_iam_instance_profile.ec2_profile.name
  }

  network_interfaces {
    associate_public_ip_address = true
    subnet_id                   = aws_subnet.public_subnet.id
    security_groups             = [aws_security_group.allow_ssh.id]
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              echo "Hello from $(hostname)" >> /home/ec2-user/message.txt
              EOF
  )

  tags = {
    Name = "fleet-instance"
  }
}

# Security group to allow SSH access
resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow-ssh"
  }
}

# EC2 Fleet configuration with On-Demand and Spot instances
resource "aws_ec2_fleet" "example" {
  target_capacity_specification {
    target_capacity = 9
    default_target_capacity_type = "mixed"
    on_demand_target_capacity = 5
    spot_target_capacity = 4
  }

  launch_template_config {
    launch_template_specification {
      name    = aws_launch_template.fleet_template.name
      version = "$Latest"
    }

    # Use both public and private subnets
    overrides {
      subnet_id = aws_subnet.public_subnet.id
      weighted_capacity = 1
    }
    overrides {
      subnet_id = aws_subnet.private_subnet.id
      weighted_capacity = 1
    }
  }

  # Spot options
  spot_options {
    allocation_strategy = "lowest-price"
    instance_interruption_behavior = "terminate"
  }

  # On-Demand options
  on_demand_options {
    allocation_strategy = "lowest-price"
  }

  tags = {
    Name = "example-fleet"
  }
}

# Data source to fetch availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

