# Steps to achieve the request:
# 1. Define the AWS provider (required for any AWS resources)
# 2. Create a VPC (required for subnets and EC2 instances)
# 3. Create two private subnets (for high availability, preferably in different AZs)
# 4. Create an EFS file system
# 5. Create a security group for EC2 instances allowing outbound traffic and NFS access to EFS
# 6. Create a security group for EFS to allow inbound NFS traffic from EC2 instances
# 7. Launch two EC2 instances in the private subnets
# 8. Ensure EC2 instances can access EFS (via mounting using User Data)
# 9. Use EFS mount targets in each subnet

provider "aws" {
  region = "us-west-2" # Can be changed as needed
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "private-ec2-efs-vpc"
  }
}

# Create two private subnets in different availability zones
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "private-subnet-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "private-subnet-b"
  }
}

# Create an EFS file system
resource "aws_efs_file_system" "efs" {
  tags = {
    Name = "shared-efs"
  }
}

# Security group for EC2 instances
resource "aws_security_group" "ec2_sg" {
  vpc_id = aws_vpc.main.id

  # Allow outbound internet access (for updates/installations)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-security-group"
  }
}

# Security group for EFS to allow NFS access from EC2 instances
resource "aws_security_group" "efs_sg" {
  vpc_id = aws_vpc.main.id

  # Allow inbound NFS (port 2049) from EC2 security group
  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    security_groups = [aws_security_group.ec2_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-security-group"
  }
}

# Create mount targets for EFS in each private subnet
resource "aws_efs_mount_target" "a" {
  file_system_id = aws_efs_file_system.efs.id
  subnet_id      = aws_subnet.private_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_efs_mount_target" "b" {
  file_system_id = aws_efs_file_system.efs.id
  subnet_id      = aws_subnet.private_b.id
  security_groups = [aws_security_group.efs_sg.id]
}

# EC2 User Data script to mount EFS on instance launch
locals {
  user_data_script = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils nfs-utils
              mkdir -p /mnt/efs
              echo '${aws_efs_file_system.efs.dns_name}:/ /mnt/efs efs _netdev,tls 0 0' >> /etc/fstab
              mount -a
              EOF
}

# Launch EC2 instance 1 in first private subnet
resource "aws_instance" "instance_1" {
  ami           = data.aws_ami.amzn2.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private_a.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  user_data     = local.user_data_script
  tags = {
    Name = "ec2-instance-1"
  }
}

# Launch EC2 instance 2 in second private subnet
resource "aws_instance" "instance_2" {
  ami           = data.aws_ami.amzn2.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private_b.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  user_data     = local.user_data_script
  tags = {
    Name = "ec2-instance-2"
  }
}

# Retrieve latest Amazon Linux 2 AMI
data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }
}

