# Create a cluster placement group for low-latency, high-throughput communication
resource "aws_placement_group" "cluster_group" {
  name     = "cluster-pg"
  strategy = "cluster"
}

# Define the AWS region and AMI for EC2 instances
# Using a common Amazon Linux 2 AMI (ensure this is valid for your region)
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Create three EC2 instances within the placement group
resource "aws_instance" "ec2_cluster" {
  count                        = 3
  ami                          = data.aws_ami.amazon_linux.id
  instance_type                = "t3.micro" # Can be changed based on requirements
  placement_group              = aws_placement_group.cluster_group.name
  associate_public_ip_address  = true
  subnet_id                    = aws_subnet.main.id
  vpc_security_group_ids       = [aws_security_group.allow_ssh.id]

  tags = {
    Name = "cluster-instance-${count.index + 1}"
  }
}

# Required networking: VPC and Subnet
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a" # You can parameterize or adjust based on needs

  tags = {
    Name = "main-subnet"
  }
}

# Security group to allow SSH access (can be adjusted for other ports)
resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow-ssh"
  }
}
```

