extracted_code:
# Amazon MSK (Managed Streaming for Kafka) cluster with 3 broker nodes
# Step-by-step considerations:
# 1. Need a VPC with at least 2 subnets (preferably 3 for high availability across AZs)
# 2. Create security groups for MSK brokers
# 3. Define Zookeeper and Kafka settings
# 4. Create the MSK cluster with 3 broker instances

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "msk_broker" {
  name   = "msk-broker-sg"
  vpc_id = aws_vpc.msk_vpc.id

  # Kafka client connections
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # SSH access for troubleshooting (should be restricted in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # All outbound traffic allowed
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-broker-sg"
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"

    client_subnets = aws_subnet.msk_subnets[*].id

    security_groups = [
      aws_security_group.msk_broker.id
    ]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.example.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  tags = {
    Environment = "production"
  }
}

resource "aws_kms_key" "example" {
  description             = "Customer managed CMK for MSK cluster encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 30
}

resource "aws_kms_alias" "example" {
  name          = "alias/msk-cluster-key"
  target_key_id = aws_kms_key.example.key_id
}

