response:
Let's break down the request step by step:

1. **Service**: We need to provision an Amazon MSK (Managed Streaming for Kafka) cluster.
2. **Region**: The region specified is `us-east-2` (note: `us-east2` is not a valid AWS region; the correct name is `us-east-2`).
3. **Broker Count**: Use three broker instances.
4. **Broker Instance Type**: The request says "three broker instances" but does not specify the type. We'll use a commonly used instance type like `kafka.m5.large` as default.
5. **Networking**: MSK requires a VPC with subnets across at least two Availability Zones. For three brokers, we need at least three subnets (one per AZ).
6. **Security**: We need to define security groups for the cluster.
7. **Zookeeper**: MSK uses Zookeeper backend (managed) so we don't need to provision it.
8. **Encryption and Monitoring**: We'll enable encryption and basic monitoring unless specified otherwise.

We’ll use the `aws_msk_cluster` resource from the AWS Terraform provider.

Now, let's write the full Terraform configuration.

```hcl
provider "aws" {
  region = "us-east-2"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = "us-east-2${element(["a", "b", "c"], count.index)}"
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${element(["a", "b", "c"], count.index)}"
  }
}

resource "aws_security_group" "msk_sg" {
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn
  }

  monitoring_settings {
    current_generation_broker_software = true
    enhanced_monitoring                = "PER_BROKER"
  }

  tags = {
    Environment = "test"
  }
}

resource "aws_kms_key" "msk" {
  description = "KMS key for MSK cluster"
  enable_key_rotation = true
}
