      aws_subnet.msk_subnet_3.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
  }

  logging_info {
    broker_log_delivery {
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs_stream.name
      }
    }
  }

  # Attach IAM role for sending logs to Firehose
  depends_on = [aws_iam_role_policy.msk_logs_to_firehose]

  # MSK requires this to allow sending logs to Firehose
  tags = {
    AWSMskServiceRoleForFirehoseAccess = aws_iam_role.msk_logs_to_firehose.arn
  }
}

