# Note: There is a region mismatch in the request. "us-east-1" is AWS, but written as "us-east1" (missing dash). Assuming "us-east-1".

# We are setting up:
# 1. Amazon MSK (Managed Streaming for Apache Kafka) cluster
# 2. Amazon Kinesis Data Firehose delivery stream to capture logs
# 3. Required IAM roles and permissions for MSK to write logs to Firehose
# 4. S3 bucket as Firehose destination (required)

# Steps:
# - Create S3 bucket for Firehose to deliver data
# - Create IAM role and policy for Firehose to write to S3
# - Create Firehose delivery stream with S3 destination
# - Create IAM role for MSK to deliver logs to Firehose
# - Create MSK cluster with logging info pointing to Firehose

provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "firehose_destination" {
  bucket = "msk-firehose-logs-destination-${random_id.suffix.hex}"
  force_destroy = true

  # Add a lifecycle rule to manage log object retention if needed
  lifecycle {
    prevent_destroy = false
  }
}

