# Note: The region "us-east1" is actually a Google Cloud region. For AWS, the equivalent is "us-east-1".
# Assuming the user meant AWS and intended the region "us-east-1", we proceed with AWS MSK Serverless.

# Configure AWS provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

# Create subnets for the MSK cluster (at least two required)
resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-az1"
  }
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-az2"
  }
}

# Create security group for the MSK cluster
resource "aws_security_group" "msk_security_group" {
  vpc_id = aws_vpc.msk_vpc.id

  # Allow TLS traffic from within the VPC (MSK uses port 9094 for TLS)
  ingress {
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
  }

  # Allow outbound internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# Define the MSK Serverless cluster
resource "aws_msk_cluster_v2" "msk_serverless_cluster" {
  cluster_name           = "my-msk-serverless-cluster"
  kafka_version          = "3.7.0" # Serverless requires specific supported versions
  cluster_type           = "SERVERLESS"

  serverless {
    client_authentication {
      sasl {
        iam = true
      }
    }

    vpc_config {
      subnet_ids         = [aws_subnet.msk_subnet_az1.id, aws_subnet.msk_subnet_az2.id]
      security_group_ids = [aws_security_group.msk_security_group.id]
    }
  }

  # Enable CloudWatch monitoring
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }
}

# Create CloudWatch log group for MSK logs
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "msk-serverless-logs"
  retention_in_days = 7
}

# Output the cluster ARN
output "msk_cluster_arn" {
  value = aws_msk_cluster_v2.msk_serverless_cluster.arn
}

# Output the cluster name
output "msk_cluster_name" {
  value = aws_msk_cluster_v2.msk_serverless_cluster.cluster_name
}

