# Set up an Amazon MSK Serverless cluster in the us-east-2 region

# Define the provider and region
provider "aws" {
  region = "us-east-2"
}

# Define the required IAM resources for MSK Serverless
resource "aws_iam_role" "msk_serverless" {
  name = "msk-serverless-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Attach the required AWS managed policy for MSK Serverless
resource "aws_iam_role_policy_attachment" "msk_serverless" {
  role       = aws_iam_role.msk_serverless.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKReadOnlyAccess"
}

# Create the VPC and subnets required for MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-2a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-2b"

  tags = {
    Name = "msk-subnet-2"
  }
}

resource "aws_subnet" "msk_subnet_3" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-2c"

  tags = {
    Name = "msk-subnet-3"
  }
}

# Create the security group for the MSK cluster
resource "aws_security_group" "msk_cluster_sg" {
  name   = "msk-cluster-security-group"
  vpc_id = aws_vpc.msk_vpc.id

  # Allow broker-to-broker communication
  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    self        = true
    description = "Broker-to-broker and client-to-broker communication"
  }

  # Allow client connections on common MSK ports
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Client connections over TLS"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "msk-security-group"
  }
}

# Create the MSK Serverless cluster
resource "aws_msk_cluster_v2" "serverless_cluster" {
  cluster_name = "serverless-msk-cluster"
  cluster_type = "SERVERLESS"

  serverless {
    client_authentication {
      sasl {
        iam {
          enabled = true
        }
      }
    }

    vpc_config {
      subnet_ids         = [aws_subnet.msk_subnet_1.id, aws_subnet.msk_subnet_2.id, aws_subnet.msk_subnet_3.id]
      security_group_ids = [aws_security_group.msk_cluster_sg.id]
    }
  }

  tags = {
    Environment = "dev"
  }
}

