# Step 1: Define required providers
provider "aws" {
  region = "us-west-2" # Default region, can be changed as needed
}

# Step 2: Create an S3 bucket for MSK logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "my-msk-cluster-logs-bucket"
  force_destroy = true

  # Enable encryption at rest for S3 bucket
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Step 3: Create a CloudWatch Logs group for MSK
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "/aws/kafka/my-msk-cluster"
  retention_in_days = 7
}

# Step 4: Create Kinesis Data Firehose delivery stream to deliver logs to S3
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-logs-delivery-stream"
  destination = "s3"

  s3_configuration {
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
    role_arn   = aws_iam_role.firehose_role.arn
    buffer_size = 10
    buffer_interval = 300
    compression_format = "UNCOMPRESSED"
  }

  # Allow Firehose to use AWS managed KMS key for encryption
  server_side_encryption {
    enabled = true
    key_type = "AWS_OWNED_CMK"
  }
}

# Step 5: Create IAM roles required for MSK and Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-msk-logs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-msk-logs-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.msk_logs_bucket.arn,
          "${aws_s3_bucket.msk_logs_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = "arn:aws:kinesis:*:*:stream/*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Step 6: Define MSK Configuration with open monitoring and logging
resource "aws_msk_configuration" "msk_config" {
  name    = "my-msk-config"
  kafka_versions = ["2.8.1", "3.0.0"]
  server_properties = <<EOF
    auto.create.topics.enable=true
    zookeeper.connection.timeout.ms=1000000
    # Open monitoring via JMX
    listener.security.protocol.map=PLAINTEXT:PLAINTEXT,SSL:SSL,SASL_PLAINTEXT:SASL_PLAINTEXT,SASL_SSL:SASL_SSL
    # Enable JMX for open monitoring
    advertised.listeners=PLAINTEXT://:9092,SSL://:9093,SASL_PLAINTEXT://:9094,SASL_SSL://:9095
    authorizer.class.name=
EOF
}

# Step 7: Set up VPC, subnets, and security groups for MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_1" {
  vpc_id = aws_vpc.msk_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id = aws_vpc.msk_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-2"
  }
}

resource "aws_subnet" "msk_subnet_3" {
  vpc_id = aws_vpc.msk_vpc.id
  cidr_block = "10.0.3.0/24"
  availability_zone = "us-west-2c"
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-3"
  }
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-cluster-sg"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# Step 8: Create Amazon MSK Cluster with 3 brokers
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnet_1.id,
      aws_subnet.msk_subnet_2.id,
      aws_subnet.msk_subnet_3.id
    ]
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 1000
      }
    }
  }

  # Enable encryption at rest using AWS managed CMK
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn
  }

  # Enable open monitoring
  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  # Enable logging to CloudWatch, S3 via Firehose
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.id
        prefix  = "msk-logs"
      }
    }
  }

  configuration_info {
    arn = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  tags = {
    Environment = "production"
  }
}

# Step 9: Create KMS key for encryption at rest
resource "aws_kms_key" "msk_kms_key" {
  description             = "KMS key for Amazon MSK cluster encryption at rest"
  enable_key_rotation     = true

  tags = {
    Name = "msk-encryption-key"
  }
}

# Step 10: Allow MSK to use the KMS key
resource "aws_kms_grant" "msk_grant" {
  key_id            = aws_kms_key.msk_kms_key.key_id
  grantee_principal = aws_msk_cluster.msk_cluster.custom_auth_configuration[0].type # Simplified, actual ARN required
  operations        = ["Decrypt", "Encrypt", "GenerateDataKey", "DescribeKey"]

  # Note: MSK service principal must be granted access; full ARN pattern may vary
  # In practice, this is automatically managed when using AWS managed key or proper service role
  # This is a placeholder — actual setup may require specific AWS service principals.
  name = "msk-kms-grant"
}
```

