# Step-by-step breakdown:
# 1. Create an Amazon MSK cluster with three brokers in us-east-1
# 2. Create necessary networking resources (VPC, subnets, security groups)
# 3. Upload a custom plugin (debezium.zip) for MSK Connect
# 4. Set up an MSK Connect worker configuration
# 5. Deploy an MSK Connect connector using the custom plugin to connect to the MSK cluster

provider "aws" {
  region = "us-east-1"
}

# VPC for MSK and MSK Connect
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Subnets for MSK brokers (3 AZs in us-east-1)
resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = ["us-east-1a", "us-east-1b", "us-east-1c"][count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security group for MSK cluster
resource "aws_security_group" "msk_cluster_sg" {
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092  # Kafka client traffic
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-cluster-sg"
  }
}

# MSK Cluster with 3 brokers
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_cluster_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.key_id
  }

  client_authentication {
    sasl {
      iam = true
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.kafka_config.arn
    revision = aws_msk_configuration.kafka_config.latest_revision
  }

  tags = {
    Environment = "test"
  }
}

# KMS key for encrypting MSK data at rest
resource "aws_kms_key" "msk_kms" {
  description             = "KMS key for MSK cluster encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 7
}

# MSK Configuration for Kafka settings
resource "aws_msk_configuration" "kafka_config" {
  name    = "example-configuration"
  kafka_versions = ["3.5.1"]

  server_properties = <<PROPERTIES
auto.create.topics.enable = true
default.replication.factor = 3
num.partitions = 3
PROPERTIES
}

# IAM role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy for MSK Connect
resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = aws_s3_object.plugin_archive.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka:DescribeCluster",
          "kafka:GetBootstrapBrokers",
          "kafka:ListClusters"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = aws_s3_bucket.plugin_bucket.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeNetworkInterfaces"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 bucket to store custom plugin (debezium.zip)
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-custom-plugins-${random_id.bucket_suffix.hex}"
}

# Upload debezium.zip plugin to S3
resource "aws_s3_object" "plugin_archive" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip" # Ensure this file exists locally
  etag   = filemd5("debezium.zip")
}

# Random suffix for unique S3 bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# MSK Connect custom plugin from debezium.zip
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = aws_s3_object.plugin_archive.key
    }
  }
}

# MSK Connect worker configuration
resource "aws_mskconnect_worker_configuration" "worker_config" {
  name        = "worker-config"
  description = "Worker config for Debezium connector"

  properties_file_content = <<EOF
key.converter=org.apache.kafka.connect.json.JsonConverter
value.converter=org.apache.kafka.connect.json.JsonConverter
key.converter.schemas.enable=true
value.converter.schemas.enable=true
offset.storage.topic=connect-offsets
offset.storage.replication.factor=3
config.storage.topic=connect-configs
config.storage.replication.factor=3
status.storage.topic=connect-status
status.storage.replication.factor=3
EOF
}

# MSK Connect connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name          = "debezium-connector"
  connector_description = "Debezium connector for CDC"
  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
  accelerator_type = "DISABLED"
  worker_configuration {
    revision = aws_mskconnect_worker_configuration.worker_config.latest_revision
    worker_configuration_arn = aws_mskconnect_worker_configuration.worker_config.arn
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
      vpc {
        subnets = aws_subnet.msk_subnets[*].id
        security_groups = [aws_security_group.msk_cluster_sg.id]
      }
      client_authentication {
        sasl {
          iam {
            enabled = true
          }
        }
      }
    }
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  capacity {
    auto_scaling {
      max_worker_count = 4
      mcu_count        = 2
      min_worker_count = 2
    }
  }

  log_delivery {
    worker_log_delivery {
      s3 {
        bucket = aws_s3_bucket.plugin_bucket.id
        enabled = true
      }
    }
  }

  # Connector-specific configurations will depend on the connector type
  # Example: Debezium MySQL connector - adjust as needed
  # connector_configuration = {
  #   "connector.class"                     = "io.debezium.connector.mysql.MySqlConnector"
  #   "database.hostname"                   = "your-db-host"
  #   "database.port"                       = "3306"
  #   "database.user"                       = "user"
  #   "database.password"                   = "password"
  #   "database.server.id"                  = "184054"
  #   "topic.prefix"                        = "dbserver1"
  #   "database.include.list"               = "inventory"
  #   "schema.history.internal.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
  #   "schema.history.internal.kafka.topic" = "schema-changes.inventory"
  # }
}

