```hcl
# Step 1: Set up required providers
provider "aws" {
  region = "us-west-2"
}

# Step 2: Create a VPC and subnets for MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Step 3: Create a security group for MSK cluster
resource "aws_security_group" "msk_sg" {
  name   = "msk-cluster-sg"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-cluster-sg"
  }
}

# Step 4: Create CloudWatch Logs group
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "/aws/msk/cluster-logs"
  retention_in_days = 7
}

# Step 5: Create S3 bucket for logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-bucket-example"
  acl    = "private"

  versioning {
    enabled = false
  }

  lifecycle_rule {
    id      = "log-retention"
    enabled = true
    expiration {
      days = 30
    }
  }
}

# Step 6: Create Kinesis Data Firehose delivery stream to deliver logs
resource "aws_kinesis_firehose_delivery_stream" "msk_logs_stream" {
  name        = "msk-logs-firehose-stream"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
  }

  tags = {
    Environment = "test"
  }
}

# IAM role for Firehose to access S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.msk_logs_bucket.arn,
          "${aws_s3_bucket.msk_logs_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Step 7: MSK Cluster with encryption, logging, and open monitoring
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster-example"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {}
      node_exporter {}
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }

      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs_stream.name
      }

      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.id
        prefix  = "logs/"
      }
    }
  }

  tags = {
    Environment = "test"
  }
}

# KMS key for encryption at rest
resource "aws_kms_key" "msk_kms" {
  description             = "KMS key for MSK cluster encryption at rest"
  deletion_window_in_days = 10
}

# Step 8: Create MSK Connect custom plugin from debezium.zip
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name        = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = "debezium.zip"
    }
  }

  description = "Debezium custom plugin for MSK Connect"
}

# S3 bucket to hold the custom plugin
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugin-bucket-example"
  acl    = "private"
}

# Upload debezium.zip to S3 (this assumes you manage the file out of Terraform)
# You can use aws_s3_object to upload if file is in local path
resource "aws_s3_object" "debezium_plugin_zip" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip" # Adjust path as needed
  etag   = filemd5("debezium.zip") # Only uploads if file changes
}

# Step 9: MSK Connect worker configuration
resource "aws_mskconnect_worker_configuration" "worker_config" {
  name        = "worker-config-debezium"
  description = "Worker config for Debezium connector"

  properties_file_content = <<EOF
  key.converter=org.apache.kafka.connect.json.JsonConverter
  value.converter=org.apache.kafka.connect.json.JsonConverter
  key.converter.schemas.enable=true
  value.converter.schemas.enable=true
  offset.storage.topic=connect-offsets
  config.storage.topic=connect-configs
  status.storage.topic=connect-status
  EOF
}

# Step 10: Create IAM role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_connect_policy" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCloudWatchFullAccess"
}

# Step 11: Create MSK Connect connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-msk-connector"
  connector_configuration = {
    "connector.class" = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"       = "1"
    "database.hostname" = "mysql.example.com"
    "database.port"     = "3306"
    "database.user"     = "user"
    "database.password" = "password"
    "database.server.id" = "184054"
    "database.server.name" = "dbserver1"
    "database.include.list" = "inventory"
    "database.history.kafka.bootstrap.servers" = "${aws_msk_cluster.msk_cluster.bootstrap_brokers_tls}"
    "database.history.kafka.topic" = "schema-changes.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  kafka_connect_version = "2.7.1"
  plugins {
    custom_plugin {
      name = aws_mskconnect_custom_plugin.debezium_plugin.name
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
  worker_configuration {
    revision = aws_mskconnect_worker_configuration.worker_config.latest_revision
    name     = aws_mskconnect_worker_configuration.worker_config.name
  }
}
```

