# Step 1: Define required providers
provider "aws" {
  region = "us-west-2" # Default region; can be changed as needed
}

# Step 2: Define variables for reusability and customization
variable "cluster_identifier" {
  description = "The name for the Aurora DB cluster"
  type        = string
  default     = "my-aurora-cluster"
}

variable "engine" {
  description = "The database engine, e.g., aurora-mysql"
  type        = string
  default     = "aurora-mysql"
}

variable "engine_version" {
  description = "The version of the database engine"
  type        = string
  default     = "8.0.mysql_aurora.3.03.0"
}

variable "instance_class" {
  description = "The instance type for the DB instances in the cluster"
  type        = string
  default     = "db.r6g.large"
}

variable "username" {
  description = "Master username for the DB cluster"
  type        = string
  default     = "admin"
}

variable "password" {
  description = "Master password for the DB cluster"
  type        = string
  sensitive   = true
  default     = "securepassword123"
}

variable "database_name" {
  description = "Name of the initial database to create"
  type        = string
  default     = "mydb"
}

variable "storage_encrypted" {
  description = "Whether to enable storage encryption"
  type        = bool
  default     = true
}

variable "backup_retention_period" {
  description = "How long to keep backups, in days"
  type        = number
  default     = 7
}

variable "preferred_backup_window" {
  description = "Time window for daily backups"
  type        = string
  default     = "03:00-04:00"
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DB subnet group"
  type        = list(string)
  default     = ["subnet-12345678", "subnet-87654321"]
}

variable "vpc_security_group_ids" {
  description = "List of VPC security group IDs to associate"
  type        = list(string)
  default     = ["sg-12345678"]
}

# Step 3: Create a DB subnet group
resource "aws_db_subnet_group" "example" {
  name       = "${var.cluster_identifier}-subnet-grp"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "${var.cluster_identifier}-subnet-group"
  }
}

# Step 4: Create the Aurora MySQL cluster
resource "aws_rds_cluster" "example" {
  cluster_identifier              = var.cluster_identifier
  engine                          = var.engine
  engine_version                  = var.engine_version
  master_username                 = var.username
  master_password                 = var.password
  database_name                   = var.database_name
  db_subnet_group_name            = aws_db_subnet_group.example.name
  vpc_security_group_ids          = var.vpc_security_group_ids
  backup_retention_period         = var.backup_retention_period
  preferred_backup_window         = var.preferred_backup_window
  storage_encrypted               = var.storage_encrypted
  skip_final_snapshot             = true # For testing only; set to false in production
  apply_immediately               = true # Apply changes immediately (can impact cost/downtime)

  # Enable deletion protection in production
  deletion_protection = false # Set to true in production
}

# Step 5: Create at least one instance in the cluster
resource "aws_rds_cluster_instance" "example" {
  count              = 1 # Adjust count for multi-AZ or read replicas
  identifier         = "${var.cluster_identifier}-instance-${count.index + 1}"
  cluster_identifier = aws_rds_cluster.example.id
  instance_class     = var.instance_class
  engine             = aws_rds_cluster.example.engine
  engine_version     = aws_rds_cluster.example.engine_version
  db_subnet_group_name = aws_db_subnet_group.example.name

  # Apply immediately
  apply_immediately = true

  # Enable deletion protection
  depends_on = [aws_rds_cluster.example]
}

