# Setting up an Amazon Aurora PostgreSQL cluster requires several key resources:
# 1. A VPC for network isolation
# 2. Subnets (preferably in multiple AZs)
# 3. A DB subnet group
# 4. Security groups to control access
# 5. The Aurora PostgreSQL cluster (with global settings)
# 6. At least one cluster instance
# 7. Optional: Enable deletion protection, backup, and logging

resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-postgresql-vpc"
  }
}

resource "aws_subnet" "aurora_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.aurora_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.aurora_subnet[*].id

  tags = {
    Name = "aurora-db-subnet-group"
  }
}

resource "aws_security_group" "aurora_sg" {
  name        = "aurora-postgresql-sg"
  description = "Allow PostgreSQL access to Aurora cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  # Allow inbound PostgreSQL traffic (port 5432) from a specific CIDR or other services
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust as needed
  }

  # Allow outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-security-group"
  }
}

resource "aws_rds_cluster" "aurora_postgresql" {
  cluster_identifier           = "aurora-postgresql-cluster"
  engine                       = "aurora-postgresql"
  engine_version               = "15.4"  # Specify desired version
  master_username              = "postgres"
  master_password              = "your_secure_password"  # Use AWS Secrets Manager in production
  db_cluster_parameter_group_name = "default.aurora-postgresql15"
  skip_final_snapshot          = true  # Set to false in production with a snapshot name
  backup_retention_period      = 7
  preferred_backup_window      = "03:00-04:00"
  preferred_maintenance_window = "sun:04:00-sun:05:00"
  deletion_protection          = false  # Disable for testing; enable in production
  db_subnet_group_name         = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids       = [aws_security_group.aurora_sg.id]
  storage_encrypted            = true
  enabled_cloudwatch_logs_exports = ["postgresql"]

  tags = {
    Name = "Aurora PostgreSQL Cluster"
  }
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  count               = 2
  identifier          = "aurora-instance-${count.index + 1}"
  cluster_identifier  = aws_rds_cluster.aurora_postgresql.id
  instance_class      = "db.r6g.large"  # Specify instance type
  engine              = "aurora-postgresql"
  engine_version      = aws_rds_cluster.aurora_postgresql.engine_version
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
  availability_zone   = aws_subnet.aurora_subnet[count.index % length(aws_subnet.aurora_subnet[*].id)].availability_zone

  tags = {
    Name = "Aurora Cluster Instance ${count.index + 1}"
  }
}

