# This request is asking for a MySQL cluster with 100 GB of storage distributed across three AWS AZs: us-east-1a, us-east-1b, and us-east-1c.
# Step-by-step analysis:
# 1. The most appropriate AWS service for a managed, highly available MySQL cluster is Amazon RDS with Multi-AZ enabled.
# 2. For true clustering with automatic failover and read scalability, Amazon RDS with Aurora MySQL is ideal.
# 3. Aurora MySQL automatically replicates data across three Availability Zones (matching us-east-1a, b, c) in a cluster volume.
# 4. Aurora storage scales automatically from 10 GB to 128 TiB; we can set a minimum of 100 GB.
# 5. We will create an Aurora MySQL cluster with an initial instance in one AZ, and additional instances or reader instances can be added for high availability and read scaling.
# 6. Use `db_subnet_group` to ensure instances are placed in the specified subnets across AZs.
# 7. The `storage_size` parameter in the DB instance will ensure at least 100 GB.

resource "aws_db_subnet_group" "mysql_cluster" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = [
    aws_subnet.subnet_a.id,
    aws_subnet.subnet_b.id,
    aws_subnet.subnet_c.id
  ]
  description = "Subnet group for MySQL cluster spanning us-east-1a, us-east-1b, us-east-1c"
}

resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier              = "mysql-aurora-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "8.0.mysql_aurora.3.04.0"
  master_username                 = "admin"
  master_password                 = "securepassword123!" # In practice, use AWS Secrets Manager
  backup_retention_period         = 7
  preferred_backup_window         = "03:00-04:00"
  db_subnet_group_name            = aws_db_subnet_group.mysql_cluster.name
  vpc_security_group_ids          = [aws_security_group.rds_sg.id]
  storage_encrypted               = true
  enabled_cloudwatch_logs_exports = ["error", "general", "slowquery"]
  # Aurora automatically manages storage, starting from 10GB, but grows as needed.
  # To ensure minimum 100 GB usage, we'll rely on pre-sizing via the instance.
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  count               = 3
  identifier          = "mysql-instance-${count.index}"
  cluster_identifier  = aws_rds_cluster.mysql_cluster.id
  instance_class      = "db.r6g.large"
  engine              = "aurora-mysql"
  db_subnet_group_name = aws_db_subnet_group.mysql_cluster.name
  availability_zone   = element([
    "us-east-1a",
    "us-east-1b",
    "us-east-1c"
  ], count.index)
  # To encourage Aurora to allocate more storage initially
  storage_size        = 100 # GB minimum per instance affects cluster storage (shared)
  auto_minor_version_upgrade = false
  publicly_accessible        = false
}

# Networking prerequisites
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "mysql-cluster-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "subnet-us-east-1a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "subnet-us-east-1b"
  }
}

resource "aws_subnet" "subnet_c" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "subnet-us-east-1c"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-mysql-sg"
  description = "Allow MySQL access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust as needed for application access
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Output the cluster endpoint
output "cluster_endpoint" {
  value = aws_rds_cluster.mysql_cluster.endpoint
}

output "cluster_read_endpoint" {
  value = aws_rds_cluster.mysql_cluster.reader_endpoint
}

