# We'll create a MySQL database instance using AWS RDS as an example cloud provider.
# Steps:
# 1. Define the AWS provider (can be adjusted for other providers like GCP or Azure).
# 2. Create a VPC and subnet configuration for the database (minimal network setup).
# 3. Create a security group to allow MySQL access (port 3306) from specific CIDR or resources.
# 4. Create the MySQL RDS instance with basic configurations (engine, allocated storage, instance class, etc.).
# 5. Output the database endpoint for reference.

provider "aws" {
  region = "us-west-2"  # Can be changed based on preference
}

# Create a VPC for the database (minimal setup)
resource "aws_vpc" "db_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support = true

  tags = {
    Name = "db-vpc"
  }
}

# Create a subnet for the DB instance
resource "aws_subnet" "db_subnet" {
  vpc_id                  = aws_vpc.db_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "db-subnet"
  }
}

# Create a DB subnet group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.db_subnet.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

# Create a security group to allow MySQL traffic
resource "aws_security_group" "db_security_group" {
  name        = "mysql-security-group"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict this in production (e.g., to application servers)
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-sg"
  }
}

# Create the MySQL RDS instance
resource "aws_db_instance" "mysql_instance" {
  identifier           = "my-mysql-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  publicly_accessible  = false  # Recommended: false for security; access via VPC
  skip_final_snapshot  = true   # Do not create final snapshot (use false in production)
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_security_group.id]

  username = "admin"
  password = "securepassword123"  # Use AWS Secrets Manager or variable in production

  # Apply maintenance and backup windows (required)
  backup_retention_period = 7
  preferred_backup_window = "03:00-04:00"
  maintenance_window      = "sun:05:00-sun:06:00"

  enabled_cloudwatch_logs_exports = ["error", "general", "slowquery"]

  tags = {
    Name = "MySQL-Instance"
  }
}

# Output the database endpoint
output "db_endpoint" {
  value = aws_db_instance.mysql_instance.endpoint
}

output "db_instance_arn" {
  value = aws_db_instance.mysql_instance.arn
}

