provider "aws" {
  region = "us-west-2"  # Can be changed as needed
}

# Create a DB subnet group using existing subnets (assume VPC and subnets exist or are created elsewhere)
# If no subnets exist, they should be created. For now, assuming they are available.
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with actual subnet IDs
  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# Create a security group to allow inbound PostgreSQL traffic
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  # Allow inbound PostgreSQL from specific CIDR or another security group
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict in production
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

# Create the PostgreSQL RDS instance
resource "aws_db_instance" "postgres_db" {
  identifier                  = "my-postgres-db"
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = "db.t3.micro"
  allocated_storage           = 20
  storage_type                = "gp2"
  username                    = "postgresuser"
  password                    = "securepassword123" # Use AWS Secrets Manager or Terraform variables in production
  db_name                     = "mydb"
  publicly_accessible         = false # Should not be publicly accessible in production
  skip_final_snapshot         = true # Set to false and define final_snapshot_identifier in production
  db_subnet_group_name        = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.postgres_sg.id]
  multi_az                    = false # Enable for production
  backup_retention_period     = 7
  availability_zone           = "us-west-2a" # Optional; omit to let AWS choose

  tags = {
    Environment = "dev"
    Name        = "PostgreSQL Instance"
  }
}

# Output the connection details
output "db_endpoint" {
  value = aws_db_instance.postgres_db.endpoint
}

output "db_name" {
  value = aws_db_instance.postgres_db.db_name
}

output "db_username" {
  value = aws_db_instance.postgres_db.username
}

output "db_port" {
  value = aws_db_instance.postgres_db.port
}

