extracted_code:
# Setting up a DynamoDB Global Table requires creating tables in multiple regions and enabling global table replication.
# In Terraform, we need to configure providers for multiple regions and then create the DynamoDB tables with stream_enabled,
# as DynamoDB Global Tables require streams for replication.

# Step 1: Define AWS providers for us-west-1 and us-west-2
provider "aws" {
  region = "us-west-1"
  alias  = "west1"
}

provider "aws" {
  region = "us-west-2"
  alias  = "west2"
}

# Step 2: Create the primary DynamoDB table in us-west-1 with stream enabled
resource "aws_dynamodb_table" "primary_table" {
  provider             = aws.west1
  name                 = "my-global-table"
  hash_key             = "id"
  billing_mode         = "PAY_PER_REQUEST"
  stream_enabled       = true
  stream_view_type     = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  # Enable global table replication
  replica {
    region_name = "us-west-2"
  }
}

# Step 3: Create the replica table in us-west-2, linked via global table
resource "aws_dynamodb_table" "replica_table" {
  provider             = aws.west2
  name                 = "my-global-table"
  hash_key             = "id"
  billing_mode         = "PAY_PER_REQUEST"
  stream_enabled       = true
  stream_view_type     = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  # This links back to the primary as part of the same global table
  replica {
    region_name = "us-west-1"
  }
}

# Note: AWS handles the replication internally once the tables are configured as replicas.
# The above configuration creates a DynamoDB Global Table spanning us-west-1 and us-west-2.

