  provider             = aws.west1
  name                 = "my-global-table"
  hash_key             = "id"
  billing_mode         = "PAY_PER_REQUEST"
  stream_enabled       = true
  stream_view_type     = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  # Enable global table replication
  replica {
    region_name = "us-west-2"
  }
}

# Step 3: Create the replica table in us-west-2, linked via global table
