  }
}

# Create two subnets in different AZs
resource "aws_subnet" "dax_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.dax_vpc.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = "us-west-2${element(["a", "b"], count.index)}"
  map_public_ip_on_launch = false

  tags = {
    Name = "dax-subnet-${count.index}"
  }
}

# Create DAX subnet group
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name       = "dax-subnet-group"
  subnet_ids = aws_subnet.dax_subnets[*].id
}

# Create security group for DAX cluster
resource "aws_security_group" "dax_security_group" {
  name   = "dax-security-group"
  vpc_id = aws_vpc.dax_vpc.id

  # Allow inbound traffic on DAX port (8111)
  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = -1
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-security-group"
  }
}

# Create IAM role for DAX
resource "aws_iam_role" "dax_role" {
  name = "dax-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AmazonDAXRole policy (managed policy for DAX)
resource "aws_iam_role_policy_attachment" "dax_policy_attach" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDAXRole"
}

# Create DAX cluster
resource "aws_dax_cluster" "dax_cluster" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
  replication_count  = 1
