  parameter_group_name = "default.dax1.0"

  maintenance_window = "sun:03:00-sun:04:00"
  snapshot_name      = "my-snapshot"

  tags = {
    Name = "dax-cluster"
  }
}

output "dax_cluster_endpoint" {
  value = aws_dax_cluster.dax_cluster.configuration_endpoint
}

