  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "VPC-Two"
  }
}

# Create a VPC peering connection between the two VPCs
resource "aws_vpc_peering_connection" "peer" {
  vpc_id      = aws_vpc.vpc_one.id
  peer_vpc_id = aws_vpc.vpc_two.id

  auto_accept = true # Accept the peering request automatically (same account)

  tags = {
    Name = "peer-vpc-one-to-vpc-two"
  }
}

# Add a route in VPC One's main route table to route traffic to VPC Two via peering
resource "aws_route" "route_to_vpc_two" {
  route_table_id         = aws_vpc.vpc_one.default_route_table_id
  destination_cidr_block = aws_vpc.vpc_two.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.peer.id
}

# Add a route in VPC Two's main route table to route traffic to VPC One via peering
resource "aws_route" "route_to_vpc_one" {
  route_table_id         = aws_vpc.vpc_two.default_route_table_id
  destination_cidr_block = aws_vpc.vpc_one.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.peer.id
}

