response:
To create an AWS Neptune cluster with a custom parameter group and restrict access to specific subnets, we need the following components:

1. **VPC**: Required to host the Neptune cluster.
2. **Subnets**: Two subnets in different AZs (recommended for high availability), associated with the VPC.
3. **Subnet Group**: A Neptune subnet group containing the two subnets.
4. **Parameter Group**: A custom Neptune parameter group to override default settings.
5. **Neptune Cluster**: The main cluster using the custom parameter group and subnet group.
6. **Security Group**: To restrict access; we allow inbound access only from the specified subnets.

We assume the VPC and subnets already exist or will be created. For this example, we'll define everything for completeness, including creating a VPC and two subnets.

Note: Neptune does not support public accessibility by default and should only be accessed within the VPC.

Let's now write the complete Terraform HCL code:

```hcl
variable "region" {
  description = "AWS region"
  default     = "us-west-2"
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  default     = "10.0.0.0/16"
}

variable "subnet1_cidr" {
  description = "CIDR block for subnet 1"
  default     = "10.0.1.0/24"
}

variable "subnet2_cidr" {
  description = "CIDR block for subnet 2"
  default     = "10.0.2.0/24"
}

# Create VPC
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# Create two subnets in different AZs
resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = var.subnet1_cidr
  availability_zone = "${var.region}a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = var.subnet2_cidr
  availability_zone = "${var.region}b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# Create Neptune subnet group
resource "aws_neptune_subnet_group" "neptune_subnets" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Create custom Neptune parameter group
resource "aws_neptune_parameter_group" "neptune_params" {
  name   = "custom-neptune-params"
  family = "neptune1"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "custom-neptune-parameter-group"
  }
}

# Create a security group to control access to the Neptune cluster
resource "aws_security_group" "neptune_sg" {
  name   = "neptune-security-group"
  vpc_id = aws_vpc.neptune_vpc.id

  # Allow inbound access on port 8182 (default Neptune port) from subnets
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [var.subnet1_cidr, var.subnet2_cidr]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

# Create Neptune cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier                   = "neptune-cluster-demo"
  engine                               = "neptune"
  engine_version                       = "1.2.1.1"
  neptune_subnet_group_name            = aws_neptune_subnet_group.neptune_subnets.name
  vpc_security_group_ids               = [aws_security_group.neptune_sg.id]
  neptune_iam_authentication_enabled   = false
  skip_final_snapshot                  = true
  backup_retention_period              = 5
  preferred_backup_window              = "07:00-09:00"
  preferred_maintenance_window         = "sun:05:00-sun:07:00"
  parameter_group_name                 = aws_neptune_parameter_group.neptune_params.name
}

# Optional: Create a cluster instance (required to use the cluster)
resource "aws_neptune_cluster_instance" "neptune_instance" {
  cluster_identifier           = aws_neptune_cluster.neptune_cluster.id
  instance_class               = "db.r5.large"
  engine                       = "neptune"
  neptune_subnet_group_name    = aws_neptune_subnet_group.neptune_subnets.name
  apply_immediately            = true

  # Optional: Tags for the instance
  tags = {
    Name = "neptune-cluster-instance"
  }
}
```

