resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name        = "neptune-subnet-group"
  description = "Subnet group for Neptune cluster"

  subnet_ids = [aws_subnet.neptune_subnet.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Create a custom Neptune cluster parameter group
resource "aws_neptune_cluster_parameter_group" "neptune_cluster_param_group" {
  name        = "neptune-cluster-param-group"
  family      = "neptune1"
  description = "Custom cluster parameter group for Neptune"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "neptune-cluster-param-group"
  }
}

# Create a custom Neptune instance parameter group
resource "aws_neptune_parameter_group" "neptune_instance_param_group" {
  name   = "neptune-instance-param-group"
  family = "neptune1"
  description = "Custom instance parameter group for Neptune"

  parameter {
    name  = "neptune_stream"
    value = "traversal"
  }

  tags = {
    Name = "neptune-instance-param-group"
  }
}

# Create a Neptune cluster with the custom cluster parameter group
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier              = "neptune-cluster-example"
  engine                          = "neptune"
  engine_version                  = "1.3.2.0"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.neptune_cluster_param_group.name
  neptune_subnet_group_name       = aws_neptune_subnet_group.neptune_subnet_group.name
  storage_encrypted               = true
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true

  tags = {
    Name = "neptune-cluster"
  }
}

# Create a security group to restrict access to the example subnet
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Security group for Neptune instance allowing access from example subnet"
  vpc_id      = aws_vpc.neptune_vpc.id

  # Allow inbound traffic on Neptune default port (8182) from the example subnet
  ingress {
    from_port       = 8182
    to_port         = 8182
    protocol        = "tcp"
    cidr_blocks     = [aws_subnet.neptune_subnet.cidr_block]
  }

  # Allow outbound traffic to anywhere
  egress {
    from_port       = 0
    to_port         = 0
    protocol        = "-1"
    cidr_blocks     = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

# Create a Neptune instance in the cluster with the custom instance parameter group
resource "aws_neptune_cluster_instance" "neptune_instance" {
  cluster_identifier           = aws_neptune_cluster.neptune_cluster.id
  instance_class               = "db.r5.large"
  engine                       = "neptune"
  neptune_parameter_group_name = aws_neptune_parameter_group.neptune_instance_param_group.name
  identifier                   = "neptune-instance-1"
