# We are provisioning a pair of AWS Chime Voice Connectors and placing them in the same group.
# Steps:
# 1. Create two AWS Chime Voice Connectors with encryption enabled (requires specifying `require_encryption`).
# 2. Create a Chime Voice Connector Group.
# 3. Associate the two Voice Connectors with the group in a prioritized order.

resource "aws_chime_voice_connector" "voice_connector_1" {
  name               = "voice-connector-1"
  require_encryption = true
}

resource "aws_chime_voice_connector" "voice_connector_2" {
  name               = "voice-connector-2"
  require_encryption = true
}

resource "aws_chime_voice_connector_group" "voice_connector_group" {
  name = "voice-connector-group"

  # Associate both encrypted voice connectors
  connector {
    priority           = 1
    voice_connector_id = aws_chime_voice_connector.voice_connector_1.id
  }

  connector {
    priority           = 2
    voice_connector_id = aws_chime_voice_connector.voice_connector_2.id
  }
}

