# Step 2: Create the first Voice Connector with higher priority (e.g., used first in routing). We'll call it "Primary".
# Step 3: Create the second Voice Connector with lower priority. We'll call it "Secondary".

# Step 4: Create a Voice Connector Group to group both connectors. Within the group, assign the first connector a higher priority (lower integer value).

resource "aws_chime_voice_connector" "primary" {
  name               = "primary-voice-connector"
  require_encryption = true
}

resource "aws_chime_voice_connector" "secondary" {
  name               = "secondary-voice-connector"
  require_encryption = true
}

# Step 5: Define the Voice Connector Group and add both connectors.
# Priority is expressed as a number: lower values indicate higher priority.
# So we assign priority 1 to the primary and 2 to the secondary.

resource "aws_chime_voice_connector_group" "group" {
  name = "voice-connector-group"

  # Define the ordered list of connectors in the group
  connector {
    priority            = 1
    voice_connector_id = aws_chime_voice_connector.primary.id
  }

  connector {
    priority            = 2
    voice_connector_id = aws_chime_voice_connector.secondary.id
  }
}

