# We need to provision an AWS Chime Voice Connector and configure media streaming to Amazon Kinesis.
# Step 1: Create the Chime Voice Connector
# Step 2: Create a Kinesis stream to receive the media
# Step 3: Configure the Voice Connector to stream to Kinesis by setting the data retention and associating the stream

resource "aws_chime_voice_connector" "voice_connector" {
  name               = "my-voice-connector"
  require_encryption = true
}

resource "aws_kinesis_stream" "media_stream" {
  name             = "chime-media-stream"
  shard_count      = 2
  retention_period = 24 # hours, minimum 24 for Chime

  # Enable server-side encryption for security
  retention_period = 24
  shard_count      = 2

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# Associate the Kinesis stream with the Chime Voice Connector for media streaming
resource "aws_chime_voice_connector_streaming" "streaming_config" {
  voice_connector_id = aws_chime_voice_connector.voice_connector.id

  # Media streaming configuration
  media_insights_configuration {
    disabled = false
    configuration_arn = aws_kinesis_stream.media_stream.arn
  }

  # Specify data retention (in hours) for call detail records
  data_retention = 7

  # Enable media streaming
  disabled = false

  # Define streaming sources and destinations
  streaming_requirement {
    media_streaming_configuration {
      disabled = false
      data_retention_hours = 7
      stream_arn           = aws_kinesis_stream.media_stream.arn
    }
  }
}

