# Step 1: Create a VPC with a specified CIDR block
# Step 2: Create two subnets (preferably in different availability zones) within the VPC
# Step 3: Create a Redshift subnet group using the two subnets
# Step 4: Create a Redshift cluster using the subnet group
# Step 5: Create a Redshift endpoint access resource (for managing inbound access via VPC endpoints)

resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name        = "redshift-subnet-grp"
  description = "Subnet group for Redshift cluster"
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

resource "aws_redshift_cluster" "redshift_cluster" {
