# 2. Enable static website hosting on the bucket (optional, if images are to be served directly from S3).
# 3. Configure public read access to the images (via bucket policy) so they can be viewed on a website.
# 4. Ensure the bucket is created in a specific region and with versioning disabled (unless needed).
# 5. Block public access settings need to be relaxed appropriately (with caution) to allow public access.
# 6. Add tags for cost allocation and management.

# Note: Exposing images publicly should be done securely. We'll allow only s3:GetObject for public access.

resource "aws_s3_bucket" "image_bucket" {
  bucket = "my-website-images-${random_id.suffix.hex}"

  # Enable static website hosting to serve images directly (optional)
  website {
    index_document = "index.html"
    error_document = "error.html"
  }

  # Allow public reads
  acl          = "public-read"
  force_destroy = true # Use with caution: allows deletion of non-empty bucket

  # Disable versioning unless needed
  versioning {
    enabled = false
  }

  # Block public access settings - we allow public access via bucket policy
  # So we disable the blocks for GetObject, but be aware of security implications
  # Best practice: use bucket policy instead of ACLs, but for simplicity, we mix them here
  # In production, consider using only bucket policies.
  policy = data.aws_iam_policy_document.bucket_policy.json

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Website Image Storage"
    Environment = "production"
    Project     = "MyWebsite"
  }
}

# Use random_id to create a unique bucket name (bucket names are globally unique)
resource "random_id" "suffix" {
  byte_length = 8
}

# Define a bucket policy to allow public read access to objects
data "aws_iam_policy_document" "bucket_policy" {
  statement {
    sid       = "PublicReadGetObject"
    effect    = "Allow"
    principals {
      type        = "*"
      identifiers = ["*"]
    }
    actions = [
      "s3:GetObject"
    ]
    resources = [
      "${aws_s3_bucket.image_bucket.arn}/*",
    ]
  }
}

# Outputs the bucket name and website endpoint
output "bucket_name" {
