# We also need to specify the destination S3 bucket and prefix where inventory reports will be stored.
# For this example, we'll use the same bucket for storing reports, but in practice, you might use a separate bucket.

resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"

  # Enable versioning for the bucket (recommended for production use)
  versioning {
    enabled = true
  }

  # Block public access settings (recommended for security)
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Add a lifecycle rule if needed (optional)
  lifecycle_rule {
    id      = "delete-inventory-older-than-365-days"
    enabled = true
    prefix  = "inventory/"

