  bucket = aws_s3_bucket.mybucket.id
  name   = "daily-inventory"

  # Set frequency to Daily as per the requirement
  frequency = "Daily"

  # Include all object versions in inventory (you can set to "Current" if needed)
  included_object_versions = "All"

  # Define destination for inventory reports
