# Step 1: Create the target S3 bucket where server access logs will be delivered
resource "aws_s3_bucket" "log_delivery_bucket" {
  bucket = "my-target-log-bucket-unique-name-12345" # Change to a unique name

  # Enable encryption for the log bucket
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Optionally, block public access for security
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Enable versioning for log integrity
  versioning {
    enabled = true
  }

  # Add a lifecycle rule to automatically expire old log objects (optional)
  lifecycle_rule {
    enabled = true
    expiration {
      days = 365
    }
  }
}

# Step 2: Create the source S3 bucket that will have its access logs enabled
resource "aws_s3_bucket" "source_bucket" {
  bucket = "my-source-bucket-unique-name-67890" # Change to a unique name

  # Enable server access logging to the target bucket
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Block public access as a best practice
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Enable versioning on source bucket
  versioning {
    enabled = true
  }

  # Configure logging
  logging {
    target_bucket = aws_s3_bucket.log_delivery_bucket.id
    target_prefix = "logs/" # Optional: prefix for logs within the target bucket
  }
}

# Step 3: Ensure the log delivery bucket grants write permissions to AWS log delivery service
resource "aws_s3_bucket_policy" "log_delivery_policy" {
  bucket = aws_s3_bucket.log_delivery_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "logdelivery.s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.log_delivery_bucket.arn}/logs/*"
        Condition = {
          StringEquals = {
            "s3:x-amz-acl": "bucket-owner-full-control"
          }
        }
      },
      {
        Effect = "Allow"
        Principal = {
          Service = "logdelivery.s3.amazonaws.com"
        }
        Action   = "s3:GetBucketAcl"
        Resource = aws_s3_bucket.log_delivery_bucket.arn
      }
    ]
  })
}

