extracted_code:
# Terraform configuration for AWS CodeBuild-based autograding system
# This setup includes:
# - IAM role for CodeBuild with permissions to access GitHub, CloudWatch, S3, and CodeBuild
# - S3 bucket to store build logs and artifacts
# - CodeBuild project configured to clone student repos from GitHub and run grading scripts
# - Assumes GitHub webhook will trigger builds (webhook setup is out of scope here)

resource "aws_s3_bucket" "autograding_artifacts" {
  bucket = "cs-course-autograding-artifacts-${random_string.suffix.result}"
  tags = {
    Name        = "CS Autograding Artifacts"
    Environment = "production"
  }
}

resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "cs-autograding-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:PutObjectAcl"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.autograding_artifacts.arn}/*"
      },
      {
        Action = [
          "s3:GetBucketPolicy",
          "s3:PutBucketPolicy"
        ]
        Effect   = "Allow"
        Resource = aws_s3_bucket.autograding_artifacts.arn
      },
      {
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

resource "aws_codebuild_project" "autograding_project" {
  name          = "cs-course-autograding"
  description   = "Auto-grading system for CS course submissions"
  build_timeout = 60 # minutes
  concurrent_build_limit = 10

  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.id
    package_zip = true
    path = "artifacts"
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.id
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"
    compute_type    = "BUILD_GENERAL1_SMALL"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "COURSE_ID"
      value = var.course_id
    }

    environment_variable {
      name  = "GRADING_SCRIPT"
      value = "/usr/local/bin/grade_submission.sh"
    }
  }

  # Source will be set per student via webhook or API call
  # Using GITHUB for OAuth token-based access
  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.organization_name}/${var.template_repo}"
    git_clone_depth = 1
    report_build_status = true
    buildspec = "buildspec.yml"
  }

  tags = [
    {
      key   = "Project"
      value = "CS-Autograding"
    },
    {
      key   = "Course"
      value = var.course_id
    }
  ]

  # Allow logs to CloudWatch
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograding"
      stream_name = "builds"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograding_artifacts.id}/logs"
    }
  }
}

# Sample buildspec template that would be used by students
# This should be part of the template repository
resource "local_file" "buildspec_template" {
  content = <<EOT
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
    commands:
      - echo "Installing grading dependencies..."
      - pip install pytest pylint

  pre_build:
    commands:
      - echo "Preparing environment for grading..."
      - chmod +x grade_submission.sh
      - ./validate_structure.sh

  build:
    commands:
      - echo "Running automated grading..."
      - ./grade_submission.sh

  post_build:
    commands:
      - echo "Grading completed."
      - cat grade_report.txt
      - aws s3 cp grade_report.txt s3://${aws_s3_bucket.autograding_artifacts.bucket}/\$CODEBUILD_BUILD_ID/\$REPO_OWNER/\$REPO_NAME/grade_report.txt

artifacts:
  files:
    - 'grade_report.txt'
    - 'test_results.xml'
  discard-paths: yes
EOT

  filename = "${path.module}/templates/buildspec.yml"
}

variable "github_token" {
  description = "GitHub personal access token with repo scope for cloning private student repos"
  type        = string
  sensitive   = true
}

variable "organization_name" {
  description = "GitHub organization name where student repositories are hosted"
  type        = string
}

variable "template_repo" {
  description = "Template repository name that contains grading scripts and buildspec"
  type        = string
}

variable "course_id" {
  description = "Identifier for the CS course (e.g., CS101)"
  type        = string
  default     = "CS101"
}

output "autograding_project_name" {
  value = aws_codebuild_project.autograding_project.name
}

output "artifacts_bucket" {
  value = aws_s3_bucket.autograding_artifacts.bucket
}

output "codebuild_role_arn" {
  value = aws_iam_role.codebuild_role.arn
}

