# Autograding System for Computer Science Course using AWS S3, CodeBuild, and Supporting Services

# Provider setup
provider "aws" {
  region = "us-east-1"
}

# S3 bucket to store student submissions (source code) and grading results
resource "aws_s3_bucket" "student_submissions" {
  bucket = "cs-course-autograder-submissions-${random_id.deploy_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "CS Course Student Submissions"
    Environment = "Production"
    Purpose     = "Autograder Source and Results Storage"
  }
}

# S3 bucket for CodeBuild artifact intermediates (required by CodeBuild)
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "cs-course-codebuild-artifacts-${random_id.deploy_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Generate random suffix to ensure S3 bucket name uniqueness
resource "random_id" "deploy_suffix" {
  byte_length = 4
}

# IAM role for CodeBuild to access S3, CloudWatch, and ECR (if needed)
resource "aws_iam_role" "codebuild_role" {
  name = "cs-course-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild permissions
resource "aws_iam_policy" "codebuild_policy" {
  name = "cs-course-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.student_submissions.arn,
          "${aws_s3_bucket.student_submissions.arn}/*",
          aws_s3_bucket.codebuild_artifacts.arn,
          "${aws_s3_bucket.codebuild_artifacts.arn}/*"
        ]
      }
    ]
  })
}

# Attach policy to CodeBuild role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  policy_arn = aws_iam_policy.codebuild_policy.arn
  role       = aws_iam_role.codebuild_role.name
}

# CodeBuild project for autograding student code
resource "aws_codebuild_project" "autograder" {
  name         = "cs-course-autograder"
  description  = "Automated grader for student programming assignments"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"  # Results uploaded manually to S3 by build script
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = false
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.student_submissions.bucket
    }

    environment_variable {
      name  = "RESULTS_PREFIX"
      value = "results/"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/cs101-assignments.git" # Placeholder - could be parameterized
    git_clone_depth = 1

    buildspec = <<BUILD_SPEC
version: 0.2
phases:
  install:
    commands:
      - echo "Installing grading dependencies..."
      - pip install pytest pylint numpy
  pre_build:
    commands:
      - echo "Fetching student code from S3..."
      - aws s3 sync s3://$SUBMISSION_BUCKET/submissions/$CODEBUILD_BUILD_ID/ ./student_code/
      - ls -la ./student_code/
  build:
    commands:
      - echo "Running autograder..."
      - cd ./student_code
      - |
        if [ -f "solution.py" ]; then
          python3 -m pytest test_assignment.py -v --json-report --json-report-file=report.json
          pylint --output-format=json solution.py > pylint_report.json
          python3 ../grader/collect_results.py  # Custom script to aggregate grades
        else
          echo '{"error": "solution.py not found"}' > grade_result.json
          echo "Required solution.py missing in submission." >&2
          exit 1
        fi
  post_build:
    commands:
      - echo "Uploading grading results..."
      - aws s3 cp report.json s3://$SUBMISSION_BUCKET/$RESULTS_PREFIX/$CODEBUILD_BUILD_ID/ --acl private
      - aws s3 cp pylint_report.json s3://$SUBMISSION_BUCKET/$RESULTS_PREFIX/$CODEBUILD_BUILD_ID/ --acl private
      - aws s3 cp grade_result.json s3://$SUBMISSION_BUCKET/$RESULTS_PREFIX/$CODEBUILD_BUILD_ID/ --acl private
      - echo "Grading completed for $CODEBUILD_BUILD_ID"
      - echo "Sending completion notification..."
      - aws sns publish --topic-arn ${aws_sns_topic.grading_completion.arn} --message "Grading completed for submission $CODEBUILD_BUILD_ID"
      - echo "Results uploaded to S3."
cache:
  paths:
    - '/root/.cache/pip/**/*'
reports:
  unittests:
    files: report.json
    file_format: JUNITXML
    base_directory: /codebuild/output/src
BUILD_SPEC
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-course-autograder"
      stream_name = "build"
    }
    s3_logs {
      location = "${aws_s3_bucket.codebuild_artifacts.id}/logs"
      encrypted = true
    }
  }

  tags = [
    {
      key   = "Project"
      value = "CS-Course-Autograder"
    },
    {
      key   = "Owner"
      value = "cs-instructor@example.com"
    }
  ]
}

# SNS topic to notify instructors/students when grading is complete
resource "aws_sns_topic" "grading_completion" {
  name = "cs-course-grading-completion"

  tags = {
    Name = "Autograder Completion Notifications"
  }
}

# Optional: Subscription to SNS topic (e.g., for instructor email)
resource "aws_sns_topic_subscription" "instructor_email" {
  topic_arn = aws_sns_topic.grading_completion.arn
  protocol  = "email"
  endpoint  = "instructor@example.com" # Replace with real email
}

# CloudWatch Event Rule to trigger CodeBuild when new submission is uploaded to S3
resource "aws_cloudwatch_event_rule" "trigger_autograding" {
  name        = "trigger-autograding-on-submission"
  description = "Triggers autograding when student submits code to S3"

  event_pattern = jsonencode({
    source      = ["aws.s3"]
    detail_type = ["Object Created"]
    detail = {
      bucket = {
        name = [aws_s3_bucket.student_submissions.bucket]
      }
      object = {
        key = [{
          prefix = "submissions/"
        }]
      }
    }
  })
}

# Permission for CloudWatch to invoke CodeBuild
resource "aws_lambda_permission" "event_permission" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.start_build.arn
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.trigger_autograding.arn
}

# Lambda function to start CodeBuild when new submission detected
resource "aws_lambda_function" "start_build" {
  filename      = "lambda/start_build.zip"
  function_name = "cs-course-start-build"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "start_build.lambda_handler"
  runtime       = "python3.9"
  timeout       = 30

  environment {
    variables = {
      PROJECT_NAME = aws_codebuild_project.autograder.name
    }
  }

  source_code_hash = filebase64sha256("lambda/start_build.zip")
}

# IAM role for Lambda to invoke CodeBuild and log to CloudWatch
resource "aws_iam_role" "lambda_exec" {
  name = "cs-course-lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_exec.name
}

resource "aws_iam_policy" "lambda_codebuild_policy" {
  name = "cs-course-lambda-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograder.arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_codebuild" {
  policy_arn = aws_iam_policy.lambda_codebuild_policy.arn
  role       = aws_iam_role.lambda_exec.name
}

# CloudWatch Event Target: invoke Lambda when S3 object created
resource "aws_cloudwatch_event_target" "start_build_target" {
  rule      = aws_cloudwatch_event_rule.trigger_autograding.name
  target_id = "StartBuildLambda"
  arn       = aws_lambda_function.start_build.arn
}

# Note: In a real setup, you would:
# 1. Package a Lambda ZIP with boto3 script to start CodeBuild
# 2. Store student repos in GitHub, use webhooks or S3 uploads to push to submission bucket
# 3. Add API Gateway + Lambda to allow secure student uploads
# 4. Add DynamoDB to store grade records and student metadata

# Example Lambda handler (not included in TF) would:
# - Parse S3 event, extract submission key
# - Start CodeBuild with environment variables including submission ID

