extracted_code:
# Designing infrastructure for a CS course autograding system using AWS
# Steps:
# 1. Create an S3 bucket to store grading outputs and potentially student artifacts.
# 2. Set up CodeBuild project to:
#    - Pull student code from GitHub.
#    - Run autograding inside a consistent environment.
#    - Upload results to S3.
# 3. Use IAM roles and policies to allow CodeBuild to access S3 and interact with GitHub.
# 4. Include necessary permissions and artifacts configuration.

resource "aws_s3_bucket" "grading_output_bucket" {
  bucket = "cs-course-autograding-outputs-${random_id.id.hex}"
  tags = {
    Name        = "CS Course Autograding Output Bucket"
    Environment = "production"
  }
}

resource "aws_s3_bucket_versioning" "grading_output_bucket_versioning" {
  bucket = aws_s3_bucket.grading_output_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "cs-course-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "codebuild_s3_github_policy" {
  name = "codebuild_s3_github_access"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ],
        Resource = [
          aws_s3_bucket.grading_output_bucket.arn,
          "${aws_s3_bucket.grading_output_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow",
        Action = [
          "codebuild:BatchPutCodeCoverages",
          "codebuild:BatchPutTestCases"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_s3_github_policy.arn
}

resource "aws_iam_role_policy_attachment" "codebuild_service_role_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildBasicAccess"
}

resource "aws_codebuild_project" "autograding_project" {
  name         = "cs-course-autograding"
  description  = "Autograde student submissions from GitHub for CS course"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"
    compute_type    = "BUILD_GENERAL1_SMALL"
    privileged_mode = false

    environment_variable {
      name  = "S3_OUTPUT_BUCKET"
      value = aws_s3_bucket.grading_output_bucket.bucket
    }

    # Optionally pass GitHub token via AWS Secrets Manager or Parameter Store
    environment_variable {
      name  = "GITHUB_REPO_TOKEN"
      value = aws_secretsmanager_secret_version.github_token.secret_string
      type  = "SECRETS_MANAGER"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/cs101-assignments.git"
    git_clone_depth = 1
    report_build_status = true

    # Optional: Use GitHub OAuth or a Personal Access Token stored in Secrets Manager
    auth {
      type = "OAUTH"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/${aws_codebuild_project.autograding_project.name}"
      stream_name = "main"
    }
    s3_logs {
      enabled = true
      bucket  = aws_s3_bucket.grading_output_bucket.bucket
      prefix  = "logs"
    }
  }

  # Build will be triggered via webhook or manually
  # We can add Webhook if needed later, but for now use manual/GitHub trigger
  webhook = true
  webhook_filters {
    type    = "EVENT"
    pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
  }
}

# Store GitHub token securely
resource "aws_secretsmanager_secret" "github_token" {
  name = "cs-course/github-token"
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id = aws_secretsmanager_secret.github_token.id
  # This should be populated out-of-band with a GitHub Personal Access Token
  # secret_string = "your_github_token_here"  # DO NOT hardcode in real usage
}

# Random ID to create a unique bucket name
resource "random_id" "id" {
  byte_length = 8
}

output "grading_bucket_name" {
  value = aws_s3_bucket.grading_output_bucket.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograding_project.name
}

