```hcl
# This Terraform configuration sets up an autograding system for a CS course
# using AWS CodeBuild within a VPC with no internet access to safely execute student code.

# Requirements:
# 1. Hosted on AWS
# 2. Pulls student submissions from GitHub
# 3. Executes in isolated environment (no internet access)
# 4. Uses AWS CodeBuild for build/grading
# 5. Uses VPC to control network access
# 6. Records grading outcomes (logs to CloudWatch, artifacts to S3)

provider "aws" {
  region = "us-east-1"
}

# S3 bucket to store build artifacts and grading results
resource "aws_s3_bucket" "grading_artifacts" {
  bucket = "cs-course-grading-artifacts-${random_string.suffix.result}"
  tags = {
    Name = "CS Course Grading Artifacts"
  }
}

resource "aws_s3_bucket_versioning" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 bucket for storing logs
resource "aws_s3_bucket" "grading_logs" {
  bucket = "cs-course-grading-logs-${random_string.suffix.result}"
  tags = {
    Name = "CS Course Grading Logs"
  }
}

# Random suffix to ensure unique bucket names
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# VPC for isolated execution environment
resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  instance_tenancy     = "default"

  tags = {
    Name = "CS-Grading-VPC"
  }
}

# Subnet for CodeBuild
resource "aws_subnet" "grading_subnet" {
  vpc_id                  = aws_vpc.grading_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = false  # No public IP => no internet access
  availability_zone       = "${var.availability_zone}"

  tags = {
    Name = "CS-Grading-Subnet"
  }
}

# Security group for CodeBuild - only allows necessary internal traffic
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-security-group"
  description = "Security group for CodeBuild projects - isolated"
  vpc_id      = aws_vpc.grading_vpc.id

  # No egress rules = all outbound traffic denied
  # This ensures no internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    self        = true
  }

  # Allow no inbound traffic for maximum isolation
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "CodeBuild-Security-Group"
  }
}

# IAM role for CodeBuild to assume
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild permissions
resource "aws_iam_policy" "codebuild_policy" {
  name = "codebuild-service-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
