          "s3:PutObjectAcl"
        ]
        Resource = [
          aws_s3_bucket.grading_artifacts.arn,
          "${aws_s3_bucket.grading_artifacts.arn}/*",
          aws_s3_bucket.grading_logs.arn,
          "${aws_s3_bucket.grading_logs.arn}/*"
        ]
