```hcl
# Autograding system using AWS S3, CodeBuild, VPC, and supporting services
# Components:
# 1. S3 bucket to store student submissions and grading results
# 2. VPC with private subnets (no internet access) for secure code execution
# 3. CodeBuild project to execute grading in isolated environment
# 4. IAM roles for least privilege access
# 5. CloudWatch Logs for storing build outputs
# 6. SNS for grading completion notifications (optional)

resource "aws_s3_bucket" "submission_bucket" {
  bucket = "student-submissions-autograding"

  versioning {
    enabled = true
  }

  lifecycle_rule {
    id      = "cleanup-old-grades"
    prefix  = "grades/"
    enabled = true
    expiration {
      days = 30
    }
  }

  lifecycle_rule {
    id      = "cleanup-old-submissions"
    prefix  = "submissions/"
    enabled = true
    expiration {
      days = 14
    }
  }

  tags = {
    Name        = "Student Submission Storage"
    Environment = "production"
    Project     = "autograding"
  }
}

resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "autograding-codebuild-artifacts"

  versioning {
    enabled = true
  }

  # Artifacts retained for audit trail
  lifecycle_rule {
    id      = "retain-artifacts"
    enabled = true
    expiration {
      days = 365
    }
  }

  tags = {
    Name        = "CodeBuild Artifacts"
    Environment = "production"
    Project     = "autograding"
  }
}

# VPC configuration - isolated environment with no internet access
resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.100.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name        = "Autograding VPC"
    Environment = "production"
    Project     = "autograding"
  }
}

# Subnets for CodeBuild - keep in private subnets with no NAT/internet gateway
resource "aws_subnet" "private_subnet_az1" {
  vpc_id                  = aws_vpc.grading_vpc.id
  cidr_block              = "10.100.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "Autograding Private Subnet 1"
  }
}

resource "aws_subnet" "private_subnet_az2" {
  vpc_id                  = aws_vpc.grading_vpc.id
  cidr_block              = "10.100.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "Autograding Private Subnet 2"
  }
}

# Security group for CodeBuild - minimal access
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-security-group"
  description = "Security group for CodeBuild grading instances"
  vpc_id      = aws_vpc.grading_vpc.id

  # No egress to internet
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.100.0.0/16"]  # Only allow VPC internal communication
  }

  # Allow inbound only from within VPC (if needed for debugging/logging)
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.100.0.0/16"]
  }

  tags = {
    Name = "CodeBuild Security Group"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild role
resource "aws_iam_policy" "codebuild_policy" {
  name        = "autograding-codebuild-policy"
  description = "Policy for CodeBuild projects in autograding system"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.submission_bucket.arn,
          "${aws_s3_bucket.submission_bucket.arn}/*",
          aws_s3_bucket.codebuild_artifacts.arn,
          "${aws_s3_bucket.codebuild_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchPutCodeCoverages",
          "codebuild:BatchPutTestCases",
          "codebuild:UpdateReport"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograding_project" {
  name          = "student-submission-autograder"
  description   = "Autograding system for student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  concurrent_build_limit = 5

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    path   = "artifacts"
    packaging = "ZIP"
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"  # Includes common dev tools
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false  # Important: avoid container escalation

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.submission_bucket.bucket
    }

    environment_variable {
      name  = "GRADES_BUCKET"
      value = aws_s3_bucket.submission_bucket.bucket
    }

    # No internet access via VPC configuration
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/student-autograding"
      stream_name = "build"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.bucket}/logs"
    }
  }

  source {
    type      = "GITHUB"
    # This would be connected to the course organization's GitHub
    # auth configuration would be set separately
    git_clone_depth = 1
    report_build_status = true
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.private_subnet_az1.id, aws_subnet.private_subnet_az2.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  # Build timeout - prevent infinite loops
  timeout_in_minutes = 15

  queued_timeout_in_minutes = 45

  tags = {
    Project = "autograding"
    Course  = "CS101"
  }

  # Build spec is stored in student repositories or in central S3
  build_timeout_in_minutes = 15
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_log_group" {
  name              = "/aws/codebuild/student-autograding"
  retention_in_days = 90
  tags = {
    Project = "autograding"
  }
}

# Optional: SNS topic for grading completion notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "student-grading-completed"

  tags = {
    Project = "autograding"
  }
}

# Notification configuration (would connect to Lambda or other services)
output "submission_bucket_name" {
  value = aws_s3_bucket.submission_bucket.bucket
  description = "S3 bucket for student submissions and grades"
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograding_project.name
  description = "CodeBuild project name for autograding"
}

output "vpc_id" {
  value = aws_vpc.grading_vpc.id
  description = "VPC ID for the grading environment"
}

# Instructions for use:
# 1. Students push to designated GitHub repositories
# 2. Webhooks trigger CodeBuild projects
# 3. CodeBuild downloads submission from S3 (or GitHub), runs tests in VPC
# 4. Results uploaded to S3 and logs stored in CloudWatch
# 5. No internet access due to VPC/SG configuration
```

