# Security group to block all outbound internet access
resource "aws_security_group" "no_outbound_sg" {
  vpc_id = aws_vpc.autograding_vpc.id

  # Deny all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    self        = true
    description = "Block all outbound traffic"
    # Note: AWS default is to ALLOW all outbound unless explicitly denied
    # So we must add a restrictive rule
  }

  # Allow inbound from itself for internal communication if needed
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
    description = "Allow all internal traffic"
  }

  tags = {
    Name = "no-outbound-sg"
  }
}

# AWS S3 bucket to store student submissions and grading results
resource "aws_s3_bucket" "autograding_bucket" {
  bucket = "cs-course-autograding-${var.account_id}" # account_id can be passed as a variable
  acl    = "private"

  versioning {
    enabled = true
  }

  tags = {
    Name        = "autograding-storage"
    Environment = "production"
  }
}

# Enable server-side encryption on the S3 bucket
resource "aws_s3_bucket_server_side_encryption_configuration" "autograding_encryption" {
  bucket = aws_s3_bucket.autograding_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# IAM role for CodeBuild to assume
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild role to access necessary resources
resource "aws_iam_policy" "codebuild_policy" {
  name = "autograding-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${var.region}:${var.account_id}:log-group:/aws/codebuild/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograding_bucket.arn,
          "${aws_s3_bucket.autograding_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeSubnet",
          "ec2:AssignPrivateIpAddresses",
          "ec2:AttachNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DetachNetworkInterface",
          "ec2:ModifyNetworkInterfaceAttribute",
          "ec2:UnassignPrivateIpAddresses"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "iam:PassRole"
        ]
        Resource = aws_iam_role.codebuild_role.arn
      }
    ]
  })
}

# Attach the policy to the CodeBuild role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograding_project" {
  name         = "cs-autograding-project"
  description  = "Autograding system for CS course submissions"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.autograding_bucket.bucket
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"  # or select appropriate image
    compute_type    = "BUILD_GENERAL1_SMALL"
    privileged      = false

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.autograding_bucket.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO_URL"
      value = "https://github.com/student-repo-placeholder"  # Can be parameterized
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/student-submissions.git" # To be configured
    git_clone_depth = 1
  }

  # Enable VPC configuration to place CodeBuild inside the isolated VPC
  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.autograding_subnet.id]
    security_group_ids = [aws_security_group.no_outbound_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograding"
      stream_name = "autograding-stream"
    }
    s3_logs {
      location = "${aws_s3_bucket.autograding_bucket.bucket}/logs"
      enabled  = true
    }
  }
}

# Optional: CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_log_group" {
  name              = "/aws/codebuild/cs-autograding"
  retention_in_days = 30
  tags = {
    Name = "codebuild-logs"
  }
}

# Variables used (to be defined in variables.tf or passed via tfvars)
variable "region" {
  default = "us-east-1"
}

variable "account_id" {
  description = "AWS Account ID"
  type        = string
}
```

