# This Terraform configuration creates a serverless cat image hosting solution
# using AWS API Gateway and S3. It allows for uploading cat images and serving random ones.

resource "aws_s3_bucket" "cat_images_bucket" {
  bucket = "cat-images-${random_id.bucket_suffix.hex}"
  # Configure for static website hosting if needed, but we'll use API Gateway/S3 direct access
  force_destroy = true

  # Block public access by default
  object_lock_enabled = false

  # Enable versioning for image backup
  versioning {
    enabled = true
  }

  tags = {
    Name        = "Cat Images Bucket"
    Environment = "production"
  }
}

resource "aws_s3_bucket_public_access_block" "cat_images_bucket" {
  bucket = aws_s3_bucket.cat_images_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# API Gateway for handling upload and retrieval requests
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI"
  description = "API for uploading and retrieving cat images"
}

resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "image_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "image"
}

resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_resource.image_resource.id
  path_part   = "random"
}

# Method for uploading images (POST /upload)
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"

  request_parameters = {
    "method.request.header.Content-Type" = true
  }

  request_models = {
    "application/json" = "Empty"
  }
}

# Method for getting a random cat image (GET /image/random)
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration for upload - this would typically connect to Lambda, 
# but for direct S3 upload, we'll set up pre-signed URL mechanism
resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload_resource.id
  http_method = aws_api_gateway_method.upload_post.http_method
  type        = "MOCK"

  request_templates = {
    "application/json" = <<EOF
{
  "statusCode": 200
}
EOF
  }

  passthrough_behavior = "WHEN_NO_TEMPLATES"
  content_handling     = "CONVERT_TO_TEXT"
}

# Integration for random image - would use Lambda to select random image
resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.random_get.http_method
  type        = "MOCK"

  request_templates = {
    "application/json" = <<EOF
{
  "statusCode": 200
}
EOF
  }

  passthrough_behavior = "WHEN_NO_TEMPLATES"
  content_handling     = "CONVERT_TO_TEXT"
}

# Method response for upload
resource "aws_api_gateway_method_response" "upload_response_200" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload_resource.id
  http_method = aws_api_gateway_method.upload_post.http_method
  status_code = "200"

  response_models = {
    "application/json" = "Empty"
  }

  response_parameters = {
    "method.response.header.Access-Control-Allow-Origin" = true
  }
}

# Method response for random image
resource "aws_api_gateway_method_response" "random_response_200" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.random_get.http_method
  status_code = "200"

  response_models = {
    "application/json" = "Empty"
  }

  response_parameters = {
    "method.response.header.Access-Control-Allow-Origin" = true
  }
}

# Deployment of the API
resource "aws_api_gateway_deployment" "cat_api_deployment" {
  depends_on = [
    aws_api_gateway_integration.upload_integration,
    aws_api_gateway_integration.random_integration
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}

# S3 bucket policy to allow API Gateway to access images
# Note: In a real implementation, you might use CloudFront or pre-signed URLs
resource "aws_s3_bucket_policy" "cat_images_bucket_policy" {
  bucket = aws_s3_bucket.cat_images_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowAPIGatewayGetObjects"
        Effect = "Allow"
        Principal = {
          Service = "apigateway.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.cat_images_bucket.arn}/*"
        Condition = {
          StringEquals = {
