# Step-by-step design:
# 1. We need an S3 bucket to store cat images (with encryption and versioning)
# 2. Lambda functions to handle:
#    - Uploading images (via API Gateway)
#    - Returning random images (via API Gateway)
# 3. API Gateway to expose REST endpoints
# 4. IAM roles for Lambda to access S3 and write logs
# 5. CloudWatch for logging

resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-images-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Cat Images Storage"
    Environment = "production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_iam_role" "lambda_role" {
  name = "cat-api-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "s3_access" {
  name = "lambda_s3_access"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_lambda_function" "upload_cat_image" {
  filename         = "lambda/upload_cat_image.zip"
  function_name    = "upload-cat-image"
  role             = aws_iam_role.lambda_role.arn
  handler          = "upload_handler.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("lambda/upload_cat_image.zip")

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

resource "aws_lambda_function" "get_random_cat" {
  filename         = "lambda/get_random_cat.zip"
  function_name    = "get-random-cat"
  role             = aws_iam_role.lambda_role.arn
  handler          = "random_handler.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("lambda/get_random_cat.zip")

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "Cat Image API"
  description = "API for uploading and retrieving cat images"
  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

resource "aws_api_gateway_resource" "image" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "image"
}

resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_resource.image.id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_resource.image.id
  path_part   = "random"
}

resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "POST"
  authorization = "NONE"

  request_parameters = {
    "method.request.header.Content-Type" = true
  }
}

resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "upload_lambda" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload.id
  http_method = aws_api_gateway_method.upload_post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.upload_cat_image.invoke_arn
}

resource "aws_api_gateway_integration" "random_lambda" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.get_random_cat.invoke_arn
}

resource "aws_lambda_permission" "api_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_cat_image.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/POST/image/upload"
}

resource "aws_lambda_permission" "api_random" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_random_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/GET/image/random"
}

resource "aws_api_gateway_deployment" "cat_api_deployment" {
  depends_on = [
    aws_api_gateway_integration.upload_lambda,
    aws_api_gateway_integration.random_lambda
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}

output "api_endpoint" {
  value = "${aws_api_gateway_rest_api.cat_api.id}.execute-api.${var.aws_region}.amazonaws.com/prod/image"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_images.id
}

