# Step-by-step design:
# 1. We need an S3 bucket to store cat images (with encryption and versioning)
# 2. Lambda functions to handle:
#    - Uploading images (via API Gateway)
#    - Returning random images (via API Gateway)
# 3. API Gateway to expose REST endpoints
# 4. IAM roles for Lambda to access S3 and write logs
# 5. CloudWatch for logging

resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-images-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Cat Images Storage"
    Environment = "production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_iam_role" "lambda_role" {
  name = "cat-api-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "s3_access" {
  name = "lambda_s3_access"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      }
    ]
  })
}

