}

# Create S3 bucket to store cat images
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-image-bucket-${random_id.suffix.hex}"
  force_destroy = true

  versioning {
    enabled = false
  }

  # Block public access (API via Lambda only)
  block_public_acls        = true
  block_public_policy      = true
  ignore_public_acls       = true
  restrict_public_buckets  = true
}

# Enable S3 bucket encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Create DynamoDB table for image metadata
resource "aws_dynamodb_table" "cat_images" {
  name           = "cat-images"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }
}

# Generate random suffix for Lambda function name
resource "random_id" "suffix" {
  byte_length = 4
}

# Create IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "lambda-cat-image-role-${random_id.suffix.hex}"

  assume_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to Lambda role
resource "aws_iam_role_policy_attachment" "lambda_exec" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Create custom policy for S3 and DynamoDB access
resource "aws_iam_policy" "lambda_custom" {
  name = "lambda-cat-image-custom-policy-${random_id.suffix.hex}"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Scan"
        ]
        Resource = aws_dynamodb_table.cat_images.arn
      }
    ]
  })
}

# Attach custom policy to Lambda role
resource "aws_iam_role_policy_attachment" "lambda_custom" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = aws_iam_policy.lambda_custom.arn
}

# Lambda function that handles cat image upload and retrieval
# This uses a placeholder ZIP file - in practice, this would be generated via archive_file or similar
resource "aws_lambda_function" "cat_image_handler" {
  filename         = "lambda_function_deployment_package.zip"
  function_name    = "cat-image-handler-${random_id.suffix.hex}"
  role             = aws_iam_role.lambda_exec.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("lambda_function_deployment_package.zip") # In real use: data.archive_file.package.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
      TABLE_NAME  = aws_dynamodb_table.cat_images.name
    }
  }

  timeout = 30
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI"
  description = "API for uploading and retrieving random cat images"
}

# Resource for /cat
resource "aws_api_gateway_resource" "cat" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "cat"
}

# POST method for uploading a cat image
resource "aws_api_gateway_method" "post_cat" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.cat.id
  http_method   = "POST"
  authorization = "NONE"

  request_models = {
    "application/json" = "Empty"
  }

  request_parameters = {
    "method.request.header.Content-Type" = false
  }
}

# Integration of POST method with Lambda
resource "aws_api_gateway_integration" "post_cat_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.cat.id
  http_method             = aws_api_gateway_method.post_cat.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_image_handler.invoke_arn
}

# GET method for retrieving a random cat image
resource "aws_api_gateway_method" "get_cat" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.cat.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration of GET method with Lambda
resource "aws_api_gateway_integration" "get_cat_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.cat.id
  http_method             = aws_api_gateway_method.get_cat.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_image_handler.invoke_arn
}

# Deploy the API Gateway
resource "aws_api_gateway_deployment" "cat_api_deployment" {
  depends_on = [
    aws_api_gateway_method.post_cat,
    aws_api_gateway_method.get_cat,
    aws_api_gateway_integration.post_cat_integration,
    aws_api_gateway_integration.get_cat_integration
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}

# Grant API Gateway permission to invoke the Lambda function
resource "aws_lambda_permission" "apigw_post" {
  statement_id  = "AllowAPIGatewayInvokePost"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_image_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/POST/cat"
}

resource "aws_lambda_permission" "apigw_get" {
  statement_id  = "AllowAPIGatewayInvokeGet"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_image_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/GET/cat"
}

# Output the API endpoint URL
output "api_endpoint" {
  description = "The URL of the API Gateway endpoint"
  value       = "${aws_api_gateway_deployment.cat_api_deployment.invoke_url}/prod/cat"
}

# Output S3 bucket name
output "s3_bucket_name" {
  description = "The name of the S3 bucket used to store cat images"
  value       = aws_s3_bucket.cat_images.id
}

# Output DynamoDB table name
output "dynamodb_table_name" {
  description = "The name of the DynamoDB table storing image metadata"
  value       = aws_dynamodb_table.cat_images.name
}
```

