# We need to break down the request:
# 1. Create an EC2 instance.
# 2. Set up AWS Backup components:
#    - Backup Vault
#    - Backup Plan (with a rule to backup daily at 12:00 AM UTC)
#    - Backup Selection (to assign the EC2 instance to the plan)

# We'll use AWS provider
provider "aws" {
  region = "us-east-1"  # You can change region as needed
}

# Create a simple EC2 instance (adding tags for backup selection)
resource "aws_instance" "example" {
  ami           = "ami-0c02fb55956c7d316"  # Amazon Linux 2 in us-east-1
  instance_type = "t2.micro"

  tags = {
    Name = "Backup-Demo-Instance"
    Backup = "true"  # This tag will be used for backup selection
  }
}

# Create a Backup Vault
resource "aws_backup_vault" "backup_vault" {
  name = "daily-backup-vault"
}

# Create a Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-12am-backup-plan"

  rule {
    name              = "daily-backup-rule"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)"  # Daily at 12:00 AM UTC
    start_window      = 60  # Minutes
    completion_window = 120 # Minutes
    lifecycle {
      delete_after = 35  # Delete after 35 days
    }
  }
}

# Create a Backup Selection using tags to assign EC2 instance to the plan
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-backup-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }
}

# IAM role for AWS Backup to perform actions
resource "aws_iam_role" "backup_role" {
  name = "AWSBackupRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach managed policy for AWS Backup
resource "aws_iam_role_policy_attachment" "backup_policy_attach" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

