# Step-by-step breakdown:
# 1. Create an EC2 instance (needs VPC, subnet, IAM role, security group)
# 2. Set up AWS Backup:
#    - Create a Backup Vault
#    - Define a Backup Plan with a daily schedule at 12:00 AM
#    - Assign the EC2 instance to the Backup Selection
# 3. Use AWS Backup to automatically back up the EC2 instance daily

# We'll use default VPC and subnet for simplicity, but in production, use specific ones

provider "aws" {
  region = "us-east-1"
}

# Create a security group for EC2
resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = -1
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create an IAM role for EC2 to allow AWS Backup to manage backups
resource "aws_iam_role" "ec2_backup_role" {
  name = "ec2-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required AWS-managed policies to allow backup and CloudWatch
resource "aws_iam_role_policy_attachment" "backup_policy" {
  role       = aws_iam_role.ec2_backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonEC2RoleforAWSBackup"
}

# EC2 instance
resource "aws_instance" "backup_target" {
  ami           = "ami-0c02fb55956c7d316"  # Amazon Linux 2 in us-east-1
  instance_type = "t3.micro"
  security_groups = [aws_security_group.allow_ssh.name]
  iam_instance_profile = aws_iam_instance_profile.ec2_backup_profile.name
  tags = {
    Name = "backup-enabled-instance"
    Backup = "true"  # This tag will help assign to backup plan
  }
}

# IAM instance profile to attach role to EC2
resource "aws_iam_instance_profile" "ec2_backup_profile" {
  name = "ec2-backup-profile"
  role = aws_iam_role.ec2_backup_role.name
}

# AWS Backup Vault
resource "aws_backup_vault" "daily_vault" {
  name        = "daily-backup-vault"
  kms_key_arn = aws_kms_key.backup_kms.arn  # Optional: Encrypt backups
}

# KMS key for encrypting backups (optional but recommended)
resource "aws_kms_key" "backup_kms" {
  description             = "KMS key for AWS Backup"
  enable_key_rotation     = true
}

# Backup Plan: Daily at 12:00 AM
resource "aws_backup_plan" "daily_plan" {
  name = "daily-12am-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.daily_vault.name
    schedule          = "cron(0 0 * * ? *)"  # Daily at 12:00 AM UTC

    lifecycle {
      delete_after = 35  # Keep backups for 35 days before deletion
    }
  }
}

# Assign EC2 instance to backup plan using tags
resource "aws_backup_selection" "backup_selection" {
  iam_role_arn = aws_iam_role.ec2_backup_role.arn
  name         = "backup-selection-by-tag"
  plan_id      = aws_backup_plan.daily_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }
}

