    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)"  # Daily at 12:00 AM UTC
    start_window_minutes = 60
    completion_window_minutes = 180

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

resource "aws_security_group" "instance_sg" {
  name        = "instance_security_group"
  description = "Allow SSH and ICMP"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "backup_instance" {
  ami                    = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-west-2 - adjust based on region
  instance_type          = "t3.micro"
  key_name               = aws_key_pair.backup_key.key_name
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  tags = {
    Name = "backup-enabled-instance"
  }
}

resource "aws_backup_selection" "backup_selection" {
  name         = "backup-selection"
  iam_role_arn = aws_iam_role.backup_role.arn
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }
}

# Add a tag to the instance to match the backup selection
resource "aws_ec2_tag" "backup_tag" {
  resource_id = aws_instance.backup_instance.id
  key         = "Backup"
  value       = "true"
}

data "aws_caller_identity" "current" {}
```

