extracted_code:
# To set up a daily execution at 07:00 UTC using AWS EventBridge, we need:
# 1. An EventBridge Rule that triggers based on a schedule (cron expression)
# 2. A target for the rule — typically a Lambda function to execute
# 3. (Optional) IAM role and permissions for EventBridge to invoke the target

# Step 1: Create a Lambda function (as an example target)
# This is a minimal example — in practice, you'd include your actual code

resource "aws_lambda_function" "example" {
  filename      = "Hello World" Lambda function for demonstration
resource "aws_lambda_function" "example" {
  filename      = "lambda.zip"
  function_name = "daily-execution-function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  source_code_hash = filebase64sha256("lambda.zip")

  environment {
    variables = {
      NAME = "World"
    }
  }
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "lambda-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Step 2: Create EventBridge Rule with a cron expression for 07:00 UTC daily
resource "aws_cloudwatch_event_rule" "daily_0700_utc" {
  name                = "daily-0700-utc"
  description         = "Triggers daily at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"  # At 07:00 UTC every day
}

# Step 3: Set Lambda as target for the EventBridge rule
resource "aws_cloudwatch_event_target" "daily_target" {
  rule      = aws_cloudwatch_event_rule.daily_0700_utc.name
  target_id = "DailyLambdaTarget"
  arn       = aws_lambda_function.example.arn
}

# Step 4: Allow EventBridge to invoke the Lambda function
resource "aws_lambda_permission" "eventbridge_invoke" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example.function_name
  principal     = "events.amazonaws.com"
  source_arn  = aws_cloudwatch_event_rule.daily_0700_utc.arn
  source_account = var.aws_account_id
}

# Optional: Output the rule name for reference
output "eventbridge_rule_name" {
  value = aws_cloudwatch_event_rule.daily_0700_utc.name
}

# Note: Ensure the lambda.zip file exists or adjust with appropriate source.

