# This Terraform configuration creates a daily scheduled AWS Lambda function
# using Amazon EventBridge (formerly CloudWatch Events) to trigger the function
# at 07:00 UTC every day.

# Steps:
# 1. Create an AWS Lambda function that contains the code to be executed
# 2. Create an IAM role and policy that grants necessary permissions for Lambda execution
# 3. Create an EventBridge rule that triggers daily at 07:00 UTC
# 4. Create a target that connects the EventBridge rule to the Lambda function
# 5. Add Lambda permission to allow EventBridge to invoke the Lambda function

resource "aws_iam_role" "lambda_role" {
  name = "lambda-eventbridge-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_role.name
}

resource "aws_lambda_function" "scheduled_function" {
  filename      = "lambda_function.zip"  # This should point to your deployment package
  function_name = "daily-scheduled-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  # Example environment variables (can be customized)
  environment {
    variables = {
      EXECUTION_TIME = "07:00 UTC"
    }
  }

  # Set source code - in practice, this would be a base64-encoded zip or S3 reference
  source_code_hash = filebase64sha256("lambda_function.zip")

  # Optional: Set timeout and memory
  timeout = 300
  memory_size = 128
}

