# Designing a globally distributed video streaming platform using Amazon S3 for content storage and AWS CloudFront for delivery.

# Step 1: Create an S3 bucket to store video content
# - The bucket will be versioned for content durability
# - Block public access by default, but allow CloudFront to access via origin access control (OAC)
# - Enable server-side encryption for security

# Step 2: Configure AWS CloudFront distribution
# - Use the S3 bucket as the origin
# - Use Origin Access Control (OAC) for secure access
# - Enable HTTPS with AWS-managed SSL certificate
# - Set up caching behaviors optimized for video streaming (range requests, TTLs)
# - Enable logging for monitoring access

# Step 3: Enable logging and monitoring
# - Enable access logs for CloudFront in another S3 bucket
# - Use a separate logging bucket to maintain separation of concerns

# Final infrastructure layout:
# - 1x S3 bucket for video content (e.g., "video-streaming-content-<random>")
# - 1x S3 bucket for CloudFront access logs
# - 1x CloudFront distribution with secure OAC and HTTPS

resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# S3 bucket for video content
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-content-${random_string.suffix.result}"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  block_public_access {
    block_public_acls       = true
    block_public_policy     = true
    ignore_public_acls      = true
    restrict_public_buckets = true
  }

  tags = {
    Name        = "Video Content Bucket"
    Environment = "production"
    Purpose     = "Video streaming storage"
  }
}

# S3 bucket for CloudFront access logs
resource "aws_s3_bucket" "cloudfront_logs" {
  bucket = "video-streaming-logs-${random_string.suffix.result}"

  block_public_access {
    block_public_acls       = true
    block_public_policy     = true
    ignore_public_acls      = true
    restrict_public_buckets = true
  }

  tags = {
    Name        = "CloudFront Access Logs"
    Environment = "production"
    Purpose     = "Store CloudFront access logs"
  }
}

# Origin Access Control for secure S3 access
resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "video-s3-oac"
  description                       = "OAC for secure S3 origin access"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_identity = ""
    }

    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
  }

  enabled             = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"
  http_version        = "http2"

  # Default cache behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]

    # Use managed cache policy for media content
    cache_policy_id      = "658327ea-f89d-4fab-a63d-7e88639e58f6" # Managed-CachingOptimizedForVideo
    origin_request_policy_id = "b68967e7-5c5b-4194-a94e-7b32f1e78ba4" # Managed-CORS-S3Origin
    response_headers_policy_id = "67f7725c-6f97-4210-82d7-5512b31e9d03" # Managed-SecurityHeadersPolicy

    target_origin_id       = "S3-${aws_s3_bucket.video_content.id}"
    viewer_protocol_policy = "redirect-to-https"
  }

  # Cache policy can support range requests for video playback (seeking)
  cache_policy {
    name                = "video-range-policy"
    min_ttl             = 0
    default_ttl         = 86400
    max_ttl             = 31536000
    comment             = "Cache policy for video streaming with range support"
    enable_accept_encoding_gzip = true
    enable_accept_encoding_brotli = true

    parameters_in_cache_key_and_forwarded_to_origin {
      query_string {
        query_string_behavior = "none"
      }

      headers {
        headers_behaviour = "none"
      }

      cookies {
        cookie_behavior = "none"
      }
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  # Enable logging
  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.cloudfront_logs.bucket_domain_name
    prefix          = "logs/"
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  tags = {
    Name        = "Video Streaming Distribution"
    Environment = "production"
    Purpose     = "Deliver video content globally"
  }
}

# Output the CloudFront URL for access
output "streaming_url" {
  description = "URL of the CloudFront distribution for video streaming"
  value       = "https://${aws_cloudfront_distribution.video_distribution.domain_name}"
}

output "content_bucket_name" {
  description = "Name of the S3 bucket to upload video content"
  value       = aws_s3_bucket.video_content.bucket
}

