```hcl
# Designing a globally distributed video streaming platform using Amazon S3 for content storage and AWS CloudFront for delivery.

# Step 1: Create an S3 bucket to store video content
# - The bucket will be versioned for content durability
# - Block public access by default, but allow CloudFront to access via origin access control (OAC)
# - Enable server-side encryption for security

# Step 2: Configure AWS CloudFront distribution
# - Use the S3 bucket as the origin
# - Use Origin Access Control (OAC) for secure access
# - Enable HTTPS with AWS-managed SSL certificate
# - Set up caching behaviors optimized for video streaming (range requests, TTLs)
# - Enable logging for monitoring access

# Step 3: Enable logging and monitoring
# - Enable access logs for CloudFront in another S3 bucket
# - Use a separate logging bucket to maintain separation of concerns

# Final infrastructure layout:
# - 1x S3 bucket for video content (e.g., "video-streaming-content-<random>")
# - 1x S3 bucket for CloudFront access logs
# - 1x CloudFront distribution with secure OAC and HTTPS

resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# S3 bucket for video content
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-content-${random_string.suffix.result}"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  block_public_access {
    block_public_acls       = true
    block_public_policy     = true
    ignore_public_acls      = true
    restrict_public_buckets = true
  }

  tags = {
    Name        = "Video Content Bucket"
    Environment = "production"
    Purpose     = "Video streaming storage"
  }
}

# S3 bucket for CloudFront access logs
resource "aws_s3_bucket" "cloudfront_logs" {
  bucket = "video-streaming-logs-${random_string.suffix.result}"

  block_public_access {
    block_public_acls       = true
    block_public_policy     = true
    ignore_public_acls      = true
    restrict_public_buckets = true
  }

  tags = {
    Name        = "CloudFront Access Logs"
    Environment = "production"
    Purpose     = "Store CloudFront access logs"
  }
}

# Origin Access Control for secure S3 access
resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "video-s3-oac"
  description                       = "OAC for secure S3 origin access"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
