    cache_policy_id      = "658327ea-f89d-4fab-a63d-7e88639e58f6" # Managed-CachingOptimizedForVideo
    origin_request_policy_id = "b68967e7-5c5b-4194-a94e-7b32f1e78ba4" # Managed-CORS-S3Origin
    response_headers_policy_id = "67f7725c-6f97-4210-82d7-5512b31e9d03" # Managed-SecurityHeadersPolicy

    target_origin_id       = "S3-${aws_s3_bucket.video_content.id}"
    viewer_protocol_policy = "redirect-to-https"
  }

  # Cache policy can support range requests for video playback (seeking)
  cache_policy {
    name                = "video-range-policy"
    min_ttl             = 0
    default_ttl         = 86400
    max_ttl             = 31536000
    comment             = "Cache policy for video streaming with range support"
    enable_accept_encoding_gzip = true
    enable_accept_encoding_brotli = true

    parameters_in_cache_key_and_forwarded_to_origin {
      query_string {
        query_string_behavior = "none"
      }

      headers {
        headers_behaviour = "none"
      }

      cookies {
        cookie_behavior = "none"
      }
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  # Enable logging
