extracted_code:
# Designing a globally distributed architecture for a video streaming platform using AWS
# Components:
# - S3 bucket to store video content (as static objects)
# - CloudFront distribution to cache and deliver content globally with low latency
# - Route 53 for DNS management with a custom domain and health checks
# - Optional: AWS WAF to protect against common web exploits
# - Optional: ACM for SSL/TLS certificate management
# - Optional: CloudWatch for monitoring and logging

provider "aws" {
  region = "us-east-1" # Required for some global resources like ACM and Route 53
}

# ----------------------------
# S3 Bucket for Video Content
# ----------------------------
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-platform-content"

  # Enable versioning for content protection
  versioning {
    enabled = true
  }

  # Enable server-side encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Block public ACLs and policy enforcement
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Make bucket publicly readable via policy (for CloudFront access only)
resource "aws_s3_bucket_policy" "allow_cloudfront" {
  bucket = aws_s3_bucket.video_content.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "cloudfront.amazonaws.com"
        },
        Action = "s3:GetObject",
        Resource = "${aws_s3_bucket.video_content.arn}/*",
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.streaming_distribution.arn
          }
        }
      }
    ]
  })
}

# ----------------------------
# ACM Certificate for HTTPS
# ----------------------------
resource "aws_acm_certificate" "cloudfront_cert" {
  domain_name       = "*.example.com" # Replace with customer's domain
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

# ----------------------------
# CloudFront Distribution
# ----------------------------
resource "aws_cloudfront_distribution" "streaming_distribution" {
  enabled             = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"

  # Use ACM certificate (must be in us-east-1)
  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate.cloudfront_cert.arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  # Origins
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-video-origin"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  # Default cache behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-origin"

    # Use managed cache policy for media streaming
    # Using managed policy for general static content (can be customized)
    cache_policy_id    = "658327ea-f89d-4fab-a63d-7e88639e58f6" # Managed-CachingOptimized
    origin_request_policy_id = "be94b09b-078d-4258-97ff-346fb4fc772e" # Managed-CORS-S3Origin
    viewer_protocol_policy = "redirect-to-https"
  }

  # Cache policy for video files (optional custom policy)
  # Can be added if specific TTL or query string handling is needed

  # Customize error responses
  custom_error_response {
    error_code         = 404
    response_code      = 404
    response_page_path = "/404.html"
  }

  # Logging to S3
  logging_config {
    include_cookies = false
    bucket          = "${aws_s3_bucket.video_content.bucket}.s3.amazonaws.com"
    prefix          = "cloudfront-logs/"
  }

  # Restrict viewing of origin content
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # Price class (optional: use PriceClass_All for global reach)
  price_class = "PriceClass_All"

  # Enable IPV6
  is_ipv6_enabled = true
}

# Origin Access Identity for secure S3 access
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for S3 bucket access via CloudFront"
}

# Update S3 bucket policy to allow OAI access
# Already included in aws_s3_bucket_policy above

# ----------------------------
# Route 53 Setup
# ----------------------------
# Replace with actual domain name
data "aws_route53_zone" "primary" {
  name = "example.com." # Replace with client domain
}

# DNS record for streaming platform
resource "aws_route53_record" "www" {
  zone_id = data.aws_route53_zone.primary.zone_id
  name    = "stream.example.com" # Subdomain for streaming
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.streaming_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.streaming_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

# Add CNAME for certificate validation if needed
# This would typically require manual or automated DNS validation
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for d in aws_acm_certificate.cloudfront_cert.domain_validation_options : d.domain_name => d
    if d.domain_name == "*.example.com"
  }

  zone_id = data.aws_route53_zone.primary.zone_id
  name    = each.value.resource_record_name
  type    = each.value.resource_record_type
  records = [each.value.resource_record_value]
  ttl     = 60
}

# ----------------------------
# Optional: AWS WAF Web ACL
# ----------------------------
resource "aws_wafv2_web_acl" "streaming_acl" {
  name  = "streaming-platform-acl"
  scope = "CLOUDFRONT"

  default_action {
    allow {}
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "StreamingAclMetrics"
    sampled_requests_enabled   = true
  }

  # AWS Managed rule: Common Exploits
  rule {
    name     = "AWSManagedRulesCommonRuleSet"
    priority = 1

    override_action {
      none {}
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "AWSManagedRulesCommonRuleSet"
      sampled_requests_enabled   = true
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesCommonRuleSet"
        vendor_name = "AWS"
      }
    }
  }

  # Rate-based rule to prevent DDoS
  rule {
    name     = "RateLimitRequests"
    priority = 2

    action {
      block {}
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "RateLimit"
      sampled_requests_enabled   = true
    }

    statement {
      rate_based_statement {
        limit = 10000 # 10,000 requests per 5 minutes from an IP
        aggregate_key_type = "IP"
      }
    }
  }
}

# Associate WAF with CloudFront
resource "aws_wafv2_web_acl_association" "streaming_association" {
  web_acl_arn = aws_wafv2_web_acl.streaming_acl.arn
  resource_arn = aws_cloudfront_distribution.streaming_distribution.arn
}

# ----------------------------
# CloudWatch Alarms (Optional)
# ----------------------------
resource "aws_cloudwatch_log_group" "cloudfront_logs" {
  name              = "/aws/cloudfront/video-streaming-distribution"
  retention_in_days = 30
}

# Outputs
output "cloudfront_domain" {
  value = aws_cloudfront_distribution.streaming_distribution.domain_name
  description = "CloudFront domain name for video streaming"
}

output "s3_bucket" {
  value = aws_s3_bucket.video_content.bucket
  description = "S3 bucket name for video content"
}

output "streaming_url" {
  value = "https://stream.example.com"
  description = "Public URL for the video streaming platform"
}

