# Global video streaming platform infrastructure on AWS
# Components:
# - S3 bucket to store video content (with versioning and encryption)
# - CloudFront Origin Access Control (OAC) for secure S3 origin access
# - CloudFront distribution with optimized settings for video streaming
# - Route 53 hosted zone for custom domain (if provided, uses a placeholder)
# - Alias record to route domain to CloudFront distribution
# - Bucket policy allowing CloudFront OAC to access content
# - Optional: Default index and error pages for web streaming interface

resource "aws_s3_bucket" "video_content" {
  bucket_prefix = "video-streaming-platform-"
  force_destroy = false # Ensure manual deletion to prevent accidental data loss

  # Enable versioning for content integrity
  versioning {
    enabled = true
  }

  # Server-side encryption for at-rest data
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Block public ACLs and policies unless set through this configuration
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  tags = {
    Name        = "Video Streaming Content Bucket"
    Environment = "production"
    Project     = "VideoStreamingPlatform"
  }
}

resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "video-streaming-oac"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution for global content delivery
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
    }
  }

  enabled             = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"
  default_cache_behavior {
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"
    compressible_content_types = [
      "text/html",
      "text/css",
      "text/javascript",
      "application/javascript",
      "application/json",
      "font/woff",
      "font/woff2",
      "image/svg+xml",
      "video/mp4",
      "video/webm"
    ]
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    viewer_protocol_policy = "redirect-to-https"
    cache_policy_id  = "658327ea-f89d-4fab-a63d-7e88639e58f6" # Managed - CachingOptimized
    origin_request_policy_id = "b689261d-4390-45f1-9c47-04b272a7930c" # Managed - CORS-S3Origin
    function_association {
      eventType = "viewer-request"
      function_arn = aws_cloudfront_function.url_rewrite.arn
    }
  }

  # Cache behavior for video content (longer TTL)
  ordered_cache_behavior {
    path_pattern     = "videos/*"
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    viewer_protocol_policy = "redirect-to-https"
    cache_policy_id  = "4135ea2d-6df8-44a3-9df3-4b5a84be39ad" # Managed - CachingOptimizedForUncompressedObjects
    compress         = true
  }

  # Add logging to S3
  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.video_content.bucket_regional_domain_name
    prefix          = "cloudfront-logs/"
  }

  # Custom error responses for streaming
  custom_error_response {
    error_code         = 404
    response_code      = 404
    response_page_path = "/404.html"
  }

  # SSL/TLS settings
  viewer_certificate {
    cloudfront_default_certificate = true
  }

  # Restrict geographic access if needed
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  tags = {
    Name        = "Global Video Streaming Distribution"
    Environment = "production"
    Project     = "VideoStreamingPlatform"
  }
}

# CloudFront Function for URL rewriting (e.g., clean URLs)
resource "aws_cloudfront_function" "url_rewrite" {
  name    = "video-url-rewriter"
  runtime = "cloudfront-js-1.0"
  publish = true
  code = <<EOF
function handler(event) {
    var request = event.request;
    var uri = request.uri;

    // Rewrite /videos/123 to /videos/123/index.html if needed
    if (uri.startsWith('/videos/')) {
        if (!uri.endsWith('.mp4') && !uri.endsWith('.webm') && !uri.endsWith('.m3u8')) {
            request.uri += (uri.endsWith('/') ? 'index.html' : '/index.html');
        }
    }

    return request;
}
EOF
}

# Optional: Route 53 hosted zone and DNS record
# Replace 'example.com' with your actual domain
resource "aws_route53_zone" "hosted_zone" {
  name = "video-streaming-platform.com"
  tags = {
    Name = "Video Streaming Platform Hosted Zone"
  }
}

# Route 53 A record alias pointing to CloudFront distribution
