# main.tf - Terraform configuration for a scalable video streaming platform on AWS

# Providers
provider "aws" {
  region = "us-east-1"
}

# VPC Module (using Terraform AWS VPC module)
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.0.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24", "10.0.103.0/24"]

  enable_nat_gateway = true
  enable_vpn_gateway = false

  tags = {
    Environment = "production"
    Project     = "VideoStreamingPlatform"
  }
}

# Security Groups
resource "aws_security_group" "web_servers" {
  name        = "web-server-sg"
  description = "Security group for video streaming EC2 instances"
  vpc_id      = module.vpc.vpc_id

  # Allow HTTP and HTTPS from the internet
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH from trusted IPs (restrict in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Should be restricted, e.g., your IP
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web-server-sg"
  }
}

# EC2 Instances (Video Streaming Servers)
resource "aws_instance" "streaming_server" {
  count                   = 3
  ami                     = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-east-1
  instance_type           = "t3.large" # Suitable for media streaming
  subnet_id               = element(module.vpc.public_subnets, count.index)
  vpc_security_group_ids  = [aws_security_group.web_servers.id]
  associate_public_ip_address = true

  key_name = "your-key-pair" # Replace with your key pair

  user_data = <<-EOF
              #!/bin/bash
              sudo yum update -y
              sudo amazon-linux-extras install nginx1 -y
              sudo systemctl start nginx
              sudo systemctl enable nginx
              # Placeholder: Install streaming software (e.g., FFmpeg, Wowza, or custom app)
              # Configure Nginx as reverse proxy or static video host
              echo "<h1>Streaming Server $(expr ${count.index} + 1)</h1>" > /usr/share/nginx/html/index.html
              EOF

  tags = {
    Name = "streaming-server-${count.index}"
    Role = "video-server"
  }
}

# Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.web_servers.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = true

  tags = {
    Name = "StreamingALB"
  }
}

# Target Group
resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  target_type = "instance"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    protocol            = "HTTP"
    port                = "traffic-port"
    unhealthy_threshold = 3
    healthy_threshold   = 2
    timeout             = 5
    interval            = 15
  }
}

# Listener
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# Attach EC2 instances to Target Group
resource "aws_lb_target_group_attachment" "streaming_attachments" {
  count            = length(aws_instance.streaming_server[*].id)
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_server[count.index].id
  port             = 80
}

# Route 53 Hosted Zone and DNS Record
resource "aws_route53_zone" "streaming_domain" {
  name = "videostream.example.com" # Replace with your domain
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.streaming_domain.zone_id
  name    = "www.videostream.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_alb.dns_name
    zone_id                = aws_lb.streaming_alb.zone_id
    evaluate_target_health = true
  }
}

# CloudFront Distribution for Video Caching (Optional enhancement)
resource "aws_cloudfront_distribution" "streaming_cf" {
  origin {
    domain_name = aws_lb.streaming_alb.dns_name
    origin_id   = "ALBOrigin"

    custom_origin_config {
      http_port              = 80
      https_port             = 443
      origin_protocol_policy = "http-only"
      origin_ssl_protocols   = ["TLSv1.2"]
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "CloudFront for video streaming"
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "ALBOrigin"

    forward_cookie_policy = "none"
    query_string_policy   = "whitelist"
    query_string          = ["video"]

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Environment = "production"
    Project     = "VideoStreamingPlatform"
  }
}

# Outputs
output "vpc_id" {
  value = module.vpc.vpc_id
}

output "public_subnets" {
  value = module.vpc.public_subnets
}

output "alb_dns" {
  value = aws_lb.streaming_alb.dns_name
}

output "route53_zone" {
  value = aws_route53_zone.streaming_domain.name
}

output "cloudfront_url" {
  value = aws_cloudfront_distribution.streaming_cf.domain_name
}

