# Terraform configuration for a video streaming platform on AWS
# This setup includes a VPC with public and private subnets, EC2 instances behind a load balancer,
# Route 53 DNS, security groups, target groups, and all required networking components.

provider "aws" {
  region = "us-east-1"
}

# Create a VPC with CIDR block
resource "aws_vpc" "streaming_vpc" {
  cidr_block = "10.0.0.0/16"

  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "video-streaming-vpc"
  }
}

# Create public subnets for load balancer and NAT
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.streaming_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.streaming_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-2"
  }
}

# Create private subnets for EC2 instances
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.streaming_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.streaming_vpc.id
  cidr在玩家中
  cidr_block        = "10.0.4.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "private-subnet-2"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.streaming_vpc.id

  tags = {
    Name = "internet-gateway"
  }
}

# Public route table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.streaming_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate public subnets with public route table
resource "aws_route_table_association" "public_assoc_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_assoc_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Private route table with NAT (via EIP and NAT Gateway)
resource "aws_eip" "nat_eip" {
  vpc = true

  tags = {
    Name = "nat-eip"
  }
}

resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public_subnet_1.id

  tags = {
    Name = "nat-gateway"
  }

  depends_on = [aws_internet_gateway.igw]
}

resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.streaming_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

# Associate private subnets with private route table
resource "aws_route_table_association" "private_assoc_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private_rt.id
}

resource "aws_route_table_association" "private_assoc_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private_rt.id
}

# Security Group for Load Balancer (allow HTTP and HTTPS from anywhere)
resource "aws_security_group" "lb_sg" {
  name        = "load-balancer-security-group"
  description = "Allow HTTP/HTTPS inbound traffic"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "lb-security-group"
  }
}

# Security Group for EC2 Instances (allow HTTP from LB only)
resource "aws_security_group" "instance_sg" {
  name        = "instance-security-group"
  description = "Allow traffic from load balancer only"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_lb.app_lb.security_groups[0]]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "instance-security-group"
  }
}

# Create Target Group for Load Balancer
resource "aws_lb_target_group" "target_group" {
  name     = "streaming-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming_vpc.id

  health_check {
    path                = "/health"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }

  tags = {
    Name = "target-group"
  }
}

# Create Application Load Balancer
resource "aws_lb" "app_lb" {
  name               = "streaming-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  tags = {
    Name = "streaming-app-lb"
  }
}

# Listener for Load Balancer on port 80
resource "aws_lb_listener" "listener_http" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

# Launch Template for EC2 Instances
resource "aws_launch_template" "streaming_template" {
  name_prefix   = "streaming-instance-template-"
  image_id      = "ami-0abcdef1234567890" # Placeholder - replace with actual AMI for video streaming
  instance_type = "t3.medium"

  user_data = base64encode(<<EOF
              #!/bin/bash
              sudo apt-get update
              sudo apt-get install -y nginx
              echo "<h1>Video Streaming Server</h1>" | sudo tee /var/www/html/index.html
              sudo systemctl start nginx
              sudo systemctl enable nginx
  EOF
  )

  vpc_security_group_ids = [aws_security_group.instance_sg.id]
  key_name               = "your-key-pair-name" # Replace with your key pair

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "streaming-server"
    }
  }
}

# Auto Scaling Group for EC2 Instances across private subnets
resource "aws_autoscaling_group" "asg" {
  name = "streaming-asg"
  min_size  = 2
  max_size  = 10
  desired_capacity = 2

  vpc_zone_identifier = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]

  launch_template {
    id      = aws_launch_template.streaming_template.id
    version = "$$Latest"
  }

  target_group_arns = [aws_lb_target_group.target_group.arn]

  tag {
    key                 = "Name"
    value               = "streaming-server"
    propagate_at_launch = true
  }

  tags = [
    {
      key                 = "Name"
      value               = "streaming-server"
      propagate_at_launch = true
    }
  ]
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "streaming_zone" {
  name = "videostreaming.example.com" # Replace with your domain
}

# Route 53 Record pointing to Load Balancer
resource "aws_route53_record" "lb_record" {
  zone_id = aws_route53_zone.streaming_zone.zone_id
  name    = "www.videostreaming.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}

# Output values
output "vpc_id" {
  value = aws_vpc.streaming_vpc.id
}

output "load_balancer_dns" {
  value = aws_lb.app_lb.dns_name
}

output "hosted_zone_id" {
  value = aws_route53_zone.streaming_zone.zone_id
}

