  owners      = ["099720109477"] # Canonical

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-focal-20.04-amd64-server-*"]
  }
}

# Create EC2 instance
resource "aws_instance" "web_instance" {
  ami                    = data.aws_ami.ubuntu.id
  instance_type          = "t3.micro"
  vpc_security_group_ids = [aws_security_group.alb_sg.id]
  subnet_id              = aws_subnet.subnet_1.id

  tags = {
    Name = "web-server"
  }
}

# Attach EC2 instance to target group
resource "aws_lb_target_group_attachment" "attachment" {
  target_group_arn = aws_lb_target_group.tg.arn
  target_id        = aws_instance.web_instance.id
  port             = 80
}

# Create Route53 hosted zone
resource "aws_route53_zone" "primary" {
  name = "test-video-stream.com"
}

# Route53 alias record for IPv4 pointing to ALB
resource "aws_route53_record" "lb_ipv4" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "lb.test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}

# Route53 alias record for IPv6 pointing to ALB
resource "aws_route53_record" "lb_ipv6" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "lb.test-video-stream.com"
  type    = "AAAA"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}
