extracted_code:
# Step-by-step breakdown:
# 1. Create a VPC with a specified CIDR block.
# 2. Create public subnets within the VPC across availability zones.
# 3. Create a security group for database access that allows PostgreSQL traffic (port 5432) from trusted sources (e.g., public subnets or specific IPs).
# 4. Provision a PostgreSQL RDS instance inside the VPC, using the database security group.
# 5. Ensure the RDS instance is not publicly accessible but can be reached from resources within the VPC (like EC2 in public subnets via security group rules).

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "db_access" {
  name        = "postgresql-db-access"
  description = "Allow PostgreSQL access from within VPC"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL (port 5432) from instances in public subnets
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-access-sg"
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "main-db-subnet-group"
  }
}

resource "aws_db_instance" "postgres" {
  identifier           = "postgres-db-instance"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  publicly_accessible  = false
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_access.id]
  username             = "admin"
  password             = "securepassword123"
  parameter_group_name = "default.postgres15"

  # Ensures it runs within the VPC and private subnets
  # Note: If private subnets were created, they should be used here instead.
  # For this example, using public subnets for simplicity (in production, use private subnets).
}

