extracted_code:
# We'll create the following resources step-by-step:
# 1. A VPC with public subnets
# 2. An Internet Gateway (required for public subnets, though not used directly by RDS)
# 3. Public subnets (RDS doesn't need IGW but subnets are required)
# 4. A DB subnet group using the public subnets
# 5. A security group allowing PostgreSQL access (port 5432) from a specified source (e.g., another security group or CIDR)
# 6. A PostgreSQL RDS instance (5GB storage, PostgreSQL 17.1)

# Variables for flexibility
variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  default     = "10.0.0.0/16"
}

variable "public_subnets" {
  description = "List of public subnet CIDR blocks"
  default     = ["10.0.1.0/24", "10.0.2.0/24"]
}

variable "availability_zones" {
  description = "Availability zones for the subnets"
  default     = ["us-west-2a", "us-west-2b"]
}

variable "db_username" {
  description = "Master username for PostgreSQL"
  type        = string
  sensitive   = true
}

variable "db_password" {
  description = "Master password for PostgreSQL"
  type        = string
  sensitive   = true
}

variable "allowed_cidr" {
  description = "CIDR block allowed to access the database"
  default     = "0.0.0.0/0"
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Create Internet Gateway (required for public routing, though RDS will be internal)
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Create public subnets
resource "aws_subnet" "public" {
  count                   = length(var.public_subnets)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = var.public_subnets[count.index]
  availability_zone       = var.availability_zones[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# Create DB subnet group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  description = "Subnet group for PostgreSQL instance"

  tags = {
    Name = "db-subnet-group"
  }
}

# Create security group for PostgreSQL
resource "aws_security_group" "db_sg" {
  name        = "postgresql-security-group"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL from specified CIDR
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [var.allowed_cidr]
  }

  # Optional: restrict egress
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# Deploy PostgreSQL RDS instance
resource "aws_db_instance" "postgres" {
  identifier           = "my-postgres-db"
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro"  # Example instance; adjust as needed
  allocated_storage    = 5              # 5GB as requested
  storage_type         = "gp2"
  publicly_accessible  = false          # Inside VPC only
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  username = var.db_username
  password = var.db_password
  port     = 5432

  # Required parameters
  multi_az               = false
  backup_retention_period = 7
  skip_final_snapshot    = true  # Not recommended for production

  tags = {
    Name = "PostgreSQL-17.1"
  }
}

