resource "aws_security_group" "db_access" {
  name        = "dolphin-db-access-sg"
  description = "Allow PostgreSQL access from specific sources"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL traffic (port 5432) - modify source as needed
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust this to allow only trusted sources
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dolphin-db-access-sg"
  }
}

# Create DB subnet group
resource "aws_db_subnet_group" "default" {
  name       = "dolphin-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "dolphin-db-subnet-group"
  }
}

# Create PostgreSQL 17.1 RDS instance
resource "aws_db_instance" "dolphin_scheduler_db" {
  identifier           = "dolphinscheduler"
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro" # Default instance type
  storage_type         = "gp2"
  allocated_storage    = 5
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_access.id]
  skip_final_snapshot  = true
  username             = "postgres"
  password             = random_password.db_password.result
  publicly_accessible  = false

  # Apply backup retention (even if final snapshot is skipped)
  backup_retention_period = 7

  # Required when using username/password
  allow_major_version_upgrade = false
  auto_minor_version_upgrade  = true

  tags = {
