```hcl
# Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Create public subnets
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# Get availability zones for subnet distribution
data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for database access
resource "aws_security_group" "db_access" {
  name        = "dolphin-db-access-sg"
  description = "Allow PostgreSQL access from specific sources"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL traffic (port 5432) - modify source as needed
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust this to allow only trusted sources
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dolphin-db-access-sg"
  }
}

# Create DB subnet group
resource "aws_db_subnet_group" "default" {
  name       = "dolphin-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "dolphin-db-subnet-group"
  }
}

# Create PostgreSQL 17.1 RDS instance
resource "aws_db_instance" "dolphin_scheduler_db" {
  identifier           = "dolphinscheduler"
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro" # Default instance type
  storage_type         = "gp2"
  allocated_storage    = 5
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_access.id]
  skip_final_snapshot  = true
  username             = "postgres"
  password             = random_password.db_password.result
  publicly_accessible  = false

  # Apply backup retention (even if final snapshot is skipped)
  backup_retention_period = 7

  # Required when using username/password
  allow_major_version_upgrade = false
  auto_minor_version_upgrade  = true

  tags = {
    Name = "dolphinscheduler-db"
  }
}

# Generate random password for the database
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_%@"
}

# Outputs
output "vpc_id" {
  value = aws_vpc.main.id
}

output "db_endpoint" {
  value = aws_db_instance.dolphin_scheduler_db.endpoint
}

output "db_name" {
  value = "dolphinscheduler"
}

output "security_group_id" {
  value = aws_security_group.db_access.id
}
