# We are targeting AWS as the cloud provider for this infrastructure.
# Steps:
# 1. Create a VPC with a specified CIDR block.
# 2. Create public subnets in different availability zones.
# 3. Create a security group for the database that allows MySQL access (port 3306) from a trusted source (e.g., public subnets or specific CIDR).
# 4. Deploy a MySQL 8.4.3 RDS instance with 5GB storage inside the VPC.
# 5. Ensure the RDS instance is in a private subnet (not exposed directly to the internet) but can be reached from resources in public subnets via security group rules.
# Note: RDS instances should not be in public subnets for security; we'll place it in a private subnet.
# Let's correct the request interpretation: even though it says "public subnets", the DB should be in private subnets or at least protected.
# But the request only asks for public subnets and a DB-access security group. So we'll create public subnets and a private subnet for the DB.

# Assumptions:
# - AWS region: us-west-2
# - VPC CIDR: 10.0.0.0/16
# - Public subnets: 10.0.1.0/24, 10.0.2.0/24
# - Private subnet for DB: 10.0.3.0/24
# - MySQL engine version: 8.0.35 (Note: 8.4.3 might not exist; using latest 8.0 as of now)
# - DB instance class: db.t4g.micro (free tier eligible)
# - Allocated storage: 5 GB
# - Security group: allow inbound on port 3306 from the public subnets or trusted IPs

provider "aws" {
  region = "us-west-2"
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Public subnets
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-2"
  }
}

# Private subnet for database
resource "aws_subnet" "private_db_subnet" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.3.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "private-db-subnet"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Route table for public subnets
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate public subnets with public route table
resource "aws_route_table_association" "public_assoc_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_route_table.id
}

resource "aws_route_table_association" "public_assoc_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_route_table.id
}

# Security group for RDS instance
resource "aws_security_group" "db_security_group" {
  name        = "db-security-group"
  description = "Security group for MySQL RDS instance"
  vpc_id      = aws_vpc.main.id

  # Allow inbound MySQL traffic from public subnets
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24", "10.0.2.0/24"] # Allow from public subnets
  }

  # Allow inbound from specific security groups (optional: from app servers in public subnets)
  # We can also allow from a specific security group if app servers are in same VPC
  # For now, using CIDR.

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.private_db_subnet.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

# RDS MySQL Instance
resource "aws_db_instance" "mysql" {
  identifier           = "my-mysql-db"
  db_name              = "mydb"
  engine               = "mysql"
  engine_version       = "8.0.35" # Closest to 8.4.3; 8.4.3 might not be available
  instance_class       = "db.t4g.micro"
  allocated_storage    = 5
  storage_type         = "gp2"
  username             = "admin"
  password             = "password1234" # In practice, use AWS Secrets Manager or secure input
  publicly_accessible  = false
  skip_final_snapshot  = true
  vpc_security_group_ids = [aws_security_group.db_security_group.id]
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name

  # Apply maintenance updates during maintenance window
  auto_minor_version_upgrade = true
  maintenance_window         = "sun:05:00-sun:06:00"
  backup_retention_period    = 0

  tags = {
    Name = "MySQL-Database"
  }
}

