```hcl
# Step 1: Define required providers
provider "aws" {
  region = "us-west-2" # Can be adjusted as needed
}

# Step 2: Create a VPC (assuming no existing VPC is imported)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

# Step 3: Create subnets (private only) across multiple AZs
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-b"
  }
}

# Step 4: Create a subnet group for RDS using private subnets
resource "aws_db_subnet_group" "rds_subnets" {
  name       = "rds-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "rds-subnet-group"
  }
}

# Step 5: Create a security group allowing PostgreSQL access from internal sources
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow PostgreSQL access from within VPC"
  vpc_id      = aws_vpc.main.id

  # Only allow PostgreSQL (port 5432) from internal VPC CIDR
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  # Allow outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# Step 6: Create a KMS key for encrypting the RDS instance
resource "aws_kms_key" "rds_kms" {
  description             = "KMS key for RDS PostgreSQL encryption"
  enable_key_rotation     = true
  key_usage               = "ENCRYPT_DECRYPT"
  customer_master_key_spec = "SYMMETRIC_DEFAULT"

  tags = {
    Name = "rds-kms-key"
  }
}

# Step 7: Create a key alias for easier reference
resource "aws_kms_alias" "rds_kms_alias" {
  name          = "alias/rds-postgresql-key"
  target_key_id = aws_kms_key.rds_kms.key_id
}

# Step 8: Create a custom PostgreSQL parameter group
resource "aws_db_parameter_group" "pg_custom" {
  name        = "custom-postgresql-params"
  family      = "postgresql15" # Adjust as needed for version
  description = "Custom parameter group for PostgreSQL RDS"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  tags = {
    Name = "custom-postgresql-params"
  }
}

# Step 9: Create the RDS PostgreSQL instance with desired settings
resource "aws_db_instance" "postgres_rds" {
  identifier                  = "protected-postgres-instance"
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = "db.t3.medium"
  allocated_storage           = 100
  storage_type                = "gp3"
  db_subnet_group_name        = aws_db_subnet_group.rds_subnets.name
  vpc_security_group_ids      = [aws_security_group.rds_sg.id]
  db_parameter_group_name     = aws_db_parameter_group.pg_custom.name
  allow_major_version_upgrade = false
  auto_minor_version_upgrade  = true
  multi_az                    = true
  publicly_accessible         = false
  backup_retention_period     = 7
  final_snapshot_identifier   = "final-snapshot-before-deletion"

  # Enable storage encryption using customer-managed KMS key
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_kms.arn

  # Database credentials (in practice, use AWS Secrets Manager or similar)
  username = "postgresadmin"
  password = "SecurePass123!" # Should be fetched from secure source

  # Apply database name
  db_name = "myappdb"

  # Enable deletion protection
  delete_automated_backups = true
  deletion_protection      = true

  tags = {
    Name        = "ProtectedPostgreSQL-RDS"
    Environment = "production"
  }

  # Ensure dependencies are correctly ordered
  depends_on = [
    aws_kms_alias.rds_kms_alias,
    aws_db_subnet_group.rds_subnets
  ]
}
```

