```hcl
variable "vpc_id" {
  description = "The ID of the existing VPC where the RDS instance will be created"
  type        = string
}

variable "subnet_ids" {
  description = "A list of subnet IDs for the DB subnet group, spanning at least two availability zones"
  type        = list(string)
}

variable "db_name" {
  description = "The name of the PostgreSQL database"
  type        = string
  default     = "mydb"
}

variable "db_username" {
  description = "Username for the PostgreSQL database"
  type        = string
  default     = "postgres"
}

variable "db_password" {
  description = "Password for the PostgreSQL database user"
  type        = string
  sensitive   = true
}

variable "engine_version" {
  description = "PostgreSQL engine version (e.g., 15.4)"
  type        = string
  default     = "15.4"
}

variable "allocated_storage" {
  description = "Storage size in GB"
  type        = number
  default     = 20
}

variable "instance_type" {
  description = "DB instance class"
  type        = string
  default     = "db.t3.micro"
}

variable "backup_retention_days" {
  description = "Number of days to retain backups"
  type        = number
  default     = 7
}

# Create a KMS key for encrypting the RDS instance
resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for encrypting PostgreSQL RDS instance"
  enable_key_rotation     = true
  deletion_window_in_days = 30
}

# Create a DB subnet group using the provided subnets
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

# Create a custom parameter group for PostgreSQL
resource "aws_db_parameter_group" "postgres_parameter_group" {
  name   = "custom-postgres-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  tags = {
    Name = "Custom PostgreSQL Parameter Group"
  }
}

# Create a security group for the RDS instance
resource "aws_security_group" "rds_security_group" {
  name        = "postgres-rds-sg"
  description = "Allow PostgreSQL access from specific sources"
  vpc_id      = var.vpc_id

  # Allow PostgreSQL traffic (port 5432) from within the VPC or restrict to specific CIDRs
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust as needed for your VPC or specific allowed sources
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL RDS Security Group"
  }
}

# Create the RDS PostgreSQL instance
resource "aws_rds_cluster" "postgres_cluster" {
  cluster_identifier              = "protected-postgres-cluster"
  db_subnet_group_name            = aws_db_subnet_group.db_subnet_group.name
  db_parameter_group_name         = aws_db_parameter_group.postgres_parameter_group.name
  engine                          = "postgres"
  engine_version                  = var.engine_version
  master_username                 = var.db_username
  master_password                 = var.db_password
  database_name                   = var.db_name
  backup_retention_period         = var.backup_retention_days
  preferred_backup_window         = "03:00-04:00"
  preferred_maintenance_window    = "sun:04:00-sun:05:00"
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds_kms_key.arn
  skip_final_snapshot             = true  # Set to false in production and specify final_snapshot_identifier
  vpc_security_group_ids          = [aws_security_group.rds_security_group.id]
  storage_type                    = "gp2"
  allocated_storage               = var.allocated_storage
  db_cluster_instance_class       = var.instance_type
  multi_az                        = true
  apply_immediately               = true
  enable_performance_insights     = true
  performance_insights_kms_key_id = aws_kms_key.rds_kms_key.arn
  copy_tags_to_snapshot           = true

  tags = {
    Name        = "Protected PostgreSQL RDS Instance"
    Environment = "production"
  }
}

# Output the RDS endpoint
output "rds_endpoint" {
  description = "The connection endpoint for the RDS instance"
  value       = aws_rds_cluster.postgres_cluster.endpoint
}

output "rds_cluster_arn" {
  description = "ARN of the RDS cluster"
  value       = aws_rds_cluster.postgres_cluster.arn
}

output "kms_key_arn" {
  description = "ARN of the KMS key used for encryption"
  value       = aws_kms_key.rds_kms_key.arn
}
```

