# This configuration sets up a secure, highly available PostgreSQL RDS instance within a custom VPC
# with encryption, private subnet placement, custom parameter group, and strict access control.

resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for encrypting PostgreSQL RDS instance"
  enable_key_rotation     = true
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
      {
        "Effect": "Allow",
        "Principal": {
          "Service": "rds.amazonaws.com"
        },
        "Action": [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey",
          "kms:ReEncrypt*",
          "kms:DescribeKey"
        ],
        "Resource": "*"
      },
      {
        "Effect": "Allow",
        "Principal": {
          "AWS": "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        },
        "Action": [
          "kms:*"
        ],
        "Resource": "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# Assume VPC and subnets already exist; otherwise, they'd need to be created.
# Using existing VPC and private subnets. Replace with actual VPC and subnet IDs as needed.

resource "aws_security_group" "rds_postgresql" {
  name        = "rds-postgresql-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = var.vpc_id

  # Only allow connections from trusted sources (e.g. application servers)
  # Customize the CIDR blocks or source security groups as needed
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgresql-security-group"
  }
}

resource "aws_db_parameter_group" "postgresql_custom" {
  name        = "custom-postgresql-13"
  family      = "postgres13"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_statement"
    value = "all"
  }

  parameter {
    name  = "rds.log_retention_period"
    value = "1440" # 1 day in minutes
  }

  tags = {
    Name = "custom-postgresql-parameter-group"
  }
}

resource "aws_db_subnet_group" "postgresql_subnets" {
  name       = "postgresql-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "postgresql-subnet-group"
  }
}

resource "aws_db_instance" "postgresql_instance" {
  identifier                  = "protected-postgresql-db"
  engine                      = "postgres"
  engine_version              = "13.16"
  instance_class              = "db.t3.micro"
  allocated_storage           = 20
  storage_type                = "gp2"
  db_name                     = "mydb"
  username                    = var.db_username
  password                    = var.db_password
  db_subnet_group_name        = aws_db_subnet_group.postgresql_subnets.name
  vpc_security_group_ids      = [aws_security_group.rds_postgresql.id]
  publicly_accessible         = false
  multi_az                    = true
  storage_encrypted           = true
  kms_key_id                  = aws_kms_key.rds_kms_key.arn
  backup_retention_period     = 7
  skip_final_snapshot         = false
  final_snapshot_identifier   = "pgsnapshot"
  parameter_group_name        = aws_db_parameter_group.postgresql_custom.name
  apply_immediately           = false
  auto_minor_version_upgrade  = true
  maintenance_window          = "sun:05:00-sun:06:00"
  backup_window               = "04:00-05:00"

  tags = {
    Name = "Protected PostgreSQL RDS Instance"
    Environment = "production"
  }
}

# Input variables used in the configuration
variable "vpc_id" {
  description = "The ID of the VPC where the RDS instance will be deployed"
  type        = string
}

variable "private_subnet_ids" {
  description = "A list of private subnet IDs for the DB subnet group"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks allowed to access the PostgreSQL instance"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

variable "db_username" {
  description = "Master username for the PostgreSQL instance"
  type        = string
  sensitive   = true
}

variable "db_password" {
  description = "Master password for the PostgreSQL instance"
  type        = string
  sensitive   = true
}

# Output the RDS endpoint for application connectivity
output "rds_endpoint" {
  description = "The connection endpoint for the PostgreSQL RDS instance"
  value       = aws_db_instance.postgresql_instance.endpoint
}

output "rds_instance_id" {
  description = "The instance identifier of the PostgreSQL RDS instance"
  value       = aws_db_instance.postgresql_instance.id
}

output "kms_key_arn" {
  description = "ARN of the KMS key used for encryption"
  value       = aws_kms_key.rds_kms_key.arn
}

