# Step 1: Define the primary VPC with a CIDR block
# Step 2: Create two subnets in different availability zones within the VPC
# Step 3: Create a security group that allows inbound MySQL traffic (port 3306)
# Step 4: Deploy a MySQL RDS instance in a multi-AZ setup, associated with the subnets and security group
# Step 5: Ensure the RDS is publicly accessible
# Step 6: Output the database endpoint for connection

provider "aws" {
  region = "us-west-2"  # Default region; can be adjusted as needed
}

resource "aws_vpc" "primary" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "primary-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.primary.id
  cidr_block             = "10.0.1.0/24"
  availability_zone      = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.primary.id
  cidr_block             = "10.0.2.0/24"
  availability_zone      = "us-west-2b"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-b"
  }
}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "db-subnet-group"
  }
}

resource "aws_security_group" "db_security_group" {
  name        = "allow-mysql-inbound"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Allow from any IP; restrict in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

resource "aws_db_instance" "mysql_instance" {
  identifier             = "public-mysql-db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  publicly_accessible    = true
  multi_az               = true  # High availability across AZs
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_security_group.id]
  username               = "admin"
  password               = "securepassword123"  # In practice, use AWS Secrets Manager or Terraform Vault
  skip_final_snapshot    = true  # Not recommended for production

  tags = {
    Name = "Public MySQL RDS"
  }
}

output "database_endpoint" {
  description = "The connection endpoint for the MySQL database"
  value       = aws_db_instance.mysql_instance.endpoint
}

