# Create a VPC for the RDS instance
resource "aws_vpc" "primary" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "primary-vpc"
  }
}

# Create two subnets in separate availability zones
resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.primary.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.primary.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "subnet-b"
  }
}

# Create a DB subnet group using the two subnets
resource "aws_db_subnet_group" "example" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

# Create a security group to allow database traffic
resource "aws_security_group" "db_security_group" {
  name        = "allow-mysql-traffic"
  description = "Allow MySQL traffic"
  vpc_id      = aws_vpc.primary.id

  # Ingress rule to allow MySQL traffic (port 3306)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Allows public access; restrict in production
  }

  # Egress rule to allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# Deploy a publicly accessible MySQL 5.7 RDS instance
resource "aws_db_instance" "mysql_instance" {
  identifier              = "public-mysql-db"
  engine                  = "mysql"
  engine_version          = "5.7"
