  db_subnet_group_name    = aws_db_subnet_group.example.name
  vpc_security_group_ids  = [aws_security_group.db_security_group.id]
  username                = "admin"         # Replace with secure value via variables
  password                = "securepassword123"  # Use AWS SSM Parameter or secret manager in production
  publicly_accessible     = true            # Publicly accessible
  skip_final_snapshot     = true            # Skip final snapshot (not for production)
  multi_az                = false           # Disable multi-AZ for now (can be enabled)

  # Apply deletion protection in production
  deletion_protection = false
}

# Output the database endpoint for connection
output "db_endpoint" {
  description = "The connection endpoint of the RDS MySQL instance"
  value       = aws_db_instance.mysql_instance.endpoint
}

output "db_address" {
  description = "The hostname of the RDS instance"
  value       = aws_db_instance.mysql_instance.address
}

output "db_port" {
  description = "The port number of the RDS instance"
  value       = aws_db_instance.mysql_instance.port
}
