# Step 1: Define the primary VPC with a CIDR block
# Step 2: Create two subnets in different Availability Zones within the VPC
# Step 3: Create a security group that allows inbound PostgreSQL traffic (port 5432)
# Step 4: Create a publicly accessible RDS PostgreSQL instance with version 15.3 and 20 GB storage
# Step 5: Associate the RDS instance with the subnets via a DB subnet group and apply the security group
# Step 6: Output the RDS endpoint for connectivity

resource "aws_vpc" "primary" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "primary-vpc"
  }
}

resource "aws_subnet" "subnet_az1" {
  vpc_id                  = aws_vpc.primary.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id                  = aws_vpc.primary.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-az2"
  }
}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

resource "aws_security_group" "db_security_group" {
  name        = "allow-postgresql"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Allow from any IP; adjust for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

resource "aws_db_instance" "postgres_instance" {
  identifier                   = "postgres-public-db"
  engine                       = "postgres"
  engine_version               = "15.3"
  instance_class               = "db.t3.micro"
  allocated_storage            = 20
  storage_type                 = "gp2"
  username                     = "dbadmin"
  password                     = "securepass123!"
  publicly_accessible          = true
  vpc_security_group_ids       = [aws_security_group.db_security_group.id]
  db_subnet_group_name         = aws_db_subnet_group.db_subnet_group.name
  multi_az                     = true
  skip_final_snapshot          = true
  apply_immediately            = true

  # Recommended to use a parameter group if customization is needed
  # parameter_group_name = "default.postgres15"

  tags = {
    Name = "PostgreSQL-Instance"
  }
}

output "rds_endpoint" {
  description = "The connection endpoint for the PostgreSQL RDS instance"
  value       = aws_db_instance.postgres_instance.endpoint
}

output "rds_address" {
  description = "The address of the RDS instance"
  value       = aws_db_instance.postgres_instance.address
}

output "rds_port" {
  description = "The port number of the RDS instance"
  value       = aws_db_instance.postgres_instance.port
}

