# Create two subnets in separate Availability Zones
resource "aws_subnet" "subnet_az1" {
  vpc_id            = aws_vpc.primary.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id            = aws_vpc.primary.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "subnet-az2"
  }
}

# Create a subnet group for RDS
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]

  tags = {
    Name = "rds-subnet-group"
  }
}

# Create a security group to allow PostgreSQL traffic (port 5432)
resource "aws_security_group" "rds_security_group" {
  name        = "rds-security-group"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Allow from any IPv4 address (public access)
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# Deploy a publicly accessible PostgreSQL 15.3 RDS instance
resource "aws_db_instance" "postgres_instance" {
  identifier               = "postgres-15-3-instance"
  engine                   = "postgres"
  engine_version           = "15.3"
  instance_class           = "db.t4g.micro"
  allocated_storage        = 200
  storage_type             = "gp2"
  db_subnet_group_name     = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids   = [aws_security_group.rds_security_group.id]
  publicly_accessible      = true
  multi_az                 = false  # Single AZ as only two subnets are required

  # Database authentication
  username                 = "admin"
  password                 = random_password.db_password.result
  # Note: In production, use proper secret management instead of random_password

  # Backup and maintenance (optional but recommended)
  backup_retention_period = 7
  deletion_protection     = false  # Set to true in production

  skip_final_snapshot     = true  # For testing; set to false and define final_snapshot_identifier in production
}

# Generate a random password for the RDS instance
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Output the RDS endpoint for connection
output "rds_endpoint" {
  value = aws_db_instance.postgres_instance.endpoint
}

output "rds_instance_arn" {
  value = aws_db_instance.postgres_instance.arn
}

output "security_group_id" {
  value = aws_security_group.rds_security_group.id
}

