# This Terraform configuration provisions an AWS PostgreSQL RDS instance with the following features:
# - PostgreSQL engine version 14 (current stable version as of recent)
# - DB instance class: db.t3.micro (suitable for small databases)
# - Initial storage: 5 GB, with auto-scaling up to 50 GB
# - Custom VPC and subnet group for network isolation
# - Maintenance window set for Monday from 00:00 to 03:00 UTC
# - Includes security group to allow PostgreSQL access (port 5432)

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "rds_subnet" {
  count             = 2
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
  vpc_id            = aws_vpc.main.id

  tags = {
    Name = "rds-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = aws_subnet.rds_subnet[*].id

  tags = {
    Name = "rds-subnet-group"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds_security_group"
  description = "Allow PostgreSQL access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Allow within VPC
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

resource "aws_db_instance" "postgres" {
  identifier_prefix               = "postgres-db-"
  engine                          = "postgres"
  engine_version                  = "14.12"
  instance_class                  = "db.t3.micro"
  allocated_storage               = 5
  max_allocated_storage           = 50
  storage_type                    = "gp3"
  db_name                         = "mydb"
  username                        = "admin"
  password                        = "password12345"  # In practice, use AWS Secrets Manager or TF variables
  db_subnet_group_name            = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.rds_sg.id]
  port                            = 5432
  publicly_accessible             = false
  maintenance_window              = "mon:00:00-mon:03:00"
  backup_retention_period         = 7
  apply_immediately               = true
  auto_minor_version_upgrade      = true
  multi_az                        = false  # Set to true for production
