data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id

  tags = {
    Name = "postgres-subnet-group"
  }
}

resource "aws_security_group" "db_security_group" {
  name        = "postgres-db-sg"
  description = "Allow PostgreSQL access from within VPC"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.custom_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-db-security-group"
  }
}

resource "aws_db_instance" "postgres_instance" {
  identifier_prefix               = "postgres-private-db"
  engine                          = "postgres"
  engine_version                  = "15.4" # Example of a recent PostgreSQL release; adjust as needed
  instance_class                  = "db.t3.micro"
  allocated_storage               = 20
  storage_encrypted               = true
  db_subnet_group_name            = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.db_security_group.id]
  publicly_accessible             = false
  allow_major_version_upgrade     = true
  auto_minor_version_upgrade      = true
  multi_az                        = false
  skip_final_snapshot             = true
  apply_immediately               = true
  backup_retention_period         = 7
  parameter_group_name            = "default.postgres15" # Adjust if using a custom parameter group

  # Sensitive credentials should typically be managed via AWS Secrets Manager or similar
  # For example purposes only - avoid hardcoding in production
  username = "dbadmin"
  password = "securepassword123"
  db_name  = "mydatabase"
}

