# Create a VPC for the Aurora MySQL cluster
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create subnets for the Aurora cluster (at least two subnets in different AZs)
resource "aws_subnet" "aurora_subnet_1" {
  vpc_id            = aws_vpc.aurora_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "aurora-subnet-1"
  }
}

resource "aws_subnet" "aurora_subnet_2" {
  vpc_id            = aws_vpc.aurora_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "aurora-subnet-2"
  }
}

# Create a DB subnet group for the Aurora cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Create security group for the Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-cluster-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-cluster-sg"
  }
}

# Create security group for the RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.aurora_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Create IAM role for RDS Proxy to access Secrets Manager
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to IAM role to allow access to Secrets Manager
resource "aws_iam_role_policy_attachment" "rds_proxy_secrets_access" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/SecretsManagerReadWrite"
}

# Generate secure database credentials
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!@#$%&*"
}

# Store database credentials in AWS Secrets Manager
resource "aws_secretsmanager_secret" "db_secret" {
  name = "aurora-mysql-credentials"
}

resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Create Aurora MySQL cluster
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier              = "aurora-mysql-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "8.0.mysql_aurora.3.04.0"
  master_username                 = "admin"
  master_password                 = random_password.db_password.result
  db_subnet_group_name            = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.aurora_sg.id]
  skip_final_snapshot             = true
  backup_retention_period         = 7
  preferred_backup_window         = "03:00-04:00"
  preferred_maintenance_window    = "sun:05:00-sun:06:00"
  deletion_protection             = false
  apply_immediately               = true
  enabled_cloudwatch_logs_exports = ["error", "slowquery", "general", "audit"]
}

# Add an instance to the cluster
resource "aws_rds_cluster_instance" "cluster_instances" {
  count               = 1
  identifier          = "aurora-instance-${count.index}"
  cluster_identifier  = aws_rds_cluster.aurora_cluster.id
  instance_class      = "db.r6g.large"
  engine              = aws_rds_cluster.aurora_cluster.engine
  engine_version      = aws_rds_cluster.aurora_cluster.engine_version
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
  publicly_accessible = false
}

# Create RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  db_proxy_target_group {
    connection_pool_configuration {
      max_connections_percent          = 100
      max_idle_connections_percent     = 50
      connection_borrow_timeout        = 120
      init_query                       = ""
      max_db_connections               = 100
      session_pinning_filters          = []
      idle_client_timeout              = 1800  # 30 minutes
      cleanup_connections_enabled      = false
    }
  }
  auth {
    auth_scheme = "SECRETS"
    description = "Database authentication"
    secrets_manager_arn = aws_secretsmanager_secret.db_secret.arn
    iam_auth    = "DISABLED"
  }
  role_arn    = aws_iam_role.rds_proxy_role.arn
  tags = {
    Name = "rds-proxy"
  }
  require_tls = true
  debug_logging = false  # Keep debug logging disabled as requested
}

# Associate the RDS Proxy with the Aurora cluster
resource "aws_db_proxy_default_target_group" "rds_proxy_target_group" {
  db_proxy_name = aws_db_proxy.rds_proxy.name

  connection_pool_configuration {
    idle_client_timeout              = 1800
    max_connections_percent          = 100
    max_idle_connections_percent     = 50
  }
}

resource "aws_db_proxy_endpoint" "rds_proxy_endpoint" {
  db_proxy_endpoint_name         = "aurora-proxy-endpoint"
  db_proxy_name                  = aws_db_proxy.rds_proxy.name
  vpc_subnet_ids                 = [aws_subnet.aurora_subnet_1.id, aws_subnet.aurora_subnet_2.id]
  vpc_security_group_ids         = [aws_security_group.rds_proxy_sg.id]
  target_role                    = "READ_WRITE"
  tags = {
    Name = "aurora-proxy-endpoint"
  }
}
```

