# Create a simple Amazon Lightsail setup
# This configuration includes:
# - A Lightsail instance (virtual private server)
# - An optional static IP address attached to the instance
# - Uses a simple blueprint (e.g., Amazon Linux 2) and a low-cost bundle

resource "aws_lightsail_instance" "example" {
  name              = "my-lightsail-instance"
  availability_zone = "us-west-2a"  # Specify a valid AZ for Lightsail
  blueprint_id      = "amazon_linux_2"  # OS image
  bundle_id         = "nano_2_0"    # Smallest instance size (512 MB RAM, 1 vCPU)
}

# Optionally attach a static IP to the instance for consistent access
resource "aws_lightsail_static_ip" "instance_static_ip" {
  name = "static-ip-example"
  attached_to = aws_lightsail_instance.example.id
}

# Output the public IP address of the instance
output "public_ip" {
  value = aws_lightsail_instance.example.public_ip_address
}

# Output the static IP (if attached)
output "static_ip_address" {
  value = aws_lightsail_static_ip.instance_static_ip.ip_address
}

