# AWS Lightsail does not support provisioning a managed database directly through its instance resource.
# Instead, we must create a Lightsail instance (virtual private server) and a separate Lightsail database.
# Lightsail databases are managed by AWS and can be created alongside instances.

# Steps:
# 1. Create a Lightsail instance (Linux/Unix-based) to serve as the application server.
# 2. Create a Lightsail database (e.g., MySQL or PostgreSQL) as the managed database.
# 3. Optionally, set up a static IP and attach it to the instance.
# 4. Ensure both resources are in the same region for low-latency connectivity.

resource "aws_lightsail_instance" "web_server" {
  name              = "web-server-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # Could also use ubuntu, centos, etc.
  bundle_id         = "nano_2_0"        # Instance size (e.g., nano, micro, small)
}

resource "aws_lightsail_database" "managed_db" {
  name              = "managed-database"
  availability_zone = "us-east-1a"
  blueprint_id      = "mysql_8_0"       # Could also use postgres_13, etc.
  bundle_id         = "micro_2_0"       # Small database bundle
  master_database_name = "myappdb"
  master_username   = "dbadmin"
  master_password   = random_password.db_password.result
  preferred_backup_window = "03:00-04:00"
  preferred_maintenance_window = "sun:05:00-sun:06:00"
}

# Generate a secure password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Optional: Attach a static IP to the instance
resource "aws_lightsail_static_ip" "instance_ip" {
  name = "web-static-ip"
}

resource "aws_lightsail_static_ip_attachment" "attach_ip" {
  static_ip_name = aws_lightsail_static_ip.instance_ip.name
  instance_name  = aws_lightsail_instance.web_server.name
}

# Output the public IP and database endpoint for reference
output "instance_public_ip" {
  value = aws_lightsail_instance.web_server.public_ip_address
}

output "database_endpoint" {
  value = aws_lightsail_database.managed_db.endpoint
}

output "database_username" {
  value = aws_lightsail_database.managed_db.master_username
  # Note: Avoid outputting passwords for security
}

