  bundle_id         = "nano_2_0"        # Instance size (e.g., nano, micro, small)
}

resource "aws_lightsail_database" "managed_db" {
  name              = "managed-database"
  availability_zone = "us-east-1a"
  blueprint_id      = "mysql_8_0"       # Could also use postgres_13, etc.
  bundle_id         = "micro_2_0"       # Small database bundle
  master_database_name = "myappdb"
  master_username   = "dbadmin"
  master_password   = random_password.db_password.result
  preferred_backup_window = "03:00-04:00"
  preferred_maintenance_window = "sun:05:00-sun:06:00"
}

# Generate a secure password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Optional: Attach a static IP to the instance
resource "aws_lightsail_static_ip" "instance_ip" {
