# AWS Long-Term Data Retention and Backup Storage Solution
# This configuration creates a secure, durable, and cost-effective solution using Amazon S3 with lifecycle policies,
# versioning, and cross-region replication for disaster recovery. It also enables logging and encryption.

resource "aws_s3_bucket" "backup_bucket" {
  bucket = "company-backups-longterm-${random_id.suffix.hex}"

  # Enable versioning to preserve, retrieve, and restore every version of every object
  versioning {
    enabled = true
  }

  # Enable server-side encryption using AWS KMS
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "aws:kms"
        kms_master_key_id = aws_kms_key.backup_key.arn
      }
    }
  }

  # Enable access logging for audit and compliance
  logging {
    target_bucket = aws_s3_bucket.backup_logs.id
    target_prefix = "logs/"
  }

  # Lifecycle policy to transition objects to Glacier Deep Archive after 90 days and expire after 7 years
  lifecycle_rule {
    id      = "longterm-retention-policy"
    enabled = true

    # Transition to Glacier after 90 days
    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    # Transition to Deep Archive after 180 days
    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    # Expire (permanently delete) objects after 7 years (adjustable for compliance)
    expiration {
      days = 2555 # 7 years
    }

    # Retain noncurrent versions for 90 days, then permanent deletion
    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }

  # Intelligent tiering for frequently accessed backup data
  lifecycle_rule {
    id      = "intelligent-tiering"
    enabled = true

    rule_filter {
      prefix = "frequent/"
    }

    # Use S3 Intelligent-Tiering to optimize costs for variable access patterns
    intelligent_tiering_configuration {
      name = "auto-tiering"

      tiering {
        access_tier = "DEEP_ARCHIVE_ACCESS"
        days        = 180
      }

      tiering {
        access_tier = "ARCHIVE_ACCESS"
        days        = 90
      }
    }
  }

  # Block public access
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Attach bucket policy for least privilege access
  policy = data.aws_iam_policy_document.bucket_policy.json
}

# Optional: Cross-Region Replication for Disaster Recovery
resource "aws_s3_bucket" "backup_bucket_replica" {
  provider = aws.us-east-1
  bucket   = "company-backups-replica-${random_id.suffix.hex}"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "aws:kms"
        kms_master_key_id = aws_kms_key.backup_key_replica.arn
      }
    }
  }

  # Block public access
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Replication configuration from primary to replica bucket
resource "aws_s3_bucket_replication_config" "replication" {
  depends_on = [aws_s3_bucket_owner_permission.replica]

  # Must enable versioning before replication
  bucket     = aws_s3_bucket.backup_bucket.id
  role       = aws_iam_role.replication_role.arn

  rules {
    id     = "replicate-for-dr"
    status = "Enabled"

    priority = 1

    destination {
      bucket        = aws_s3_bucket.backup_bucket_replica.arn
      storage_class = "STANDARD"
    }

    # Optional: Filter what gets replicated (e.g., only data needing DR)
    filter {
      prefix = "dr/"
    }
  }
}

# KMS key for encrypting data at rest
resource "aws_kms_key" "backup_key" {
  description             = "KMS key for encrypting long-term backup data"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  policy = data.aws_iam_policy_document.kms_policy.json
}

# KMS key for replica region
resource "aws_kms_key" "backup_key_replica" {
  provider                = aws.us-east-1
  description             = "KMS key for replica backup bucket"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# Bucket for storing access logs
resource "aws_s3_bucket" "backup_logs" {
  bucket = "company-backups-logs-${random_id.suffix.hex}"

  # Block public access
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true

  # Encrypt logs
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "aws:kms"
        kms_master_key_id = aws_kms_key.backup_key.arn
      }
    }
  }
}

# Generate unique suffix for bucket names
resource "random_id" "suffix" {
  byte_length = 8
}

# IAM role for replication
resource "aws_iam_role" "replication_role" {
  name = "s3-replication-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "replication_policy" {
  name = "s3-replication-policy"
  role = aws_iam_role.replication_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetReplicationConfiguration",
          "s3:GetObjectVersionForReplication"
        ]
        Resource = aws_s3_bucket.backup_bucket.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ReplicateObject",
          "s3:ReplicateDelete"
        ]
        Resource = "${aws_s3_bucket.backup_bucket_replica.arn}/*"
      },
      {
        Effect = "Allow"
        Action = "kms:Decrypt"
        Resource = aws_kms_key.backup_key.arn
      },
      {
        Effect = "Allow"
        Action = "kms:Encrypt"
        Resource = aws_kms_key.backup_key_replica.arn
      }
    ]
  })
}

# Allow replica bucket to write to the source-owned bucket
resource "aws_s3_bucket_ownership_controls" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_ownership_controls" "backup_bucket_replica" {
  bucket = aws_s3_bucket.backup_bucket_replica.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_owner_permission" "replica" {
  bucket = aws_s3_bucket.backup_bucket_replica.id
  permission = "FULL_CONTROL"
}

# Data sources for IAM policies
data "aws_iam_policy_document" "bucket_policy" {
  statement {
    sid = "AllowSSLRequestsOnly"
    actions = ["s3:*"]
    resources = [
      aws_s3_bucket.backup_bucket.arn,
