      values   = ["false"]
    }

    effect = "Deny"
    principals {
      type        = "AWS"
      identifiers = ["*"]
    }
  }
}

data "aws_iam_policy_document" "kms_policy" {
  statement {
    effect = "Allow"
    principals {
      type        = "AWS"
