# Create an Amazon S3 Glacier vault with a notification service

# Step 1: Define the Glacier Vault
# We start by creating a Glacier vault using the aws_glacier_vault resource.
# This vault will store our archived data securely.

# Step 2: Set up SNS Topic for Notifications
# Glacier can send notifications via Amazon SNS when jobs complete.
# We need to create an SNS topic and attach a policy that allows Glacier to publish to it.

# Step 3: Configure Vault Notifications
# Link the Glacier vault to the SNS topic so that when a retrieval job completes,
# Glacier sends a message to the topic.

resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-job-completion-notifications"
}

resource "aws_sns_topic_policy" "glacier_notifications_policy" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action = [
          "SNS:Publish"
        ]
        Resource = aws_sns_topic.glacier_notifications.arn
        Condition = {
          ArnLike = {
            "aws:SourceArn" = aws_glacier_vault.archive_vault.arn
          }
        }
      }
    ]
  })
}

resource "aws_glacier_vault" "archive_vault" {
  name = "my-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  # Optional: Add tags for the Glacier vault
  tags = {
    Name        = "ArchiveVault"
    Environment = "production"
  }
}

