response:
To fulfill this request, we need to create an Amazon S3 Glacier vault that sends a notification when an archive retrieval job completes. This involves several steps:

1. **Create an S3 Glacier Vault**: The main resource we need is the `aws_glacier_vault`, which represents the archive storage location.
2. **Set up Amazon SNS Topic**: Glacier uses Amazon Simple Notification Service (SNS) to send notifications. We must create an SNS topic so that Glacier can publish retrieval completion messages to it.
3. **Configure Vault Notifications**: Use the `aws_glacier_vault_notifications` resource to associate the SNS topic with the Glacier vault and specify that notifications should be sent for `ArchiveRetrievalCompleted` events.
4. **IAM Permissions (if needed)**: While not always required in Terraform (as the AWS provider handles authentication), we assume appropriate permissions are in place. However, we'll ensure the SNS topic policy allows Glacier to publish to it.

Let’s now generate the Terraform configuration accordingly.

```hcl
resource "aws_sns_topic" "glacier_retrieval_topic" {
  name = "glacier-archive-retrieval-notifications"
}

resource "aws_glacier_vault" "archive_vault" {
  name = "my-glacier-archive-vault"
}

resource "aws_glacier_vault_notifications" "vault_notifications" {
  vault_name = aws_glacier_vault.archive_vault.name

  sns_topic = aws_sns_topic.glacier_retrieval_topic.arn

  events = [
    "ArchiveRetrievalCompleted"
  ]
}
```

extracted_code:
# Create a VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Create a subnet in a specific Availability Zone
resource "aws_subnet" "subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "main-subnet"
  }
}

# Create an Internet Gateway and attach to the VPC
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Create a route table for public access
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate the route table with the subnet
resource "aws_route_table_association" "subnet_assoc" {
  subnet_id      = aws_subnet.subnet.id
  route_table_id = aws_route_table.public.id
}

# Create a security group for the EC2 instance
resource "aws_security_group" "instance_sg" {
  name        = "instance-security-group"
  description = "Allow HTTP and SSH traffic"
  vpc_id      = aws_vpc.main.id

  # Allow SSH from anywhere (0.0.0.0/0)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow HTTP from anywhere
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "instance-security-group"
  }
}

# Launch a t2.micro EC2 instance
resource "aws_instance" "web_server" {
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-west-2
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]
  associate_public_ip_address = true

  tags = {
    Name = "web-server-instance"
  }
}

# Create a Network Load Balancer
resource "aws_lb" "nlb" {
  name               = "network-load-balancer"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.subnet.id]

  tags = {
    Name = "network-lb"
  }
}

# Create a target group for the NLB
resource "aws_lb_target_group" "nlb_tg" {
  name     = "nlb-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id
  target_type = "instance"

  health_check {
    port            = "80"
    protocol        = "TCP"
    interval        = 30
    timeout         = 10
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }

  tags = {
    Name = "nlb-target-group"
  }
}

# Register the EC2 instance with the target group
resource "aws_lb_target_group_attachment" "instance_attachment" {
  target_group_arn = aws_lb_target_group.nlb_tg.arn
  target_id        = aws_instance.web_server.id
  port             = 80
}

# Create a listener for the NLB to forward traffic from port 80 to target group
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

