extracted_code:
# Create a Network Load Balancer (NLB) on AWS
# Steps:
# 1. Define required providers (AWS in this case)
# 2. Create a VPC (if not using existing)
# 3. Create subnets in at least two availability zones
# 4. Create a Network Load Balancer with internal or external scheme
# 5. Create a target group to route traffic to targets (e.g., EC2 instances or IP)
# 6. Create a listener to forward traffic from NLB to target group

provider "aws" {
  region = "us-west-2"
}

# Create VPC
resource "aws_vpc" "nlb_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "nlb-demo-vpc"
  }
}

# Create subnets in two availability zones
resource "aws_subnet" "subnet_az1" {
  vpc_id                  = aws_vpc.nlb_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "nlb-subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id                  = aws_vpc.nlb_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "nlb-subnet-az2"
  }
}

# Create Elastic IP for each subnet (if external NLB)
resource "aws_eip" "nlb_eip_az1" {
  vpc = true
}

resource "aws_eip" "nlb_eip_az2" {
  vpc = true
}

# Create Network Load Balancer
resource "aws_lb" "nlb" {
  name               = "nlb-demo"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]

  # Enable cross-zone load balancing (optional)
  enable_cross_zone_load_balancing = true

  # Enable deletion protection (optional)
  enable_deletion_protection = false

  # Assign EIPs to the NLB in each subnet (only for external NLBs)
  # Note: EIPs are ignored if internal = true
  enable_tcp_reset = true

  tags = {
    Environment = "demo"
  }
}

# Create Target Group
resource "aws_lb_target_group" "nlb_target_group" {
  name     = "nlb-target-group"
  port     = 5000
  protocol = "TCP"
  vpc_id   = aws_vpc.nlb_vpc.id

  # Health check settings
  health_check {
    protocol            = "TCP"
    port                = "5000"
    interval            = 30
    timeout             = 10
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }

  # Stickiness for TCP (optional)
  stickiness {
    type    = "source_ip"
    enabled = true
  }

  # Target type can be 'instance', 'ip', or 'lambda'
  target_type = "instance"

  tags = {
    Name = "nlb-target-group"
  }
}

# Create Listener to route traffic to target group
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "5000"
  protocol          = "TCP"

  # Forward traffic to target group
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_target_group.arn
  }
}

# Output the DNS name of the NLB
output "nlb_dns_name" {
  value = aws_lb.nlb.dns_name
}

output "nlb_arn" {
  value = aws_lb.nlb.arn
}

