# This configuration creates an internal load balancer with specific private IP addresses
# Step-by-step considerations:
# 1. Creating a VPC for the network infrastructure
# 2. Creating subnets in different availability zones
# 3. Creating a load balancer with internal scheme and specifying private IPs
# 4. Using static private IP addresses through subnet and IP assignment

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "internal-lb-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "internal-lb-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "internal-lb-subnet-b"
  }
}

resource "aws_lb" "internal" {
  name               = "internal-load-balancer"
  internal           = true
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  # Enable static IP assignment for the load balancer
  enable_deletion_protection = false

  tags = {
    Name = "internal-lb"
  }
}

# Security group for the load balancer
resource "aws_security_group" "lb_sg" {
  name        = "internal-lb-sg"
  description = "Security group for internal load balancer"
  vpc_id      = aws_vpc.main.id

  # Allow HTTP traffic from internal network
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  # Allow HTTPS traffic from internal network
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "internal-lb-sg"
  }
}

# Optional: If specific private IPs are required for the load balancer endpoints,
# we can use network interfaces with specific IPs, but for ALB/NLB the IP is 
# assigned from the subnet. For static IP requirements, we ensure the subnets
# are properly configured and use the load balancer's DNS name.

