```hcl
# This Terraform configuration creates a load balancer that routes traffic to instances in a target group.
# We'll use AWS as the cloud provider for this example.

# Provider configuration
provider "aws" {
  region = "us-west-2"  # You can change this to your preferred region
}

# Create a VPC for the instances and load balancer
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "load-balancer-vpc"
  }
}

# Create a subnet for the instances and load balancer
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "subnet-1"
  }
}

# Create a second subnet for high availability (required for load balancer)
resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "subnet-2"
  }
}

# Create an internet gateway to allow Internet access
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Create a route table for public access
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate subnets with the route table
resource "aws_route_table_association" "assoc_1" {
  subnet_id      = aws_subnet.subnet_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "assoc_2" {
  subnet_id      = aws_subnet.subnet_2.id
  route_table_id = aws_route_table.public.id
}

# Create a security group for the load balancer
resource "aws_security_group" "lb_sg" {
  name        = "lb-security-group"
  description = "Allow HTTP and HTTPS inbound traffic"
  vpc_id      = aws_vpc.main.id

  # Allow inbound HTTP traffic (port 80)
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow inbound HTTPS traffic (port 443)
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "lb-security-group"
  }
}

# Create a security group for the instances
resource "aws_security_group" "instance_sg" {
  name        = "instance-security-group"
  description = "Allow HTTP traffic from load balancer and SSH from anywhere"
  vpc_id      = aws_vpc.main.id

  # Allow inbound HTTP traffic from load balancer
  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.lb_sg.id]
  }

  # Allow SSH from anywhere (for management purposes - restrict in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "instance-security-group"
  }
}

# Create a target group
resource "aws_lb_target_group" "target_group" {
  name     = "example-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  # Health check settings
  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200"
  }

  tags = {
    Name = "example-target-group"
  }
}

# Create an Application Load Balancer
resource "aws_lb" "main" {
  name               = "example-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "example-load-balancer"
  }
}

# Create a listener for the load balancer
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  # Forward all requests to the target group
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

# Optional: Create sample EC2 instances to register with the target group
resource "aws_instance" "instance_1" {
  count                   = 2
  ami                     = "ami-0c02fb55956c7d316"  # Amazon Linux 2 in us-west-2
  instance_type           = "t3.micro"
  subnet_id               = element([aws_subnet.subnet_1.id, aws_subnet.subnet_2.id], count.index)
  vpc_security_group_ids  = [aws_security_group.instance_sg.id]
  associate_public_ip_address = true

  user_data = <<-EOF
              #!/bin/bash
              echo "<html><h1>Instance ${count.index + 1}</h1></html>" > index.html
              nohup python3 -m http.server 80 &
              EOF

  tags = {
    Name = "web-instance-${count.index + 1}"
  }
}

# Register the EC2 instances with the target group
resource "aws_lb_target_group_attachment" "attachment_1" {
  count            = 2
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id        = aws_instance.instance_1[count.index].id
  port             = 80
}

# Output the DNS name of the load balancer
output "load_balancer_dns_name" {
  value = aws_lb.main.dns_name
}

# Output the target group ARN
output "target_group_arn" {
  value = aws_lb_target_group.target_group.arn
}
```

