# Provider block
provider "aws" {
  region = "us-west-2"
}

# VPC for the load balancer
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "alb-oidc-vpc"
  }
}

# Public subnets
resource "aws_subnet" "public1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-2"
  }
}

# Security group for ALB
resource "aws_security_group" "alb_sg" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-security-group"
  }
}

# ALB
resource "aws_lb" "main" {
  name               = "alb-with-oidc"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public1.id, aws_subnet.public2.id]

  tags = {
    Name = "ALB-OIDC"
  }
}

# Target group (example for EC2 on port 80)
resource "aws_lb_target_group" "app" {
  name     = "app-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    path = "/"
  }

  tags = {
    Name = "app-target-group"
  }
}

# Listener with Authenticate-OIDC action
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.id
  port              = "80"
  protocol          = "HTTP"

  # Default action: authenticate using OIDC, then forward
  default_action {
    type = "authenticate-oidc"

    authenticate_oidc {
      # Example using Cognito User Pools (replace with actual values)
      authorization_endpoint = "https://your-domain.auth.us-west-2.amazoncognito.com/oauth2/authorize"
      client_id              = "your-client-id"
      client_secret          = "your-client-secret"
      issuer                 = "https://cognito-idp.us-west-2.amazonaws.com/your-user-pool-id"
      token_endpoint         = "https://your-domain.auth.us-west-2.amazoncognito.com/oauth2/token"
      userinfo_endpoint      = "https://your-domain.auth.us-west-2.amazoncognito.com/oauth2/userInfo"
      # Optional
      on_unauthenticated_request = "authenticate"
      session_timeout            = 604800
      session_cookie_name        = "AWSELBAuth"
    }

    # After authentication, forward to the target group
    next {
      type             = "forward"
      target_group_arn = aws_lb_target_group.app.arn
    }
  }
}

