# We are going to create an Application Load Balancer (ALB) with a Lambda function as its target.
# Steps:
# 1. Create a VPC and subnets for the load balancer (ALB requires a VPC with at least two subnets).
# 2. Create a security group for the ALB.
# 3. Create the ALB, listener, and target group.
# 4. Create a Lambda function (for demonstration, a simple function that returns a response).
# 5. Allow the ALB to invoke the Lambda function by setting up the appropriate permissions.

resource "aws_vpc" "alb_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "alb-lambda-vpc"
  }
}

resource "aws_subnet" "public_subnet1" {
  vpc_id            = aws_vpc.alb_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet2" {
  vpc_id            = aws_vpc.alb_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "public-subnet-2"
  }
}

resource "aws_security_group" "alb_sg" {
  name   = "alb-lambda-sg"
  vpc_id = aws_vpc.alb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-lambda-security-group"
  }
}

resource "aws_lb" "alb" {
  name               = "alb-lambda"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_subnet1.id, aws_subnet.public_subnet2.id]

  tags = {
    Name = "alb-with-lambda"
  }
}

resource "aws_lambda_function" "example" {
  filename      = "lambda_function_payload.zip"  # This should be a valid path to your deployment package
  function_name = "alb-lambda-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  environment {
    variables = {
      FUNCTION_VERSION = "1"
    }
  }
}

# IAM role for Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "lambda-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_role.name
}

# Allow ALB to invoke the Lambda function
resource "aws_lambda_permission" "allow_alb" {
  statement_id  = "AllowExecutionFromALB"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example.function_name
  principal     = "elasticloadbalancing.amazonaws.com"
  source_arn    = "${aws_lb.alb.arn}/*"
}

resource "aws_lb_target_group" "lambda_tg" {
  name     = "lambda-target-group"
  port     = 80
  protocol = "HTTP"
  target_type = "lambda"

  # No need for health check settings for lambda target groups
}

resource "aws_lb_target_group_attachment" "lambda_attachment" {
  target_group_arn = aws_lb_target_group.lambda_tg.arn
  target_id        = aws_lambda_function.example.arn
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.lambda_tg.arn
  }
}

