# Let's think through the requirements step by step:

# 1. We need a simple SQL database on AWS - Amazon RDS (Relational Database Service) is the most suitable choice.
# 2. We'll use MySQL as the database engine (common choice for "simple SQL database").
# 3. We need a DB instance with basic configurations: instance class, storage, credentials.
# 4. We should create a DB subnet group to place the database in private subnets.
# 5. We need a security group to control access (only allow connection from specific sources).
# 6. We'll use default VPC and subnets for simplicity, but best practice would be to use a custom VPC.
# 7. We'll enable deletion protection and backup for production safety.

resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = var.subnet_ids != [] ? var.subnet_ids : data.aws_subnets.default.ids

  tags = {
    Name = "Main DB Subnet Group"
  }
}

resource "aws_security_group" "db_security_group" {
  name        = "rds-security-group"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = var.vpc_id != "" ? var.vpc_id : data.aws_vpc.default.id

  # Allow inbound PostgreSQL traffic (port 5432) from a specified CIDR or security group
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS Security Group"
  }
}

resource "aws_db_instance" "default" {
  identifier_prefix           = "simple-sql-db-"
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = var.instance_class
  allocated_storage           = var.allocated_storage
  storage_type                = "gp3"
  storage_encrypted           = true
  final_snapshot_identifier   = "final-snapshot-${formatdate("YYYY-MM-DD-HH-mm", timestamp())}"
  deletion_protection         = var.deletion_protection
  backup_retention_period     = var.backup_retention_period
  preferred_backup_window     = "03:00-04:00"
  skip_final_snapshot         = false
  multi_az                    = var.multi_az
  vpc_security_group_ids      = [aws_security_group.db_security_group.id]
  db_subnet_group_name        = aws_db_subnet_group.main.name
  publicly_accessible         = false
  allow_major_version_upgrade = true
  auto_minor_version_upgrade  = true
  copy_tags_to_snapshot       = true

  # Database settings
  username = var.username
  password = var.password
  db_name  = var.db_name != "" ? var.db_name : "mydb"

  # Parameters for performance and monitoring
  enabled_cloudwatch_logs_exports = ["postgresql"]

  # Backup and maintenance
  backup_window       = "04:00-05:00"
  maintenance_window  = "sun:05:00-sun:06:00"

  tags = {
    Name        = "Simple SQL Database"
    Environment = "production"
  }
}

# Variables with reasonable defaults
variable "instance_class" {
  description = "The RDS instance class"
  type        = string
  default     = "db.t4g.micro"
}

variable "allocated_storage" {
  description = "The allocated storage in GB"
  type        = number
  default     = 20
}

variable "deletion_protection" {
  description = "Enable deletion protection"
  type        = bool
  default     = true
}

variable "backup_retention_period" {
  description = "Number of days to retain backups"
  type        = number
  default     = 7
}

variable "multi_az" {
  description = "Enable Multi-AZ deployment for high availability"
  type        = bool
  default     = false
}

variable "username" {
  description = "Master username for the database"
  type        = string
  sensitive   = true
}

variable "password" {
  description = "Master password for the database"
  type        = string
  sensitive   = true
}

variable "db_name" {
  description = "Name of the database to create"
  type        = string
  default     = ""
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks that can access the database"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

variable "vpc_id" {
  description = "VPC ID where the database will be deployed"
  type        = string
  default     = ""
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DB subnet group"
  type        = list(string)
  default     = []
}

# Data sources to get default VPC and subnets if not provided
data "aws_vpc" "default" {
  default = true

  count = var.vpc_id == "" ? 1 : 0
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = var.vpc_id != "" ? [var.vpc_id] : data.aws_vpc.default[*].id
  }

  filter {
    name   = "map-public-ip-on-launch"
    values = ["false"]  # Select private subnets
  }

  count = var.subnet_ids == [] ? 1 : 0
}

# Output the database endpoint
output "db_endpoint" {
  description = "The connection endpoint for the database"
  value       = aws_db_instance.default.endpoint
}

output "db_name" {
  description = "The name of the database"
  value       = aws_db_instance.default.db_name
}

output "db_instance_id" {
  description = "The RDS instance ID"
  value       = aws_db_instance.default.id
}

