# Step-by-step reasoning:
# 1. To restore an AWS database from an S3 bucket, we typically deal with Amazon RDS.
# 2. RDS supports importing snapshot data from S3 (e.g., for MySQL or PostgreSQL) via the `aws_db_snapshot` and `aws_db_instance` resources.
# 3. However, direct restore from S3 backups (e.g., .sql dump files) is not a native RDS feature; instead, RDS supports importing from S3 only for certain engines using the `aws_db_instance` with `s3_import`.
# 4. To enable this, we need:
#    - An S3 bucket with the database backup.
#    - An IAM role that allows RDS to access the S3 bucket.
#    - The DB instance configured to restore from the S3 source via the `s3_import` argument.
# 5. The database instance must be created with all required parameters including engine type, allocated storage, etc.

resource "aws_s3_bucket" "db_backup_bucket" {
  bucket = "my-db-backup-bucket-unique-name"
  force_destroy = true
}

resource "aws_iam_role" "rds_s3_import_role" {
  name = "rds-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds_s3_import_policy" {
  name = "rds-s3-import-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:ListBucket",
          "s3:GetObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.db_backup_bucket.arn,
          "${aws_s3_bucket.db_backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "rds_s3_import_attachment" {
  name       = "rds-s3-import-attachment"
  policy_arn = aws_iam_policy.rds_s3_import_policy.arn
  roles      = [aws_iam_role.rds_s3_import_role.name]
}

resource "aws_db_instance" "restored_db" {
  identifier           = "restored-db-from-s3"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  db_name              = "mydb"
  username             = "admin"
  password             = "securepassword123"
  skip_final_snapshot  = true

  # Restore from S3
  s3_import {
    source_engine          = "mysql"
    source_engine_version  = "8.0"
    bucket_name            = aws_s3_bucket.db_backup_bucket.bucket
    ingestion_role_arn     = aws_iam_role.rds_s3_import_role.arn
    bucket_prefix          = "backup/"
  }

  # Depends on IAM role and policy setup
  depends_on = [
    aws_iam_policy_attachment.rds_s3_import_attachment
  ]
}

