# Step-by-step breakdown:
# 1. Create a KMS key to encrypt the database credentials in Secrets Manager
# 2. Create a database secret in Secrets Manager using the KMS key
# 3. Set up an RDS database instance that references the secret for master credentials
# 4. Ensure proper dependencies and security configurations

resource "aws_kms_key" "database_key" {
  description             = "KMS key for encrypting database master credentials"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_secretsmanager_secret" "database_credentials" {
  name       = "db-master-credentials"
  kms_key_id = aws_kms_key.database_key.arn

  # Prevent replacement to avoid credential rotation unless explicitly intended
  force_overwrite_replica_secret = false
}

resource "aws_secretsmanager_secret_rotation" "database_credentials" {
  secret_id           = aws_secretsmanager_secret.database_credentials.id
  rotation_lambda_arn = ""  # Using AWS managed rotation for RDS
  rotation_rules {
    automatically_after_days = 90
  }
}

resource "aws_secretsmanager_secret_version" "initial" {
  secret_id     = aws_secretsmanager_secret.database_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

resource "aws_db_instance" "main" {
  identifier             = "my-database"
  engine                 = "postgres"
  engine_version         = "15"
  instance_class         = "db.t4g.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_name                = "mydb"
  username               = "admin"
  password               = random_password.db_password.result
  skip_final_snapshot    = true
  deletion_protection    = false  # Disable for example; enable in production
  vpc_security_group_ids = [aws_security_group.database.id]

  # Ensure the DB uses the same KMS key for storage encryption
  storage_encrypted   = true
  kms_key_id          = aws_kms_key.database_key.arn

  # Depends on secret version since credentials are used
  depends_on = [aws_secretsmanager_secret_version.initial]
}

resource "aws_security_group" "database" {
  name        = "database-sg"
  description = "Allow access to database"

