response:
# Amazon EFS with Resource-Based Policy Terraform Configuration

Let's break this down step by step:

1. First, we need to create an EFS file system
2. We need to create a mount target for the EFS (required for connectivity)
3. We need to create a resource-based policy for the EFS
4. The policy needs to be attached to the EFS file system

```h	ZEPHIR
resource "aws_efs_file_system" "efs" {
  creation_token = "my-efs-file-system"
  encrypted      = true
  tags = {
    Name = "MyEFSFileSystem"
  }
}

resource "aws_efs_mount_target" "efs_mount" {
  count                   = length(data.aws_subnets.private.ids)
  file_system_id          = aws_efs_file_system.efs.id
  subnet_id               = data.aws_subnets.private.ids[count.index]
  security_groups         = [aws_security_group.efs_sg.id]
}

data "aws_subnets" "private" {
  filter {
    name   = "vpc-id"
    values = [var.vpc_id]
  }

  filter {
    name   = "tag:Name"
    values = ["private-*"]
  }
}

resource "aws_security_group" "efs_sg" {
  name        = "allow-efs-access"
  vpc_id      = var.vpc_id
  description = "Allow EFS access from within VPC"

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow-efs-access"
  }
}

resource "aws_efs_file_system_policy" "efs_policy" {
  file_system_id = aws_efs_file_system.efs.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = aws_efs_file_system.efs.arn
        Condition = {
          Bool = {
            "elasticfilesystem:AccessedViaMountTarget" = "true"
          }
        }
      },
      {
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = aws_efs_file_system.efs.arn
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
      }
    ]
  })
}

variable "vpc_id" {
  description = "The VPC ID where the EFS will be created"
  type        = string
}
```

