# Step 1: Create an EFS file system with automatic backups enabled
# - We need to create an AWS EFS file system
# - Enable automatic backups using AWS Backup
# - Configure the file system to be encrypted
# - Use the general purpose performance mode
# - Use the bursting throughput mode
# - Enable lifecycle management for cost optimization

# Create the EFS file system
resource "aws_efs_file_system" "efs" {
  creation_token = "my-efs-fs"

  # Enable automatic backups through AWS Backup
  # AWS Backup is managed separately and needs a backup plan and selection
  encrypted = true
  performance_mode = "generalPurpose"
  throughput_mode = "bursting"

  # Enable lifecycle policy to transition files to lower cost storage classes
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  # Enable automatic backup via AWS Backup
  # This requires a backup plan and selection to be created
  backup_policy {
    status = "ENABLED"
  }

  tags = {
    Name = "my-efs-file-system"
  }
}

# Create mount targets for the EFS in specified subnets
# Note: You'll need to specify your subnet IDs and security group
# These are typically created in each Availability Zone where you want to mount the EFS
resource "aws_efs_mount_target" "mount_target" {
  # We'll create one mount target per subnet/AZ
  # This example assumes you have three subnets in different AZs
  count = length(var.subnet_ids)

  file_system_id  = aws_efs_file_system.efs.id
  subnet_id       = var.subnet_ids[count.index]
  security_groups = var.security_group_ids
}

# Input variables needed for the configuration
variable "subnet_ids" {
  description = "List of subnet IDs where EFS mount targets will be created"
  type        = list(string)
}

variable "security_group_ids" {
  description = "List of security group IDs for the EFS mount targets"
  type        = list(string)
  default     = []
}

# Output the EFS file system ID for reference
output "efs_file_system_id" {
  value = aws_efs_file_system.efs.id
}

# Output the DNS name for the EFS file system
output "efs_dns_name" {
  value = aws_efs_file_system.efs.dns_name
}

