# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  # Enable DNS hostname support in the VPC
  enable_dns_hostnames = true
  enable_dns_support   = true

  # Add tags for identification
  tags = {
    Name = "main-vpc"
  }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "main_igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Create a Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  # Route to the Internet via the Internet Gateway
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main_igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Create public subnets and associate them with the route table
resource "aws_subnet" "public_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = "us-west-2${var.az_letters[count.index]}"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# Associate each public subnet with the public route table
resource "aws_route_table_association" "public_subnet_association" {
  count          = length(aws_subnet.public_subnet[*].id)
  subnet_id      = aws_subnet.public_subnet[count.index].id
  route_table_id = aws_route_table.public.id
}

# Optional: Define AZ letters for subnet placement
variable "az_letters" {
  description = "Availability Zone suffixes for subnet placement"
  type        = list(string)
  default     = ["a", "b", "c"]
}

