# Create the 'peer' VPC
resource "aws_vpc" "peer" {
  cidr_block = "10.0.0.0/24"
  tags = {
    Name = "peer"
  }
}

# Create the 'base' VPC
resource "aws_vpc" "base" {
  cidr_block = "10.1.0.0/24"
  tags = {
    Name = "base"
  }
}

# Create a VPC peering connection between 'peer' and 'base'
resource "aws_vpc_peering_connection" "pike" {
  vpc_id        = aws_vpc.peer.id
  peer_vpc_id   = aws_vpc.base.id
  auto_accept   = false

  tags = {
    Name     = "pike"
    pike     = "permissions"
  }
}

# Accept the peering connection (assuming same account)
resource "aws_vpc_peering_connection_accepter" "pike_accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  auto_accept               = true

  tags = {
    pike = "permissions"
  }

  depends_on = [aws_vpc_peering_connection.pike]
}

