# Step 1: Create the "base" VPC with CIDR 10.1.0.0/24
resource "aws_vpc" "base" {
  cidr_block = "10.1.0.0/24"
  tags = {
    Name = "base"
  }
}

# Step 2: Create the "peer" VPC with CIDR 10.0.0.0/24
resource "aws_vpc" "peer" {
  cidr_block = "10.0.0.0/24"
  tags = {
    Name = "peer"
  }
}

# Step 3: Create a VPC peering connection named "pike"
resource "aws_vpc_peering_connection" "pike" {
  vpc_id        = aws_vpc.base.id
  peer_vpc_id   = aws_vpc.peer.id
  auto_accept   = false  # Since we're managing both VPCs, we can accept it via Terraform
  tags = {
    Name = "pike"
  }
}

# Step 4: Accept the peering connection (required when auto_accept = false)
resource "aws_vpc_peering_connection_accepter" "pike_accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  auto_accept               = true

  tags = {
    Name = "pike-accepter"
  }

  # Ensure the accepter runs after the request is created
  depends_on = [aws_vpc_peering_connection.pike]
}

