# Define the two VPCs: "peer" and "base"
# First, we'll retrieve the VPCs by their tags or names since they are assumed to exist.
# We use data sources to locate the VPCs by their name tags.

data "aws_vpc" "base" {
  filter {
    name   = "tag:Name"
    values = ["base"]
  }
}

data "aws_vpc" "peer" {
  filter {
    name   = "tag:Name"
    values = ["peer"]
  }
}

# Create the VPC peering connection between "base" and "peer" VPCs
resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = data.aws_vpc.base.id
  peer_vpc_id = data.aws_vpc.peer.id
  auto_accept = false  # Assuming manual acceptance is needed; if peer is in same account, can be set to true or use aws_vpc_peering_connection_accepter

  tags = {
    Name        = "pike"
    pike        = "permissions"
    Description = "Peering connection between base and peer VPCs for private communication"
  }
}

# Output the peering connection ID for reference
output "pike_peering_connection_id" {
  value = aws_vpc_peering_connection.pike.id
}

# Note: If both VPCs are in the same AWS account, you can automatically accept the peering.
# Otherwise, the accepter (peer VPC owner) must manually accept it, or use aws_vpc_peering_connection_accepter in a separate configuration.

